export interface ScrapItem {
  id: string;
  name: string;
  rate: number;
  lastUpdated: string;
  category: 'Metal' | 'Paper' | 'Plastic' | 'Electronics' | 'Others';
}

export interface StockItem {
  itemId: string;
  itemName: string;
  purchased: number;
  sold: number;
  available: number;
}

export interface StaffMember {
  id: string;
  name: string;
  role: 'Manager' | 'Worker' | 'Driver';
  status: 'Active' | 'Inactive';
  phone: string;
}

export interface LeaveRequest {
  id: string;
  staffName: string;
  fromDate: string;
  toDate: string;
  reason: string;
  status: 'Pending' | 'Approved' | 'Rejected';
}

export interface CompanySettings {
  name: string;
  subtitle: string;
  address: string;
  phone: string;
  signatureUrl: string | null; // Base64 string for demo
}

export interface BillItem {
  id: string; // unique row id
  itemId: string; // ref to ScrapItem
  customName?: string; // for 'Others'
  rate: number;
  weight: number;
  amount: number;
}

export interface Bill {
  id: string;
  billNo: string;
  customerName: string;
  customerAddress: string;
  customerPhone: string;
  items: BillItem[];
  totalAmount: number;
  date: string;
  staffName: string;
}

export type ViewMode = 'ADMIN' | 'STAFF';

import jsPDF from 'jspdf';
import { Bill, CompanySettings } from '../types';

export const generateBillPDF = (bill: Bill, company: CompanySettings) => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a5', // Receipt format mostly A5 or thermal, A5 is safer for standard printers
  });

  const margin = 10;
  let y = margin;

  // Header
  doc.setFontSize(16);
  doc.setFont('helvetica', 'bold');
  doc.text(company.name.toUpperCase(), 74, y, { align: 'center' });
  y += 6;

  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.text(company.subtitle, 74, y, { align: 'center' });
  y += 5;
  doc.text(company.address, 74, y, { align: 'center' });
  y += 5;
  doc.text(`Phone: ${company.phone}`, 74, y, { align: 'center' });

  y += 8;
  doc.setLineWidth(0.5);
  doc.line(margin, y, 148 - margin, y);
  y += 5;

  // Bill Meta
  doc.setFontSize(9);
  doc.text(`Bill No: ${bill.billNo}`, margin, y);
  doc.text(`Date: ${new Date(bill.date).toLocaleString()}`, 148 - margin, y, { align: 'right' });
  y += 5;

  // Customer Details
  doc.setFont('helvetica', 'bold');
  doc.text('Customer Details:', margin, y);
  y += 5;
  doc.setFont('helvetica', 'normal');
  doc.text(`Name: ${bill.customerName}`, margin, y);
  y += 5;
  doc.text(`Mobile: ${bill.customerPhone}`, margin, y);
  y += 5;
  if(bill.customerAddress) {
    doc.text(`Address: ${bill.customerAddress}`, margin, y);
    y += 5;
  }

  y += 5;

  // Table Header
  const col1 = margin;
  const col2 = 60;
  const col3 = 90;
  const col4 = 120;

  doc.setFillColor(230, 230, 230);
  doc.rect(margin, y - 4, 148 - (margin * 2), 8, 'F');

  doc.setFont('helvetica', 'bold');
  doc.text('Item', col1 + 2, y + 1);
  doc.text('Rate', col2, y + 1, { align: 'right' });
  doc.text('Weight', col3, y + 1, { align: 'right' });
  doc.text('Amount', 148 - margin - 2, y + 1, { align: 'right' });

  y += 8;
  doc.setFont('helvetica', 'normal');

  // Items
  bill.items.forEach((item) => {
    let itemName = item.customName || 'Unknown';
    // Truncate if too long
    if (itemName.length > 25) itemName = itemName.substring(0, 22) + '...';

    doc.text(itemName, col1 + 2, y);
    doc.text(item.rate.toFixed(2), col2, y, { align: 'right' });
    doc.text(item.weight.toFixed(2), col3, y, { align: 'right' });
    doc.text(item.amount.toFixed(2), 148 - margin - 2, y, { align: 'right' });
    y += 6;
  });

  y += 2;
  doc.setLineWidth(0.2);
  doc.line(margin, y, 148 - margin, y);
  y += 6;

  // Total
  doc.setFontSize(12);
  doc.setFont('helvetica', 'bold');
  doc.text('TOTAL:', 90, y);
  doc.text(`₹ ${bill.totalAmount.toFixed(2)}`, 148 - margin - 2, y, { align: 'right' });

  // Signature
  if (company.signatureUrl) {
    y += 15;
    doc.addImage(company.signatureUrl, 'PNG', 148 - margin - 40, y, 35, 15);
    y += 16;
    doc.setFontSize(8);
    doc.setFont('helvetica', 'normal');
    doc.text('Authorized Signature', 148 - margin - 22, y, { align: 'center' });
  } else {
    y += 25;
    doc.setFontSize(8);
    doc.setFont('helvetica', 'normal');
    doc.text('Authorized Signature', 148 - margin - 20, y, { align: 'center' });
  }

  // Footer
  doc.setFontSize(7);
  doc.text('Generated by Apna Kabadi System', 74, 200, { align: 'center' });

  doc.save(`Bill_${bill.billNo}.pdf`);
};

import React, { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { ScrapItem, StaffMember, LeaveRequest, CompanySettings, Bill, ViewMode } from '../types';
import { INITIAL_ITEMS, INITIAL_STAFF, INITIAL_LEAVES, DEFAULT_COMPANY } from '../constants';

interface AppContextType {
  items: ScrapItem[];
  updateItemRate: (id: string, newRate: number) => void;
  staff: StaffMember[];
  addStaff: (member: StaffMember) => void;
  updateStaffStatus: (id: string, status: 'Active' | 'Inactive') => void;
  leaves: LeaveRequest[];
  updateLeaveStatus: (id: string, status: 'Approved' | 'Rejected') => void;
  company: CompanySettings;
  updateCompany: (settings: CompanySettings) => void;
  bills: Bill[];
  addBill: (bill: Bill) => void;
  viewMode: ViewMode;
  setViewMode: (mode: ViewMode) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider = ({ children }: { children: ReactNode }) => {
  const [items, setItems] = useState<ScrapItem[]>(INITIAL_ITEMS);
  const [staff, setStaff] = useState<StaffMember[]>(INITIAL_STAFF);
  const [leaves, setLeaves] = useState<LeaveRequest[]>(INITIAL_LEAVES);
  const [company, setCompany] = useState<CompanySettings>(DEFAULT_COMPANY);
  const [bills, setBills] = useState<Bill[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('ADMIN');

  // Load from localStorage on mount (Simulating persistence)
  useEffect(() => {
    const savedBills = localStorage.getItem('apna_kabadi_bills');
    if (savedBills) setBills(JSON.parse(savedBills));

    const savedRates = localStorage.getItem('apna_kabadi_rates');
    if (savedRates) setItems(JSON.parse(savedRates));
  }, []);

  // Save changes
  useEffect(() => {
    localStorage.setItem('apna_kabadi_bills', JSON.stringify(bills));
  }, [bills]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_rates', JSON.stringify(items));
  }, [items]);

  const updateItemRate = (id: string, newRate: number) => {
    setItems(prev => prev.map(item => 
      item.id === id ? { ...item, rate: newRate, lastUpdated: new Date().toISOString().split('T')[0] } : item
    ));
  };

  const addStaff = (member: StaffMember) => {
    setStaff(prev => [...prev, member]);
  };

  const updateStaffStatus = (id: string, status: 'Active' | 'Inactive') => {
    setStaff(prev => prev.map(s => s.id === id ? { ...s, status } : s));
  };

  const updateLeaveStatus = (id: string, status: 'Approved' | 'Rejected') => {
    setLeaves(prev => prev.map(l => l.id === id ? { ...l, status } : l));
  };

  const updateCompany = (settings: CompanySettings) => {
    setCompany(settings);
  };

  const addBill = (bill: Bill) => {
    setBills(prev => [bill, ...prev]);
  };

  return (
    <AppContext.Provider value={{
      items, updateItemRate,
      staff, addStaff, updateStaffStatus,
      leaves, updateLeaveStatus,
      company, updateCompany,
      bills, addBill,
      viewMode, setViewMode
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

