import React, { useState } from 'react';
import { useApp } from '../../context/AppContext';
import { Edit2, Save, X, AlertTriangle, Search } from 'lucide-react';

export const RateChart = () => {
  const { items, updateItemRate } = useApp();
  const [editingId, setEditingId] = useState<string | null>(null);
  const [tempRate, setTempRate] = useState<string>('');
  const [searchTerm, setSearchTerm] = useState('');

  const startEdit = (id: string, currentRate: number) => {
    setEditingId(id);
    setTempRate(currentRate.toString());
  };

  const saveEdit = (id: string) => {
    const rate = parseFloat(tempRate);
    if (!isNaN(rate) && rate >= 0) {
      updateItemRate(id, rate);
    }
    setEditingId(null);
  };

  const cancelEdit = () => {
    setEditingId(null);
    setTempRate('');
  };

  const filteredItems = items.filter(item => 
    item.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    item.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
           <h1 className="text-2xl font-bold text-slate-800">Rate Chart Management</h1>
           <p className="text-slate-500 mt-1">Manage daily scrap buying rates</p>
        </div>

        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
          <input 
            type="text" 
            placeholder="Search items..." 
            className="pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none w-full md:w-64"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="bg-amber-50 border-l-4 border-amber-500 p-4 rounded-r-lg flex items-start space-x-3">
        <AlertTriangle className="text-amber-600 shrink-0 mt-0.5" size={20} />
        <div>
          <h4 className="font-bold text-amber-800">Critical Warning</h4>
          <p className="text-sm text-amber-700 mt-1">
            Rates updated here reflect instantly in the staff billing panel. Do not change rates while a purchase is being negotiated to avoid discrepancies.
          </p>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200 text-slate-600 text-sm uppercase tracking-wider">
                <th className="p-4 font-semibold">Item Name</th>
                <th className="p-4 font-semibold">Category</th>
                <th className="p-4 font-semibold text-right">Current Rate (₹/Kg)</th>
                <th className="p-4 font-semibold text-right">Last Updated</th>
                <th className="p-4 font-semibold text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredItems.map((item) => (
                <tr key={item.id} className="hover:bg-slate-50 transition-colors">
                  <td className="p-4 font-medium text-slate-800">{item.name}</td>
                  <td className="p-4">
                    <span className="px-2 py-1 bg-slate-100 text-slate-600 rounded text-xs font-semibold">
                      {item.category}
                    </span>
                  </td>
                  <td className="p-4 text-right">
                    {editingId === item.id ? (
                      <input 
                        type="number" 
                        value={tempRate}
                        onChange={(e) => setTempRate(e.target.value)}
                        className="w-24 text-right p-1 border border-blue-400 rounded focus:ring-2 focus:ring-blue-500 outline-none"
                        autoFocus
                      />
                    ) : (
                      <span className="font-bold text-slate-700">₹{item.rate.toFixed(2)}</span>
                    )}
                  </td>
                  <td className="p-4 text-right text-sm text-slate-500">{item.lastUpdated}</td>
                  <td className="p-4 flex justify-center space-x-2">
                    {editingId === item.id ? (
                      <>
                        <button 
                          onClick={() => saveEdit(item.id)}
                          className="p-2 bg-green-100 text-green-700 rounded-lg hover:bg-green-200 transition"
                          title="Save"
                        >
                          <Save size={18} />
                        </button>
                        <button 
                          onClick={cancelEdit}
                          className="p-2 bg-red-100 text-red-700 rounded-lg hover:bg-red-200 transition"
                          title="Cancel"
                        >
                          <X size={18} />
                        </button>
                      </>
                    ) : (
                      <button 
                        onClick={() => startEdit(item.id, item.rate)}
                        className="p-2 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-100 transition"
                        title="Edit Rate"
                        disabled={item.name === 'Others' && item.rate === 0} // Disable edit for special logical items if needed
                      >
                        <Edit2 size={18} />
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {filteredItems.length === 0 && (
          <div className="p-8 text-center text-slate-500">
            No items found matching your search.
          </div>
        )}
      </div>
    </div>
  );
};

import React from 'react';
import { useApp } from '../../context/AppContext';
import { StockItem } from '../../types';

export const Stock = () => {
  const { items, bills } = useApp();

  // Calculate stock purely based on purchase bills for this UI-only demo
  // In a real app, you'd subtract sales. Here we just show purchased vs sold(mock 0)
  const stockData: StockItem[] = items.map(item => {
    // Only count items with fixed IDs, skip dynamic "Others" for strict tracking if needed, 
    // but here we include everything.
    const purchased = bills.reduce((acc, bill) => {
      const billItems = bill.items.filter(bi => bi.itemId === item.id);
      return acc + billItems.reduce((sum, bi) => sum + bi.weight, 0);
    }, 0);

    return {
      itemId: item.id,
      itemName: item.name,
      purchased: purchased,
      sold: 0, // Mock value as sales module isn't in scope
      available: purchased // Simple calculation
    };
  }).sort((a, b) => b.available - a.available);

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-slate-800">Stock Inventory</h1>
        <p className="text-slate-500 mt-1">Real-time overview of available materials</p>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200 text-slate-600 text-sm uppercase tracking-wider">
                <th className="p-4 font-semibold">Item Name</th>
                <th className="p-4 font-semibold text-right">Total Purchased (Kg)</th>
                <th className="p-4 font-semibold text-right">Total Sold (Kg)</th>
                <th className="p-4 font-semibold text-right">Available Stock (Kg)</th>
                <th className="p-4 font-semibold text-right">Est. Value (₹)</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {stockData.map((stock) => {
                const currentRate = items.find(i => i.id === stock.itemId)?.rate || 0;
                const value = stock.available * currentRate;

                return (
                  <tr key={stock.itemId} className="hover:bg-slate-50 transition-colors">
                    <td className="p-4 font-medium text-slate-800">{stock.itemName}</td>
                    <td className="p-4 text-right text-slate-600">{stock.purchased.toFixed(2)}</td>
                    <td className="p-4 text-right text-slate-400">{stock.sold.toFixed(2)}</td>
                    <td className="p-4 text-right font-bold text-blue-600">{stock.available.toFixed(2)}</td>
                    <td className="p-4 text-right text-slate-500">₹{value.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

