  const handleAddStaff = (e: React.FormEvent) => {
    e.preventDefault();
    if (newStaff.name && newStaff.phone && newStaff.role) {
      addStaff({
        id: Date.now().toString(),
        name: newStaff.name,
        phone: newStaff.phone,
