          >
            <UserPlus size={18} />
            <span>Add Staff</span>
          </button>
        )}
      </div>

      {/* Tabs */}
      <div className="flex border-b border-slate-200">
        <button 
          onClick={() => setActiveTab('staff')}
          className={`px-6 py-3 font-medium text-sm transition-colors border-b-2 ${activeTab === 'staff' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
        >
          All Staff
