import React, { useState, useRef } from 'react';
import { useApp } from '../../context/AppContext';
import { Upload, Save } from 'lucide-react';

export const CompanySettingsPage = () => {
  const { company, updateCompany } = useApp();
  const [formData, setFormData] = useState(company);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData(prev => ({ ...prev, [e.target.name]: e.target.value }));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({ ...prev, signatureUrl: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    updateCompany(formData);
    alert('Company settings updated successfully!');
  };

  return (
    <div className="max-w-3xl mx-auto space-y-6">
       <div>
          <h1 className="text-2xl font-bold text-slate-800">Company Settings</h1>
          <p className="text-slate-500 mt-1">Configure bill headers and digital signature</p>
        </div>

      <form onSubmit={handleSubmit} className="bg-white p-8 rounded-xl shadow-sm border border-slate-200 space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Company Name</label>
              <input 
                name="name"
                value={formData.name}
                onChange={handleChange}
                className="w-full p-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Subtitle / Tagline</label>
              <input 
                name="subtitle"
                value={formData.subtitle}
                onChange={handleChange}
                className="w-full p-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Contact Phone</label>
              <input 
                name="phone"
                value={formData.phone}
                onChange={handleChange}
                className="w-full p-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              />
            </div>
          </div>

          <div className="space-y-4">
             <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Full Address</label>
              <input 
                name="address"
                value={formData.address}
                onChange={handleChange}
                className="w-full p-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              />
            </div>

            <div className="pt-2">
              <label className="block text-sm font-medium text-slate-700 mb-2">Digital Signature</label>
              <div 
                className="border-2 border-dashed border-slate-300 rounded-lg p-4 text-center hover:bg-slate-50 cursor-pointer transition-colors"
                onClick={() => fileInputRef.current?.click()}
              >
                {formData.signatureUrl ? (
                  <div className="relative group">
                    <img 
                      src={formData.signatureUrl} 
                      alt="Signature" 
                      className="h-20 mx-auto object-contain"
                    />
                    <div className="absolute inset-0 bg-black/40 hidden group-hover:flex items-center justify-center text-white text-sm rounded">
                      Change Image
                    </div>
                  </div>
                ) : (
                  <div className="py-4">
                    <Upload className="mx-auto text-slate-400 mb-2" />
                    <span className="text-sm text-slate-500">Upload Signature Image</span>
                  </div>
                )}
                <input 
                  ref={fileInputRef}
                  type="file" 
                  accept="image/*" 
                  className="hidden" 
                  onChange={handleFileChange}
                />
              </div>
              <p className="text-xs text-slate-400 mt-2">Recommended: PNG with transparent background. Will be printed on PDF bills.</p>
            </div>
          </div>
        </div>

        <div className="pt-6 border-t border-slate-100">
           <div className="bg-slate-50 p-4 rounded-lg mb-6 border border-slate-200">
              <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Live Preview (Bill Header)</h4>
              <div className="text-center font-serif text-slate-800">
                <div className="font-bold text-lg">{formData.name}</div>
                <div className="text-xs text-slate-600">{formData.subtitle}</div>
                <div className="text-xs text-slate-600">{formData.address}</div>
              </div>
           </div>

          <button 
            type="submit"
            className="w-full md:w-auto px-8 py-3 bg-blue-600 hover:bg-blue-700 text-white font-medium rounded-lg flex items-center justify-center space-x-2 transition shadow-sm"
          >
            <Save size={20} />
            <span>Save Settings</span>
          </button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useApp } from '../../context/AppContext';
import { BillItem, Bill } from '../../types';
import { generateBillPDF } from '../../utils/pdfGenerator';
import { Plus, Trash2, RotateCcw, Download, Save, AlertCircle } from 'lucide-react';

export const Billing = () => {
  const { items, company, addBill } = useApp();

  // Form State
  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [billItems, setBillItems] = useState<BillItem[]>([]);

  // Temporary Item State
  const [selectedItemId, setSelectedItemId] = useState(items[0]?.id || '');
  const [weight, setWeight] = useState('');
  const [customName, setCustomName] = useState('');

  // Derived state
  const selectedItemData = items.find(i => i.id === selectedItemId);
  const currentRate = selectedItemData?.rate || 0;
  const isOthers = selectedItemData?.name === 'Others';
  const currentAmount = (parseFloat(weight) || 0) * currentRate;

  // Totals
  const totalAmount = billItems.reduce((sum, item) => sum + item.amount, 0);

  const addItem = () => {
    if (!selectedItemId || !weight || parseFloat(weight) <= 0) return;
    if (isOthers && !customName) return;

    const newItem: BillItem = {
      id: Date.now().toString(),
      itemId: selectedItemId,
      customName: isOthers ? customName : undefined,
      rate: currentRate,
      weight: parseFloat(weight),
      amount: currentAmount
    };

    setBillItems([...billItems, newItem]);

    // Reset inputs but keep item selection for speed
    setWeight('');
    setCustomName('');
  };

  const removeItem = (id: string) => {
    setBillItems(billItems.filter(item => item.id !== id));
  };

  const resetForm = () => {
    if (window.confirm("Are you sure you want to reset the form? All data will be lost.")) {
      setCustomerName('');
      setCustomerPhone('');
      setCustomerAddress('');
      setBillItems([]);
      setWeight('');
      setCustomName('');
    }
  };

  const handleGenerateBill = () => {
    if (!customerName || billItems.length === 0) {
      alert("Please fill customer details and add at least one item.");
      return;
    }

    const bill: Bill = {
      id: Date.now().toString(),
      billNo: `INV-${Date.now().toString().slice(-6)}`,
      customerName,
      customerPhone,
      customerAddress,
      items: billItems,
      totalAmount,
      date: new Date().toISOString(),
      staffName: 'Logged In User', // Simplified for demo
    };

    // Save to history
    addBill(bill);

    // Generate PDF
    generateBillPDF(bill, company);

    // Soft reset (keep customer details maybe? No, complete reset is safer for next customer)
    setCustomerName('');
    setCustomerPhone('');
    setCustomerAddress('');
    setBillItems([]);
    setWeight('');
  };

  return (
    <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-6">

      {/* Left Column: Inputs */}
      <div className="lg:col-span-2 space-y-6">

        {/* Customer Details */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold text-slate-800 mb-4 border-b pb-2">Customer Details</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Customer Name *</label>
              <input 
                type="text" 
                value={customerName}
                onChange={e => setCustomerName(e.target.value)}
                className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="Enter Name"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Phone Number</label>
              <input 
                type="tel" 
                value={customerPhone}
                onChange={e => setCustomerPhone(e.target.value)}
                className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="Mobile No."
              />
            </div>
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-slate-600 mb-1">Address</label>
              <input 
                type="text" 
                value={customerAddress}
                onChange={e => setCustomerAddress(e.target.value)}
                className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="City / Area"
              />
            </div>
          </div>
        </div>

        {/* Item Entry - High Emphasis */}
        <div className="bg-slate-800 p-6 rounded-xl shadow-lg text-white">
          <h3 className="text-lg font-bold text-blue-300 mb-4">Add Items</h3>
          <div className="grid grid-cols-1 md:grid-cols-12 gap-4 items-end">

            <div className="md:col-span-4">
              <label className="block text-sm text-slate-300 mb-1">Select Item</label>
              <select 
                value={selectedItemId}
                onChange={e => setSelectedItemId(e.target.value)}
                className="w-full p-3 bg-slate-700 border border-slate-600 rounded-lg focus:ring-2 focus:ring-blue-400 outline-none text-white"
              >
                {items.map(item => (
                  <option key={item.id} value={item.id}>
                    {item.name}
                  </option>
                ))}
              </select>
            </div>

            {isOthers && (
              <div className="md:col-span-3">
                 <label className="block text-sm text-slate-300 mb-1">Item Description</label>
                 <input 
                  type="text" 
                  value={customName}
                  onChange={e => setCustomName(e.target.value)}
                  className="w-full p-3 bg-slate-700 border border-slate-600 rounded-lg focus:ring-2 focus:ring-blue-400 outline-none text-white"
                  placeholder="Specify item"
                />
              </div>
            )}

            <div className={`md:col-span-${isOthers ? '2' : '3'}`}>
               <label className="block text-sm text-slate-300 mb-1">Rate (₹/kg)</label>
               <div className="w-full p-3 bg-slate-900/50 border border-slate-700 rounded-lg text-slate-400 cursor-not-allowed font-mono">
                 {currentRate.toFixed(2)}
               </div>
            </div>

            <div className={`md:col-span-${isOthers ? '3' : '3'}`}>
              <label className="block text-sm text-slate-300 mb-1">Weight (Kg)</label>
              <input 
                type="number" 
                value={weight}
                onChange={e => setWeight(e.target.value)}
                className="w-full p-3 bg-white text-slate-900 border border-transparent rounded-lg focus:ring-2 focus:ring-blue-400 outline-none font-bold text-lg"
                placeholder="0.00"
                step="0.01"
                min="0"
              />
            </div>

            <div className="md:col-span-2">
              <button 
                onClick={addItem}
                className="w-full p-3 bg-blue-600 hover:bg-blue-500 text-white font-bold rounded-lg transition-transform active:scale-95 flex justify-center items-center"
              >
                <Plus size={24} />
              </button>
            </div>
          </div>

          <div className="mt-3 flex justify-between items-center text-sm text-slate-400">
             <span>Live Amount: <span className="text-white font-bold">₹{currentAmount.toFixed(2)}</span></span>
             <span className="flex items-center text-amber-400"><AlertCircle size={14} className="mr-1"/> Rates fixed by Admin</span>
          </div>
        </div>

        {/* Items Table */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-600 text-sm uppercase">
              <tr>
                <th className="p-4">Item</th>
                <th className="p-4 text-right">Rate</th>
                <th className="p-4 text-right">Weight</th>
                <th className="p-4 text-right">Amount</th>
                <th className="p-4 text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {billItems.map((item) => {
                 const itemName = items.find(i => i.id === item.itemId)?.name;
                 const displayName = item.customName ? `${itemName} (${item.customName})` : itemName;
                 return (
                  <tr key={item.id} className="hover:bg-slate-50">
                    <td className="p-4 font-medium text-slate-800">{displayName}</td>
                    <td className="p-4 text-right text-slate-500">{item.rate.toFixed(2)}</td>
                    <td className="p-4 text-right font-mono">{item.weight.toFixed(2)}</td>
                    <td className="p-4 text-right font-bold text-slate-800">₹{item.amount.toFixed(2)}</td>
                    <td className="p-4 text-center">
                      <button 
                        onClick={() => removeItem(item.id)}
                        className="text-red-500 hover:bg-red-50 p-2 rounded-full transition"
                      >
                        <Trash2 size={18} />
                      </button>
                    </td>
                  </tr>
                 );
              })}
              {billItems.length === 0 && (
                <tr>
                  <td colSpan={5} className="p-8 text-center text-slate-400 italic">No items added yet.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Right Column: Summary & Actions */}
      <div className="space-y-6">
        <div className="bg-white p-6 rounded-xl shadow-lg border border-blue-100 sticky top-4">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Bill Summary</h3>

          <div className="space-y-4 mb-8">
            <div className="flex justify-between text-slate-600">
              <span>Total Items</span>
              <span className="font-medium">{billItems.length}</span>
            </div>
            <div className="flex justify-between text-slate-600">
              <span>Total Weight</span>
              <span className="font-medium">
                {billItems.reduce((sum, i) => sum + i.weight, 0).toFixed(2)} Kg
              </span>
            </div>
            <div className="border-t border-dashed border-slate-300 pt-4 flex justify-between items-end">
              <span className="text-lg font-bold text-slate-800">Grand Total</span>
              <span className="text-3xl font-bold text-blue-600">₹{totalAmount.toFixed(2)}</span>
            </div>
          </div>

          <div className="space-y-3">
            <button 
              onClick={handleGenerateBill}
              disabled={billItems.length === 0}
              className={`w-full py-4 rounded-lg font-bold text-lg flex items-center justify-center space-x-2 transition-all shadow-md
                ${billItems.length > 0 
                  ? 'bg-blue-600 hover:bg-blue-700 text-white hover:shadow-lg' 
                  : 'bg-slate-200 text-slate-400 cursor-not-allowed'}`}
            >
              <Save size={20} />
              <span>Generate & Save Bill</span>
            </button>

            <button 
              onClick={resetForm}
              className="w-full py-3 bg-white border border-slate-300 text-slate-600 rounded-lg hover:bg-slate-50 font-medium flex items-center justify-center space-x-2 transition"
            >
              <RotateCcw size={18} />
              <span>Reset Form</span>
            </button>
          </div>

          {/* Signature Preview */}
          <div className="mt-8 pt-6 border-t border-slate-100 text-center">
            <p className="text-xs text-slate-400 mb-2">Authorized By</p>
            {company.signatureUrl ? (
              <img src={company.signatureUrl} alt="Sig" className="h-10 mx-auto opacity-70" />
            ) : (
               <div className="h-10 flex items-center justify-center text-slate-300 text-xs italic">
                 No Signature Uploaded
               </div>
            )}
            <p className="text-xs font-bold text-slate-500 mt-1">{company.name}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

