import React, { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { ScrapItem, StaffMember, LeaveRequest, CompanySettings, Bill, ViewMode, Customer } from '../types';
import { INITIAL_ITEMS, INITIAL_STAFF, INITIAL_LEAVES, DEFAULT_COMPANY } from '../constants';

interface AppContextType {
  items: ScrapItem[];
  updateItemRate: (id: string, newRate: number) => void;
  staff: StaffMember[];
  addStaff: (member: StaffMember) => void;
  updateStaffStatus: (id: string, status: 'Active' | 'Inactive') => void;
  customers: Customer[];
  addCustomer: (customer: Customer) => void;
  leaves: LeaveRequest[];
  updateLeaveStatus: (id: string, status: 'Approved' | 'Rejected') => void;
  company: CompanySettings;
  updateCompany: (settings: CompanySettings) => void;
  bills: Bill[];
  addBill: (bill: Bill) => void;
  currentUser: StaffMember | null;
  login: (phone: string, password: string) => boolean;
  logout: () => void;
  viewMode: ViewMode;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider = ({ children }: { children?: ReactNode }) => {
  const [items, setItems] = useState<ScrapItem[]>(INITIAL_ITEMS);
  const [staff, setStaff] = useState<StaffMember[]>(INITIAL_STAFF);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [leaves, setLeaves] = useState<LeaveRequest[]>(INITIAL_LEAVES);
  const [company, setCompany] = useState<CompanySettings>(DEFAULT_COMPANY);
  const [bills, setBills] = useState<Bill[]>([]);

  // Auth State
  const [currentUser, setCurrentUser] = useState<StaffMember | null>(null);

  // Load from localStorage on mount (Simulating persistence)
  useEffect(() => {
    const savedBills = localStorage.getItem('apna_kabadi_bills');
    if (savedBills) setBills(JSON.parse(savedBills));

    const savedRates = localStorage.getItem('apna_kabadi_rates');
    if (savedRates) setItems(JSON.parse(savedRates));

    const savedStaff = localStorage.getItem('apna_kabadi_staff');
    if (savedStaff) setStaff(JSON.parse(savedStaff));

    const savedCustomers = localStorage.getItem('apna_kabadi_customers');
    if (savedCustomers) setCustomers(JSON.parse(savedCustomers));

    // Try to restore session
    const savedUser = localStorage.getItem('apna_kabadi_user');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
  }, []);

  // Save changes
  useEffect(() => {
    localStorage.setItem('apna_kabadi_bills', JSON.stringify(bills));
  }, [bills]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_rates', JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_staff', JSON.stringify(staff));
  }, [staff]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_customers', JSON.stringify(customers));
  }, [customers]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('apna_kabadi_user', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('apna_kabadi_user');
    }
  }, [currentUser]);

  const updateItemRate = (id: string, newRate: number) => {
    setItems(prev => prev.map(item => 
      item.id === id ? { ...item, rate: newRate, lastUpdated: new Date().toISOString().split('T')[0] } : item
    ));
  };

  const addStaff = (member: StaffMember) => {
    setStaff(prev => [...prev, member]);
  };

  const updateStaffStatus = (id: string, status: 'Active' | 'Inactive') => {
    setStaff(prev => prev.map(s => s.id === id ? { ...s, status } : s));
  };

  const addCustomer = (customer: Customer) => {
    // Check if exists
    if (!customers.some(c => c.phone === customer.phone)) {
      setCustomers(prev => [...prev, customer]);
    }
  };

  const updateLeaveStatus = (id: string, status: 'Approved' | 'Rejected') => {
    setLeaves(prev => prev.map(l => l.id === id ? { ...l, status } : l));
  };

  const updateCompany = (settings: CompanySettings) => {
    setCompany(settings);
  };

  const addBill = (bill: Bill) => {
    setBills(prev => [bill, ...prev]);
  };

  const login = (phone: string, pass: string): boolean => {
    const user = staff.find(s => s.phone === phone && s.password === pass && s.status === 'Active');
    if (user) {
      setCurrentUser(user);
      return true;
    }
    return false;
  };

  const logout = () => {
    setCurrentUser(null);
  };

  const viewMode: ViewMode = currentUser?.role === 'Manager' ? 'ADMIN' : 'STAFF';

  return (
    <AppContext.Provider value={{
      items, updateItemRate,
      staff, addStaff, updateStaffStatus,
      customers, addCustomer,
      leaves, updateLeaveStatus,
      company, updateCompany,
      bills, addBill,
      currentUser, login, logout, viewMode
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

import jsPDF from 'jspdf';
import { Bill, CompanySettings } from '../types';

export const generateBillPDF = (bill: Bill, company: CompanySettings, action: 'download' | 'print' = 'download') => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a5',
  });

  const margin = 10;
  const pageWidth = 148;
  const contentWidth = pageWidth - (margin * 2);
  let y = margin;

  // --- HEADER ---
  // Company Name
  doc.setFontSize(16);
  doc.setFont('helvetica', 'bold');
  doc.text(company.name.toUpperCase(), pageWidth / 2, y, { align: 'center' });
  y += 6;

  // Subtitle
  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(80);
  doc.text(company.subtitle, pageWidth / 2, y, { align: 'center' });
  y += 5;

  // Address & Phone
  doc.setFontSize(9);
  doc.text(company.address, pageWidth / 2, y, { align: 'center' });
  y += 4;
  doc.text(`Ph: ${company.phone}`, pageWidth / 2, y, { align: 'center' });

  y += 6;
  doc.setDrawColor(200);
  doc.line(margin, y, pageWidth - margin, y);
  y += 6;

  // --- INVOICE TITLE & STATUS ---
  doc.setFontSize(12);
  doc.setFont('helvetica', 'bold');
  doc.setTextColor(0);

  const title = bill.transactionType === 'SALE' ? 'SALES INVOICE' : 'PURCHASE RECEIPT';
  doc.text(title, margin, y);

  // Status Badge
  const statusColor = bill.paymentStatus === 'Paid' ? [34, 197, 94] : [239, 68, 68]; // Green or Red
  doc.setFillColor(statusColor[0], statusColor[1], statusColor[2]);
  doc.roundedRect(pageWidth - margin - 25, y - 4, 25, 6, 1, 1, 'F');
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(8);
  doc.text(bill.paymentStatus.toUpperCase(), pageWidth - margin - 12.5, y, { align: 'center' });

  y += 8;

  // --- METADATA ---
  doc.setTextColor(0);
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(9);

  const colLeft = margin;
  const colRight = pageWidth / 2 + 5;

  // Left Column (Bill Details)
  doc.text(`Bill No:`, colLeft, y);
  doc.setFont('helvetica', 'bold');
  doc.text(bill.billNo, colLeft + 15, y);

  // Right Column (Date)
  doc.setFont('helvetica', 'normal');
  doc.text(`Date:`, colRight, y);
  doc.setFont('helvetica', 'bold');
  doc.text(new Date(bill.date).toLocaleDateString(), colRight + 12, y);

  y += 6;

  // Customer Details Box
  doc.setFillColor(248, 250, 252); // Very light grey
  doc.rect(margin, y, contentWidth, 22, 'F');
  doc.setDrawColor(226, 232, 240);
  doc.rect(margin, y, contentWidth, 22, 'S');

  let cy = y + 5;
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(9);
  doc.text('Customer Details:', margin + 4, cy);

  doc.setFont('helvetica', 'normal');
  cy += 5;
  doc.text(`Name: ${bill.customerName}`, margin + 4, cy);
  cy += 4;
  doc.text(`Phone: ${bill.customerPhone}`, margin + 4, cy);
  if (bill.customerAddress) {
    cy += 4;
    doc.text(`Addr: ${bill.customerAddress}`, margin + 4, cy);
  }

  y += 28;

  // --- ITEM TABLE ---
  const cols = {
    item: margin + 2,
    rate: 80,
    weight: 105,
    amount: pageWidth - margin - 2
  };

  // Table Header
  doc.setFillColor(51, 65, 85); // Slate 700
  doc.rect(margin, y, contentWidth, 8, 'F');
  doc.setTextColor(255);
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(9);

  doc.text('Item Name', cols.item, y + 5.5);
  doc.text('Rate', cols.rate, y + 5.5, { align: 'right' });
  doc.text('Weight', cols.weight, y + 5.5, { align: 'right' });
  doc.text('Amount', cols.amount, y + 5.5, { align: 'right' });

  y += 8;

  // Table Rows
  doc.setTextColor(0);
  doc.setFont('helvetica', 'normal');

  let totalWeight = 0;

  bill.items.forEach((item, index) => {
    // Alternating row color
    if (index % 2 === 0) {
      doc.setFillColor(255, 255, 255);
    } else {
      doc.setFillColor(249, 250, 251);
    }
    doc.rect(margin, y, contentWidth, 8, 'F');

    let itemName = item.customName || 'Unknown';
    if (itemName.length > 20) itemName = itemName.substring(0, 18) + '...';

    doc.text(itemName, cols.item, y + 5.5);
    doc.text(item.rate.toFixed(2), cols.rate, y + 5.5, { align: 'right' });
    doc.text(item.weight.toFixed(2), cols.weight, y + 5.5, { align: 'right' });
    doc.text(item.amount.toFixed(2), cols.amount, y + 5.5, { align: 'right' });

    totalWeight += item.weight;
    y += 8;
  });

  // Table Border Bottom
  doc.setDrawColor(200);
  doc.line(margin, y, pageWidth - margin, y);
  y += 2;

  // --- TOTALS ---
  y += 4;
  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.text(`Total Items: ${bill.items.length}`, margin, y);
  doc.text(`Total Weight: ${totalWeight.toFixed(2)} Kg`, margin + 40, y);

  y += 8;
  doc.setFontSize(14);
  doc.setFont('helvetica', 'bold');

  // Highlight Total
  doc.setFillColor(240, 253, 244); // Light Green bg
  if (bill.transactionType === 'SALE') doc.setFillColor(255, 251, 235); // Light Yellow for Sale

  doc.roundedRect(pageWidth - margin - 60, y - 6, 60, 10, 1, 1, 'F');

  doc.text('TOTAL:', pageWidth - margin - 35, y, { align: 'right' });
  doc.text(`₹ ${bill.totalAmount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}`, pageWidth - margin - 5, y, { align: 'right' });

  // --- SIGNATURE ---
  y += 20; // Space for spacing
  if (y > 170) { doc.addPage(); y = 20; } // New page if low

  if (company.signatureUrl) {
    doc.addImage(company.signatureUrl, 'PNG', pageWidth - margin - 40, y, 35, 12);
    y += 12;
  } else {
    y += 10;
  }

  doc.setFontSize(8);
  doc.setFont('helvetica', 'normal');
  doc.text('Authorized Signature', pageWidth - margin - 22, y + 4, { align: 'center' });

  // Footer
  doc.setFontSize(7);
  doc.setTextColor(150);
  doc.text('Generated by Apna Kabadi Manager', pageWidth / 2, 200, { align: 'center' });

  if (action === 'print') {
    doc.autoPrint();
    const blob = doc.output('bloburl');
    window.open(blob, '_blank');
  } else {
    doc.save(`${bill.transactionType}_${bill.billNo}.pdf`);
  }
};

import React, { useState } from 'react';
import { useApp } from '../../context/AppContext';
import { BillItem, Bill, TransactionType, PaymentStatus, Customer } from '../../types';
