};

import React from 'react';
import { useApp } from '../../context/AppContext';
import { StockItem } from '../../types';

export const Stock = () => {
  const { items, bills } = useApp();

  const stockData: StockItem[] = items.map(item => {
    // Purchases: Weight added to stock
    const purchased = bills
      .filter(b => b.transactionType === 'PURCHASE')
      .reduce((acc, bill) => {
        const billItems = bill.items.filter(bi => bi.itemId === item.id);
        return acc + billItems.reduce((sum, bi) => sum + bi.weight, 0);
      }, 0);

    // Sales: Weight removed from stock
    const sold = bills
      .filter(b => b.transactionType === 'SALE')
      .reduce((acc, bill) => {
        const billItems = bill.items.filter(bi => bi.itemId === item.id);
        return acc + billItems.reduce((sum, bi) => sum + bi.weight, 0);
      }, 0);

    return {
      itemId: item.id,
      itemName: item.name,
      purchased: purchased,
      sold: sold,
      available: purchased - sold
    };
  }).sort((a, b) => b.available - a.available);

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-slate-800">Stock Inventory</h1>
        <p className="text-slate-500 mt-1">Real-time overview of available materials</p>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200 text-slate-600 text-sm uppercase tracking-wider">
                <th className="p-4 font-semibold">Item Name</th>
                <th className="p-4 font-semibold text-right">In (Purchase)</th>
                <th className="p-4 font-semibold text-right">Out (Sold)</th>
                <th className="p-4 font-semibold text-right">Net Stock (Kg)</th>
                <th className="p-4 font-semibold text-right">Est. Value (₹)</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {stockData.map((stock) => {
                const currentRate = items.find(i => i.id === stock.itemId)?.rate || 0;
                const value = stock.available * currentRate;

                return (
                  <tr key={stock.itemId} className="hover:bg-slate-50 transition-colors">
                    <td className="p-4 font-medium text-slate-800">{stock.itemName}</td>
                    <td className="p-4 text-right text-blue-600 font-medium">{stock.purchased.toFixed(2)}</td>
                    <td className="p-4 text-right text-emerald-600 font-medium">{stock.sold.toFixed(2)}</td>
                    <td className={`p-4 text-right font-bold ${stock.available < 0 ? 'text-red-600' : 'text-slate-800'}`}>
                      {stock.available.toFixed(2)}
                    </td>
                    <td className="p-4 text-right text-slate-500">₹{value.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../../context/AppContext';
import { BillItem, Bill, TransactionType, PaymentStatus, Customer } from '../../types';
import { generateBillPDF } from '../../utils/pdfGenerator';
import { Plus, Trash2, RotateCcw, Save, AlertCircle, Printer, Share2, CheckCircle, FileDown, Search, ArrowRightLeft, UserPlus } from 'lucide-react';

export const Billing = () => {
  const { items, company, addBill, currentUser, customers, addCustomer } = useApp();

  // Transaction Mode
  const [transactionType, setTransactionType] = useState<TransactionType>('PURCHASE');

  // Form State
  const [customerSearch, setCustomerSearch] = useState('');
  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);
  const [selectedCustomerId, setSelectedCustomerId] = useState<string | undefined>(undefined);

  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('Paid');

  const [billItems, setBillItems] = useState<BillItem[]>([]);

  // Item Entry State
  const [selectedItemId, setSelectedItemId] = useState(items[0]?.id || '');
  const [weight, setWeight] = useState('');
  const [customName, setCustomName] = useState('');
  const [manualRate, setManualRate] = useState(''); // For Sales

  // Success Modal State
  const [lastBill, setLastBill] = useState<Bill | null>(null);
  const [showSuccessModal, setShowSuccessModal] = useState(false);

  // Derived state
  const selectedItemData = items.find(i => i.id === selectedItemId);
  const isOthers = selectedItemData?.name === 'Others';

  // Rate Logic: Purchase = Fixed Admin Rate, Sale = Manual/Negotiated Rate (Default to Admin Rate)
  const activeRate = transactionType === 'SALE' && manualRate 
    ? parseFloat(manualRate) 
    : (selectedItemData?.rate || 0);

  const currentAmount = (parseFloat(weight) || 0) * activeRate;
  const totalAmount = billItems.reduce((sum, item) => sum + item.amount, 0);

  // Filter customers for autocomplete
  const filteredCustomers = customers.filter(c => 
    c.name.toLowerCase().includes(customerSearch.toLowerCase()) || 
    c.phone.includes(customerSearch)
  );

  const selectCustomer = (customer: Customer) => {
    setCustomerName(customer.name);
    setCustomerPhone(customer.phone);
    setCustomerAddress(customer.address);
    setSelectedCustomerId(customer.id);
    setCustomerSearch('');
    setShowCustomerSuggestions(false);
  };

  const addItem = () => {
    if (!selectedItemId || !weight || parseFloat(weight) <= 0) return;
    if (isOthers && !customName) return;

    const newItem: BillItem = {
      id: Date.now().toString(),
      itemId: selectedItemId,
      customName: isOthers ? customName : undefined,
      rate: activeRate,
      weight: parseFloat(weight),
      amount: currentAmount
    };

    setBillItems([...billItems, newItem]);

    // Reset inputs
    setWeight('');
    setCustomName('');
    setManualRate('');
  };

  const removeItem = (id: string) => {
    setBillItems(billItems.filter(item => item.id !== id));
  };

  const resetForm = () => {
    if (billItems.length === 0 || window.confirm("Reset the current form?")) {
      setCustomerName('');
      setCustomerPhone('');
      setCustomerAddress('');
      setSelectedCustomerId(undefined);
      setBillItems([]);
      setWeight('');
      setCustomName('');
      setManualRate('');
      setPaymentStatus('Paid');
    }
  };

  const handleGenerateBill = () => {
    if (!customerName || billItems.length === 0) {
      alert("Please fill customer details and add at least one item.");
      return;
    }

    if (!window.confirm("Are you sure you want to generate this invoice?")) {
      return;
    }

    // Auto-save new customer if phone doesn't exist
    if (customerPhone && !customers.some(c => c.phone === customerPhone)) {
      addCustomer({
        id: Date.now().toString(),
        name: customerName,
        phone: customerPhone,
        address: customerAddress
      });
    }

    const bill: Bill = {
      id: Date.now().toString(),
      billNo: `INV-${Date.now().toString().slice(-6)}`,
      transactionType,
      customerId: selectedCustomerId,
      customerName,
      customerPhone,
      customerAddress,
      items: billItems,
      totalAmount,
      paymentStatus,
      date: new Date().toISOString(),
      staffName: currentUser?.name || 'Staff',
    };

    addBill(bill);
    setLastBill(bill);

    // Clear form directly to avoid second confirmation
    setCustomerName('');
    setCustomerPhone('');
    setCustomerAddress('');
    setSelectedCustomerId(undefined);
    setBillItems([]);
    setWeight('');
    setCustomName('');
    setManualRate('');
    setPaymentStatus('Paid');

    setShowSuccessModal(true);
  };

  const shareViaWhatsApp = () => {
    if (!lastBill) return;
    const type = lastBill.transactionType === 'PURCHASE' ? 'Purchase Receipt' : 'Sales Invoice';
