import React from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AppProvider, useApp } from './context/AppContext';
import { Layout } from './components/Layout';
import { Login } from './pages/Login';
import { Dashboard } from './pages/admin/Dashboard';
import { RateChart } from './pages/admin/RateChart';
import { Stock } from './pages/admin/Stock';
import { Staff } from './pages/admin/Staff';
import { CompanySettingsPage } from './pages/admin/CompanySettings';
import { Billing } from './pages/staff/Billing';
import { BillHistory } from './pages/staff/BillHistory';

// Simple Route Guard
const RoleGuard = ({ children, allowedMode }: { children?: React.ReactNode, allowedMode: 'ADMIN' | 'STAFF' }) => {
  const { currentUser } = useApp();

  if (!currentUser) {
    return <Navigate to="/login" replace />;
  }

  // Derive mode from role
  const currentMode = currentUser.role === 'Manager' ? 'ADMIN' : 'STAFF';

  if (currentMode !== allowedMode) {
    return <Navigate to={allowedMode === 'ADMIN' ? '/staff/billing' : '/admin/dashboard'} replace />;
  }
  return <>{children}</>;
};

const AppRoutes = () => {
  return (
    <Routes>
      <Route path="/login" element={<Login />} />
      <Route path="/" element={<Navigate to="/login" replace />} />

      {/* Admin Routes */}
      <Route path="/admin/*" element={
        <RoleGuard allowedMode="ADMIN">
          <Layout>
             <Routes>
              <Route path="dashboard" element={<Dashboard />} />
              <Route path="rates" element={<RateChart />} />
              <Route path="stock" element={<Stock />} />
              <Route path="billing" element={<Billing />} />
              <Route path="transactions" element={<BillHistory />} />
              <Route path="staff" element={<Staff />} />
              <Route path="settings" element={<CompanySettingsPage />} />
              <Route path="*" element={<Navigate to="dashboard" replace />} />
            </Routes>
          </Layout>
        </RoleGuard>
      } />

      {/* Staff Routes */}
      <Route path="/staff/*" element={
        <RoleGuard allowedMode="STAFF">
          <Layout>
            <Routes>
              <Route path="billing" element={<Billing />} />
              <Route path="history" element={<BillHistory />} />
              <Route path="*" element={<Navigate to="billing" replace />} />
            </Routes>
          </Layout>
        </RoleGuard>
      } />
    </Routes>
  );
};

const App = () => {
  return (
    <AppProvider>
      <HashRouter>
        <AppRoutes />
      </HashRouter>
    </AppProvider>
  );
};

export default App;

import React from 'react';
import { useApp } from '../../context/AppContext';
import { StockItem } from '../../types';
import { Plus } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

export const Stock = () => {
  const { items, bills } = useApp();
  const navigate = useNavigate();

  const stockData: StockItem[] = items.map(item => {
    // Purchases: Weight added to stock
    const purchased = bills
      .filter(b => b.transactionType === 'PURCHASE')
      .reduce((acc, bill) => {
        const billItems = bill.items.filter(bi => bi.itemId === item.id);
        return acc + billItems.reduce((sum, bi) => sum + bi.weight, 0);
      }, 0);

    // Sales: Weight removed from stock
    const sold = bills
      .filter(b => b.transactionType === 'SALE')
      .reduce((acc, bill) => {
        const billItems = bill.items.filter(bi => bi.itemId === item.id);
        return acc + billItems.reduce((sum, bi) => sum + bi.weight, 0);
      }, 0);

    return {
      itemId: item.id,
      itemName: item.name,
      purchased: purchased,
      sold: sold,
      available: purchased - sold
    };
  }).sort((a, b) => b.available - a.available);

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Stock Inventory</h1>
          <p className="text-slate-500 mt-1">Real-time overview of available materials</p>
        </div>

        <button 
          onClick={() => navigate('/admin/billing')}
          className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg transition-colors font-medium shadow-sm"
        >
          <Plus size={18} />
          <span>Add New Purchase</span>
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200 text-slate-600 text-sm uppercase tracking-wider">
                <th className="p-4 font-semibold">Item Name</th>
                <th className="p-4 font-semibold text-right">In (Purchase)</th>
                <th className="p-4 font-semibold text-right">Out (Sold)</th>
                <th className="p-4 font-semibold text-right">Net Stock (Kg)</th>
                <th className="p-4 font-semibold text-right">Est. Value (₹)</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {stockData.map((stock) => {
                const currentRate = items.find(i => i.id === stock.itemId)?.rate || 0;
                const value = stock.available * currentRate;

                return (
                  <tr key={stock.itemId} className="hover:bg-slate-50 transition-colors">
                    <td className="p-4 font-medium text-slate-800">{stock.itemName}</td>
                    <td className="p-4 text-right text-blue-600 font-medium">{stock.purchased.toFixed(2)}</td>
                    <td className="p-4 text-right text-emerald-600 font-medium">{stock.sold.toFixed(2)}</td>
                    <td className={`p-4 text-right font-bold ${stock.available < 0 ? 'text-red-600' : 'text-slate-800'}`}>
                      {stock.available.toFixed(2)}
                    </td>
                    <td className="p-4 text-right text-slate-500">₹{value.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

