};

import React, { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { ScrapItem, StaffMember, LeaveRequest, CompanySettings, Bill, ViewMode, Customer, SalaryPayment } from '../types';
import { INITIAL_ITEMS, INITIAL_STAFF, INITIAL_LEAVES, DEFAULT_COMPANY } from '../constants';

interface AppContextType {
  items: ScrapItem[];
  updateItemRate: (id: string, newRate: number) => void;
  staff: StaffMember[];
  addStaff: (member: StaffMember) => void;
  updateStaffStatus: (id: string, status: 'Active' | 'Inactive') => void;
  updateStaffPassword: (id: string, newPass: string) => void;
  customers: Customer[];
  addCustomer: (customer: Customer) => void;
  updateCustomer: (id: string, data: Partial<Customer>) => void;
  leaves: LeaveRequest[];
  updateLeaveStatus: (id: string, status: 'Approved' | 'Rejected') => void;
  salaryPayments: SalaryPayment[];
  addSalaryPayment: (payment: SalaryPayment) => void;
  company: CompanySettings;
  updateCompany: (settings: CompanySettings) => void;
  bills: Bill[];
  addBill: (bill: Bill) => void;
  currentUser: StaffMember | null;
  login: (phone: string, password: string) => boolean;
  logout: () => void;
  viewMode: ViewMode;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider = ({ children }: { children?: ReactNode }) => {
  const [items, setItems] = useState<ScrapItem[]>(INITIAL_ITEMS);
  const [staff, setStaff] = useState<StaffMember[]>(INITIAL_STAFF);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [leaves, setLeaves] = useState<LeaveRequest[]>(INITIAL_LEAVES);
  const [salaryPayments, setSalaryPayments] = useState<SalaryPayment[]>([]);
  const [company, setCompany] = useState<CompanySettings>(DEFAULT_COMPANY);
  const [bills, setBills] = useState<Bill[]>([]);

  // Auth State
  const [currentUser, setCurrentUser] = useState<StaffMember | null>(null);

  // Load from localStorage on mount (Simulating persistence)
  useEffect(() => {
    const savedBills = localStorage.getItem('apna_kabadi_bills');
    if (savedBills) setBills(JSON.parse(savedBills));

    const savedRates = localStorage.getItem('apna_kabadi_rates');
    if (savedRates) setItems(JSON.parse(savedRates));

    const savedStaff = localStorage.getItem('apna_kabadi_staff');
    if (savedStaff) setStaff(JSON.parse(savedStaff));

    const savedCustomers = localStorage.getItem('apna_kabadi_customers');
    if (savedCustomers) setCustomers(JSON.parse(savedCustomers));

    const savedSalaries = localStorage.getItem('apna_kabadi_salaries');
    if (savedSalaries) setSalaryPayments(JSON.parse(savedSalaries));

    // Try to restore session
    const savedUser = localStorage.getItem('apna_kabadi_user');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
  }, []);

  // Save changes
  useEffect(() => {
    localStorage.setItem('apna_kabadi_bills', JSON.stringify(bills));
  }, [bills]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_rates', JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_staff', JSON.stringify(staff));
  }, [staff]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_customers', JSON.stringify(customers));
  }, [customers]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_salaries', JSON.stringify(salaryPayments));
  }, [salaryPayments]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('apna_kabadi_user', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('apna_kabadi_user');
    }
  }, [currentUser]);

  const updateItemRate = (id: string, newRate: number) => {
    setItems(prev => prev.map(item => 
      item.id === id ? { ...item, rate: newRate, lastUpdated: new Date().toISOString().split('T')[0] } : item
    ));
  };

  const addStaff = (member: StaffMember) => {
    setStaff(prev => [...prev, member]);
  };

  const updateStaffStatus = (id: string, status: 'Active' | 'Inactive') => {
    setStaff(prev => prev.map(s => s.id === id ? { ...s, status } : s));
  };

  const updateStaffPassword = (id: string, newPass: string) => {
    setStaff(prev => prev.map(s => s.id === id ? { ...s, password: newPass } : s));
  };

  const addCustomer = (customer: Customer) => {
    // Check if exists
    if (!customers.some(c => c.phone === customer.phone)) {
      setCustomers(prev => [...prev, customer]);
    }
  };

  const updateCustomer = (id: string, data: Partial<Customer>) => {
    setCustomers(prev => prev.map(c => c.id === id ? { ...c, ...data } : c));
  };

  const updateLeaveStatus = (id: string, status: 'Approved' | 'Rejected') => {
    setLeaves(prev => prev.map(l => l.id === id ? { ...l, status } : l));
  };

  const addSalaryPayment = (payment: SalaryPayment) => {
    setSalaryPayments(prev => [payment, ...prev]);
  };

  const updateCompany = (settings: CompanySettings) => {
    setCompany(settings);
  };

  const addBill = (bill: Bill) => {
    setBills(prev => [bill, ...prev]);
  };

  const login = (phone: string, pass: string): boolean => {
    const user = staff.find(s => s.phone === phone && s.password === pass && s.status === 'Active');
    if (user) {
      setCurrentUser(user);
      return true;
    }
    return false;
  };

  const logout = () => {
    setCurrentUser(null);
  };

  const viewMode: ViewMode = currentUser?.role === 'Manager' ? 'ADMIN' : 'STAFF';

  return (
    <AppContext.Provider value={{
      items, updateItemRate,
      staff, addStaff, updateStaffStatus, updateStaffPassword,
      customers, addCustomer, updateCustomer,
      leaves, updateLeaveStatus,
      salaryPayments, addSalaryPayment,
      company, updateCompany,
      bills, addBill,
      currentUser, login, logout, viewMode
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

import React, { useState } from 'react';
import { useApp } from '../../context/AppContext';
import { Customer } from '../../types';
import { Search, UserPlus, MapPin, Phone, Edit, ArrowDownLeft, ArrowUpRight } from 'lucide-react';

export const Customers = () => {
  const { customers, bills, addCustomer, updateCustomer } = useApp();
  const [searchTerm, setSearchTerm] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  // Form State
  const [formData, setFormData] = useState<Partial<Customer>>({
    name: '',
    phone: '',
    address: ''
  });

  const filteredCustomers = customers.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.phone.includes(searchTerm) ||
    c.address.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleOpenModal = (customer?: Customer) => {
    if (customer) {
      setEditingId(customer.id);
      setFormData(customer);
    } else {
      setEditingId(null);
      setFormData({ name: '', phone: '', address: '' });
    }
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.phone || !formData.address) return;

    if (editingId) {
      updateCustomer(editingId, formData);
    } else {
      // Check for duplicate phone on new add
      if (customers.some(c => c.phone === formData.phone)) {
        alert('A customer with this phone number already exists.');
        return;
      }
      addCustomer({
        id: Date.now().toString(),
        name: formData.name,
        phone: formData.phone,
        address: formData.address
      } as Customer);
    }
    setShowModal(false);
  };

  return (
    <div className="max-w-6xl mx-auto space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
           <h1 className="text-2xl font-bold text-slate-800">Customer Management</h1>
           <p className="text-slate-500 mt-1">Manage client database and view history</p>
        </div>

        <div className="flex gap-3">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="Search customers..." 
              className="pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none w-full md:w-64"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={() => handleOpenModal()}
            className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg transition-colors font-medium shadow-sm whitespace-nowrap"
          >
            <UserPlus size={18} />
            <span>Add Customer</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200 text-slate-600 text-sm uppercase tracking-wider">
                <th className="p-4 font-semibold">Customer Details</th>
                <th className="p-4 font-semibold">Location</th>
                <th className="p-4 font-semibold text-center">Total Visits</th>
                <th className="p-4 font-semibold text-right">Total Trade Volume</th>
                <th className="p-4 font-semibold text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredCustomers.map((customer) => {
                // Calculate Stats
                const customerBills = bills.filter(b => b.customerPhone === customer.phone || b.customerId === customer.id);
                const totalPurchase = customerBills.filter(b => b.transactionType === 'PURCHASE').reduce((s, b) => s + b.totalAmount, 0);
                const totalSale = customerBills.filter(b => b.transactionType === 'SALE').reduce((s, b) => s + b.totalAmount, 0);

                return (
                  <tr key={customer.id} className="hover:bg-slate-50 transition-colors">
                    <td className="p-4">
                      <div className="font-bold text-slate-800">{customer.name}</div>
                      <div className="flex items-center text-slate-500 text-sm mt-0.5">
                        <Phone size={12} className="mr-1" />
                        {customer.phone}
                      </div>
                    </td>
                    <td className="p-4">
                       <div className="flex items-start text-slate-600 text-sm">
                        <MapPin size={14} className="mr-1 mt-0.5 shrink-0 text-slate-400" />
                        {customer.address}
                      </div>
                    </td>
                    <td className="p-4 text-center">
                      <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-slate-100 text-slate-800">
                        {customerBills.length}
                      </span>
                    </td>
                    <td className="p-4 text-right">
                       <div className="space-y-1">
                          {totalPurchase > 0 && (
                            <div className="text-xs flex justify-end items-center text-blue-600 font-medium">
                              <ArrowDownLeft size={12} className="mr-1" />
                              Bought: ₹{totalPurchase.toLocaleString()}
                            </div>
                          )}
                          {totalSale > 0 && (
                            <div className="text-xs flex justify-end items-center text-emerald-600 font-medium">
                               <ArrowUpRight size={12} className="mr-1" />
                               Sold: ₹{totalSale.toLocaleString()}
                            </div>
                          )}
                          {totalPurchase === 0 && totalSale === 0 && (
                            <span className="text-slate-400 text-xs">-</span>
                          )}
                       </div>
                    </td>
                    <td className="p-4 text-center">
                      <button 
                        onClick={() => handleOpenModal(customer)}
                        className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-full transition"
                      >
                        <Edit size={18} />
                      </button>
                    </td>
