            </button>
          </div>
        </div>
      </div>

      {/* POS Success Modal */}
      {showSuccessModal && lastBill && (
        <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl max-w-lg w-full p-8 text-center relative animate-in fade-in zoom-in duration-200">
            <div className="mx-auto w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mb-4">
              <CheckCircle className="text-green-600" size={32} />
            </div>

            <h2 className="text-2xl font-bold text-slate-800 mb-2">Invoice Generated!</h2>
            <p className="text-slate-500 mb-8">
              {lastBill.transactionType} Invoice #{lastBill.billNo} saved.
            </p>

            <div className="grid grid-cols-2 gap-4 mb-4">
               <button 
                 onClick={() => generateBillPDF(lastBill, company, 'print')}
                 className="flex flex-col items-center justify-center p-4 bg-slate-50 hover:bg-slate-100 rounded-xl border border-slate-200 transition"
               >
                 <Printer size={28} className="text-slate-700 mb-2" />
                 <span className="font-medium text-slate-700">Print Receipt</span>
               </button>

               <button 
                 onClick={() => generateBillPDF(lastBill, company, 'download')}
                 className="flex flex-col items-center justify-center p-4 bg-slate-50 hover:bg-slate-100 rounded-xl border border-slate-200 transition"
               >
                 <FileDown size={28} className="text-slate-700 mb-2" />
                 <span className="font-medium text-slate-700">Download PDF</span>
               </button>
            </div>

            <button 
              onClick={shareViaWhatsApp}
              className="w-full flex items-center justify-center space-x-2 py-3 bg-green-500 hover:bg-green-600 text-white rounded-xl font-bold transition mb-6"
            >
              <Share2 size={20} />
              <span>Send via WhatsApp</span>
            </button>

            <button 
              onClick={() => setShowSuccessModal(false)}
              className="text-slate-500 hover:text-slate-700 font-medium underline"
            >
              Start New Order
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { useApp } from '../../context/AppContext';
import { BillItem, Bill, TransactionType, PaymentStatus, Customer } from '../../types';
import { generateBillPDF } from '../../utils/pdfGenerator';
import { Plus, Trash2, RotateCcw, Save, AlertCircle, Printer, Share2, CheckCircle, FileDown, Search, ArrowRightLeft } from 'lucide-react';

export const Billing = () => {
  const { items, company, addBill, currentUser, customers, addCustomer } = useApp();

  // Refs for Focus Management
  const itemSelectRef = useRef<HTMLSelectElement>(null);
  const weightInputRef = useRef<HTMLInputElement>(null);

  // Transaction Mode
  const [transactionType, setTransactionType] = useState<TransactionType>('PURCHASE');

  // Form State
  const [customerSearch, setCustomerSearch] = useState('');
  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);
  const [selectedCustomerId, setSelectedCustomerId] = useState<string | undefined>(undefined);

  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('Paid');

  const [billItems, setBillItems] = useState<BillItem[]>([]);

  // Item Entry State
  const [selectedItemId, setSelectedItemId] = useState(items[0]?.id || '');
  const [weight, setWeight] = useState('');
  const [customName, setCustomName] = useState('');
  const [manualRate, setManualRate] = useState(''); // For Sales
  const [formError, setFormError] = useState<string | null>(null);

  // Modal States
  const [lastBill, setLastBill] = useState<Bill | null>(null);
  const [showSuccessModal, setShowSuccessModal] = useState(false);
  const [showConfirmationModal, setShowConfirmationModal] = useState(false);

  // Derived state
  const selectedItemData = items.find(i => i.id === selectedItemId);
  const isOthers = selectedItemData?.name === 'Others' || selectedItemData?.category === 'Others';

  // Rate Logic: Purchase = Fixed Admin Rate, Sale = Manual/Negotiated Rate (Default to Admin Rate)
  const activeRate = transactionType === 'SALE' && manualRate 
    ? parseFloat(manualRate) 
    : (selectedItemData?.rate || 0);

  const currentAmount = (parseFloat(weight) || 0) * activeRate;
  const totalAmount = billItems.reduce((sum, item) => sum + item.amount, 0);

  // Filter customers for autocomplete
  const filteredCustomers = customers.filter(c => 
    c.name.toLowerCase().includes(customerSearch.toLowerCase()) || 
    c.phone.includes(customerSearch)
  );

  const selectCustomer = (customer: Customer) => {
    setCustomerName(customer.name);
    setCustomerPhone(customer.phone);
    setCustomerAddress(customer.address);
    setSelectedCustomerId(customer.id);
    setCustomerSearch('');
    setShowCustomerSuggestions(false);
  };

  const addItem = () => {
    // Validation
    if (!selectedItemId) return;
    if (!weight || parseFloat(weight) <= 0) {
      setFormError('weight');
      weightInputRef.current?.focus();
      return;
    }
    if (isOthers && !customName) {
      setFormError('customName');
      return;
    }

    setFormError(null);

    const resolvedName = isOthers && customName 
      ? `Others (${customName})` 
      : (selectedItemData?.name || 'Unknown');

    const newItem: BillItem = {
      id: Date.now().toString(),
      itemId: selectedItemId,
      itemName: resolvedName,
      customName: isOthers ? customName : undefined,
      rate: activeRate,
      weight: parseFloat(weight),
      amount: currentAmount
    };

    setBillItems([...billItems, newItem]);

    // Reset inputs
    setWeight('');
    setCustomName('');
    setManualRate('');

    // Focus back to Item Select for rapid entry
    if (window.innerWidth > 768) {
      itemSelectRef.current?.focus();
    }
  };

  const removeItem = (id: string) => {
    setBillItems(billItems.filter(item => item.id !== id));
  };

  const resetForm = () => {
    if (billItems.length === 0 || window.confirm("Reset the current form?")) {
      setCustomerName('');
      setCustomerPhone('');
      setCustomerAddress('');
      setSelectedCustomerId(undefined);
      setBillItems([]);
      setWeight('');
      setCustomName('');
      setManualRate('');
      setPaymentStatus('Paid');
      setFormError(null);
    }
  };

  const handleGenerateBill = () => {
    if (!customerName || billItems.length === 0) {
      alert("Please fill customer details and add at least one item.");
      return;
    }
    setShowConfirmationModal(true);
  };

  const finalizeBillGeneration = () => {
    // Auto-save new customer if phone doesn't exist
    if (customerPhone && !customers.some(c => c.phone === customerPhone)) {
      addCustomer({
        id: Date.now().toString(),
        name: customerName,
        phone: customerPhone,
        address: customerAddress
      });
    }

    // Create unique bill number (INV-YYYYMMDD-XXXX)
    const dateStr = new Date().toISOString().slice(0,10).replace(/-/g, '');
    const randomSuffix = Math.floor(1000 + Math.random() * 9000);
    const uniqueBillNo = `INV-${dateStr}-${randomSuffix}`;

    const bill: Bill = {
      id: Date.now().toString(),
      billNo: uniqueBillNo,
      transactionType,
      customerId: selectedCustomerId,
      customerName,
      customerPhone,
      customerAddress,
      items: billItems,
      totalAmount,
      paymentStatus,
      date: new Date().toISOString(),
      staffName: currentUser?.name || 'Staff',
    };

    addBill(bill);
    setLastBill(bill);

    // Clear form
    setCustomerName('');
    setCustomerPhone('');
    setCustomerAddress('');
    setSelectedCustomerId(undefined);
    setBillItems([]);
    setWeight('');
    setCustomName('');
    setManualRate('');
    setPaymentStatus('Paid');

    setShowConfirmationModal(false);
    setShowSuccessModal(true);
  };

  const shareViaWhatsApp = () => {
    if (!lastBill) return;
    const type = lastBill.transactionType === 'PURCHASE' ? 'Purchase Receipt' : 'Sales Invoice';
    const text = `*${company.name}*\n${type} #${lastBill.billNo}\nDate: ${new Date(lastBill.date).toLocaleDateString()}\nStatus: ${lastBill.paymentStatus}\n\nTotal Amount: *₹${lastBill.totalAmount.toFixed(2)}*\n\nThank you!`;
    const url = `https://wa.me/${lastBill.customerPhone}?text=${encodeURIComponent(text)}`;
    window.open(url, '_blank');
  };

  return (
    <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-6 relative">

      {/* Top Bar: Transaction Type Toggle */}
      <div className="lg:col-span-3 bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="flex items-center space-x-2">
           <ArrowRightLeft className="text-slate-400" />
           <span className="font-semibold text-slate-600">Transaction Mode:</span>
        </div>
        <div className="flex bg-slate-100 p-1 rounded-lg">
          <button 
            onClick={() => setTransactionType('PURCHASE')}
            className={`px-6 py-2 rounded-md font-medium transition-all ${transactionType === 'PURCHASE' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Purchase (Buy)
          </button>
          <button 
            onClick={() => setTransactionType('SALE')}
            className={`px-6 py-2 rounded-md font-medium transition-all ${transactionType === 'SALE' ? 'bg-emerald-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Sale (Sell)
          </button>
        </div>
      </div>

      {/* Left Column: Inputs */}
      <div className="lg:col-span-2 space-y-6">

        {/* Customer Details */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 relative">
          <h3 className="text-lg font-bold text-slate-800 mb-4 border-b pb-2 flex justify-between items-center">
            <span>Customer Details</span>
            {selectedCustomerId && <span className="text-xs bg-green-100 text-green-700 px-2 py-1 rounded-full">Existing Customer</span>}
          </h3>

          {/* Customer Search */}
          <div className="relative mb-4">
             <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                  type="text"
                  value={customerSearch}
                  onChange={(e) => {
                    setCustomerSearch(e.target.value);
                    setShowCustomerSuggestions(true);
                  }}
                  onFocus={() => setShowCustomerSuggestions(true)}
                  placeholder="Search existing customer by Name or Phone..."
                  className="w-full pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50"
                />
             </div>
             {showCustomerSuggestions && customerSearch && (
                <div className="absolute z-10 w-full bg-white mt-1 border border-slate-200 rounded-lg shadow-lg max-h-48 overflow-y-auto">
                   {filteredCustomers.length > 0 ? (
                      filteredCustomers.map(c => (
                        <div 
                          key={c.id} 
                          onClick={() => selectCustomer(c)}
                          className="p-3 hover:bg-slate-50 cursor-pointer border-b border-slate-100 last:border-0"
                        >
                          <p className="font-bold text-slate-800">{c.name}</p>
                          <p className="text-xs text-slate-500">{c.phone}</p>
                        </div>
                      ))
                   ) : (
                     <div className="p-3 text-sm text-slate-500">No existing customers found. Fill details below to add.</div>
                   )}
                </div>
             )}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Customer Name *</label>
              <input 
                type="text" 
                value={customerName}
                onChange={e => setCustomerName(e.target.value)}
                className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="Enter Name"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Phone Number</label>
              <input 
                type="tel" 
                value={customerPhone}
                onChange={e => setCustomerPhone(e.target.value)}
                className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="Mobile No."
              />
            </div>
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-slate-600 mb-1">Address</label>
              <input 
                type="text" 
                value={customerAddress}
                onChange={e => setCustomerAddress(e.target.value)}
                className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="City / Area"
              />
            </div>
          </div>
        </div>

        {/* Item Entry - Dynamic Theme */}
        <div className={`p-6 rounded-xl shadow-lg text-white transition-colors duration-300 ${transactionType === 'PURCHASE' ? 'bg-slate-800' : 'bg-emerald-800'}`}>
          <div className="flex justify-between items-center mb-4">
            <h3 className={`text-lg font-bold ${transactionType === 'PURCHASE' ? 'text-blue-300' : 'text-emerald-300'}`}>
              {transactionType === 'PURCHASE' ? 'Add Purchase Items' : 'Add Sale Items'}
            </h3>
            <span className="text-xs bg-white/10 px-2 py-1 rounded">
               Stock: {transactionType === 'PURCHASE' ? 'IN' : 'OUT'}
            </span>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-12 gap-4 items-end">

            <div className={`md:col-span-${isOthers ? '3' : '4'}`}>
              <label className="block text-sm text-slate-300 mb-1">Select Item</label>
              <select 
                ref={itemSelectRef}
                value={selectedItemId}
                onChange={e => {
                  setSelectedItemId(e.target.value);
                  setCustomName('');
                  setManualRate('');
                }}
                className="w-full p-3 bg-white/10 border border-white/20 rounded-lg focus:ring-2 focus:ring-white/50 outline-none text-white [&>option]:text-slate-900"
              >
                {items.map(item => (
                  <option key={item.id} value={item.id}>
                    {item.name}
                  </option>
                ))}
              </select>
            </div>

            {isOthers && (
              <div className="md:col-span-3">
                 <label className="block text-sm text-slate-300 mb-1">Description</label>
                 <input 
                  type="text" 
                  autoFocus
                  value={customName}
                  onChange={e => setCustomName(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && weightInputRef.current?.focus()}
                  className={`w-full p-3 bg-white/10 border rounded-lg focus:ring-2 focus:ring-white/50 outline-none text-white placeholder-slate-400 ${formError === 'customName' ? 'border-red-400 ring-1 ring-red-400' : 'border-white/20'}`}
                  placeholder="Specify item details"
                />
              </div>
            )}

            <div className={`md:col-span-${isOthers ? '2' : '3'}`}>
               <label className="block text-sm text-slate-300 mb-1">Rate (₹/kg)</label>
               {transactionType === 'SALE' ? (
                 <input 
                   type="number" 
                   value={manualRate || activeRate}
                   onChange={e => setManualRate(e.target.value)}
                   onKeyDown={(e) => e.key === 'Enter' && weightInputRef.current?.focus()}
                   className="w-full p-3 bg-white text-slate-900 border border-transparent rounded-lg focus:ring-2 focus:ring-white/50 outline-none font-bold"
                 />
               ) : (
                 <div className="w-full p-3 bg-black/20 border border-white/10 rounded-lg text-slate-300 cursor-not-allowed font-mono">
                   {activeRate.toFixed(2)}
                 </div>
               )}
            </div>

            <div className={`md:col-span-${isOthers ? '2' : '3'}`}>
              <label className="block text-sm text-slate-300 mb-1">Weight (Kg)</label>
              <input 
                ref={weightInputRef}
                type="number" 
                value={weight}
                onChange={e => {
                   setWeight(e.target.value);
                   if (formError === 'weight') setFormError(null);
                }}
                className={`w-full p-3 bg-white text-slate-900 border rounded-lg focus:ring-2 focus:ring-white/50 outline-none font-bold text-lg ${formError === 'weight' ? 'border-red-500 ring-2 ring-red-500' : 'border-transparent'}`}
                placeholder="0.00"
                step="0.01"
                min="0"
                onKeyDown={(e) => e.key === 'Enter' && addItem()}
              />
            </div>

            <div className="md:col-span-2">
              <button 
                onClick={addItem}
                className={`w-full p-3 font-bold rounded-lg transition-transform active:scale-95 flex justify-center items-center text-white shadow-lg
                  ${transactionType === 'PURCHASE' ? 'bg-blue-600 hover:bg-blue-500' : 'bg-emerald-600 hover:bg-emerald-500'}
                `}
              >
                <Plus size={24} />
              </button>
            </div>
          </div>

          <div className="mt-4 pt-3 border-t border-white/10 flex justify-between items-center text-slate-200">
             <div className="flex flex-col">
                <span className="text-xs uppercase tracking-wider opacity-70">Calculated Amount</span>
                <span className="text-xl font-bold text-white">₹{currentAmount.toFixed(2)}</span>
             </div>
             <span className="flex items-center text-amber-300 text-sm">
                {transactionType === 'SALE' && <span className="mr-1 text-xs">(Rate Editable)</span>}
                <AlertCircle size={14} className="mr-1"/> 
                {transactionType === 'PURCHASE' ? 'Rates fixed by Admin' : 'Verify Market Rate'}
             </span>
          </div>
        </div>

        {/* Items Table */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-600 text-sm uppercase">
              <tr>
                <th className="p-4">Item</th>
                <th className="p-4 text-right">Rate</th>
                <th className="p-4 text-right">Weight</th>
                <th className="p-4 text-right">Amount</th>
                <th className="p-4 text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {billItems.map((item) => {
                 return (
                  <tr key={item.id} className="hover:bg-slate-50">
                    <td className="p-4 font-medium text-slate-800">{item.itemName}</td>
                    <td className="p-4 text-right text-slate-500">{item.rate.toFixed(2)}</td>
                    <td className="p-4 text-right font-mono">{item.weight.toFixed(2)}</td>
                    <td className="p-4 text-right font-bold text-slate-800">₹{item.amount.toFixed(2)}</td>
                    <td className="p-4 text-center">
                      <button 
                        onClick={() => removeItem(item.id)}
                        className="text-red-500 hover:bg-red-50 p-2 rounded-full transition"
                      >
                        <Trash2 size={18} />
                      </button>
                    </td>
                  </tr>
                 );
              })}
              {billItems.length === 0 && (
                <tr>
                  <td colSpan={5} className="p-8 text-center text-slate-400 italic">No items added yet.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Right Column: Summary & Actions */}
      <div className="space-y-6">
        <div className={`p-6 rounded-xl shadow-lg border-t-4 sticky top-4 bg-white ${transactionType === 'PURCHASE' ? 'border-blue-500' : 'border-emerald-500'}`}>
          <h3 className="text-lg font-bold text-slate-800 mb-6 flex justify-between">
            <span>Bill Summary</span>
            <span className={`text-xs px-2 py-1 rounded text-white ${transactionType === 'PURCHASE' ? 'bg-blue-500' : 'bg-emerald-500'}`}>
              {transactionType}
            </span>
          </h3>

          <div className="space-y-4 mb-6">
            <div className="flex justify-between text-slate-600">
              <span>Total Items</span>
              <span className="font-medium">{billItems.length}</span>
            </div>
            <div className="flex justify-between text-slate-600">
              <span>Total Weight</span>
              <span className="font-medium">
                {billItems.reduce((sum, i) => sum + i.weight, 0).toFixed(2)} Kg
              </span>
            </div>
             <div className="flex justify-between items-center py-2">
              <span className="text-slate-600">Payment Status</span>
              <select 
                value={paymentStatus}
                onChange={(e) => setPaymentStatus(e.target.value as PaymentStatus)}
                className={`p-1 rounded border text-sm font-bold ${paymentStatus === 'Paid' ? 'text-green-600 border-green-200 bg-green-50' : 'text-red-600 border-red-200 bg-red-50'}`}
              >
                <option value="Paid">PAID</option>
                <option value="Pending">PENDING</option>
              </select>
            </div>
            <div className="border-t border-dashed border-slate-300 pt-4 flex justify-between items-end">
              <span className="text-lg font-bold text-slate-800">Grand Total</span>
              <span className={`text-3xl font-bold ${transactionType === 'PURCHASE' ? 'text-blue-600' : 'text-emerald-600'}`}>
                ₹{totalAmount.toFixed(2)}
              </span>
            </div>
          </div>

          <div className="space-y-3">
            <button 
              onClick={handleGenerateBill}
              disabled={billItems.length === 0}
              className={`w-full py-4 rounded-lg font-bold text-lg flex items-center justify-center space-x-2 transition-all shadow-md
                ${billItems.length > 0 
                  ? (transactionType === 'PURCHASE' ? 'bg-blue-600 hover:bg-blue-700 text-white' : 'bg-emerald-600 hover:bg-emerald-700 text-white') 
                  : 'bg-slate-200 text-slate-400 cursor-not-allowed'}`}
            >
              <Save size={20} />
              <span>Generate Invoice</span>
            </button>

            <button 
              onClick={resetForm}
              className="w-full py-3 bg-white border border-slate-300 text-slate-600 rounded-lg hover:bg-slate-50 font-medium flex items-center justify-center space-x-2 transition"
            >
              <RotateCcw size={18} />
              <span>Reset POS</span>
            </button>
          </div>
        </div>
      </div>

      {/* Confirmation Modal */}
      {showConfirmationModal && (
        <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-xl shadow-2xl max-w-md w-full p-6 animate-in fade-in zoom-in duration-200">
                <div className="flex flex-col items-center text-center">
                    <div className="bg-amber-100 p-3 rounded-full mb-4">
                        <AlertCircle className="text-amber-600" size={32} />
                    </div>
                    <h3 className="text-xl font-bold text-slate-800 mb-2">Confirm Invoice Generation</h3>
                    <p className="text-slate-500 mb-6">
                        You are about to generate a <strong>{transactionType}</strong> invoice for <strong>₹{totalAmount.toFixed(2)}</strong>. 
                        This action cannot be undone.
                    </p>
                    <div className="flex w-full space-x-3">
                        <button 
                            onClick={() => setShowConfirmationModal(false)}
                            className="flex-1 py-2.5 border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 font-medium transition"
                        >
                            Cancel
                        </button>
                        <button 
                            onClick={finalizeBillGeneration}
                            className={`flex-1 py-2.5 text-white rounded-lg font-medium transition shadow-md ${transactionType === 'PURCHASE' ? 'bg-blue-600 hover:bg-blue-700' : 'bg-emerald-600 hover:bg-emerald-700'}`}
                        >
                            Confirm & Generate
                        </button>
                    </div>
                </div>
             </div>
        </div>
      )}

      {/* POS Success Modal */}
      {showSuccessModal && lastBill && (
        <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl max-w-lg w-full p-8 text-center relative animate-in fade-in zoom-in duration-200">
            <div className="mx-auto w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mb-4">
              <CheckCircle className="text-green-600" size={32} />
            </div>

            <h2 className="text-2xl font-bold text-slate-800 mb-2">Invoice Generated!</h2>
            <p className="text-slate-500 mb-8">
              {lastBill.transactionType} Invoice #{lastBill.billNo} saved.
            </p>

            <div className="grid grid-cols-2 gap-4 mb-4">
               <button 
                 onClick={() => generateBillPDF(lastBill, company, 'print')}
                 className="flex flex-col items-center justify-center p-4 bg-slate-50 hover:bg-slate-100 rounded-xl border border-slate-200 transition"
               >
                 <Printer size={28} className="text-slate-700 mb-2" />
                 <span className="font-medium text-slate-700">Print Receipt</span>
               </button>

               <button 
                 onClick={() => generateBillPDF(lastBill, company, 'download')}
                 className="flex flex-col items-center justify-center p-4 bg-slate-50 hover:bg-slate-100 rounded-xl border border-slate-200 transition"
               >
                 <FileDown size={28} className="text-slate-700 mb-2" />
                 <span className="font-medium text-slate-700">Download PDF</span>
               </button>
            </div>

            <button 
              onClick={shareViaWhatsApp}
              className="w-full flex items-center justify-center space-x-2 py-3 bg-green-500 hover:bg-green-600 text-white rounded-xl font-bold transition mb-6"
            >
              <Share2 size={20} />
              <span>Send via WhatsApp</span>
            </button>

            <button 
              onClick={() => setShowSuccessModal(false)}
              className="text-slate-500 hover:text-slate-700 font-medium underline"
            >
              Start New Order
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export interface ScrapItem {
  id: string;
  name: string;
  rate: number;
  lastUpdated: string;
  category: 'Metal' | 'Paper' | 'Plastic' | 'Electronics' | 'Others';
}

export interface StockItem {
  itemId: string;
  itemName: string;
  purchased: number;
  sold: number;
  available: number;
}

export interface StaffMember {
  id: string;
  name: string;
  role: 'Manager' | 'Worker' | 'Driver';
  status: 'Active' | 'Inactive';
  phone: string;
  password?: string;
}

export interface Customer {
  id: string;
  name: string;
  phone: string;
  address: string;
}

export interface LeaveRequest {
  id: string;
  staffName: string;
  fromDate: string;
  toDate: string;
  reason: string;
  status: 'Pending' | 'Approved' | 'Rejected';
}

export interface SalaryPayment {
  id: string;
  staffId: string;
  staffName: string;
  amount: number;
  paymentDate: string;
  type: 'Salary' | 'Advance' | 'Bonus';
  remarks?: string;
}

export interface CompanySettings {
  name: string;
  subtitle: string;
  address: string;
  phone: string;
  signatureUrl: string | null; // Base64 string for demo
}

export interface BillItem {
  id: string; // unique row id
  itemId: string; // ref to ScrapItem
  itemName: string; // Snapshot of item name
  customName?: string; // for 'Others'
  rate: number;
  weight: number;
  amount: number;
}

export type TransactionType = 'PURCHASE' | 'SALE';
export type PaymentStatus = 'Paid' | 'Pending';

export interface Bill {
  id: string;
  billNo: string;
  transactionType: TransactionType;
  customerId?: string;
  customerName: string;
  customerAddress: string;
  customerPhone: string;
  items: BillItem[];
  totalAmount: number;
  paymentStatus: PaymentStatus;
  date: string;
  staffName: string;
  isFinalized?: boolean;
}

export type ViewMode = 'ADMIN' | 'STAFF';

import React, { useState, useRef } from 'react';
import { useApp } from '../../context/AppContext';
import { BillItem, Bill, TransactionType, PaymentStatus, Customer } from '../../types';
import { generateBillPDF } from '../../utils/pdfGenerator';
import { Plus, Trash2, RotateCcw, Save, AlertCircle, Printer, Share2, CheckCircle, FileDown, Search, ArrowRightLeft } from 'lucide-react';

export const Billing = () => {
  const { items, company, addBill, currentUser, customers, addCustomer } = useApp();

  // Refs for Focus Management
  const itemSelectRef = useRef<HTMLSelectElement>(null);
  const weightInputRef = useRef<HTMLInputElement>(null);

  // Transaction Mode
  const [transactionType, setTransactionType] = useState<TransactionType>('PURCHASE');

  // Form State
  const [customerSearch, setCustomerSearch] = useState('');
  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);
  const [selectedCustomerId, setSelectedCustomerId] = useState<string | undefined>(undefined);

  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('Paid');

  const [billItems, setBillItems] = useState<BillItem[]>([]);

  // Item Entry State
  const [selectedItemId, setSelectedItemId] = useState(items[0]?.id || '');
  const [weight, setWeight] = useState('');
  const [customName, setCustomName] = useState('');
  const [manualRate, setManualRate] = useState(''); // For Sales
  const [formError, setFormError] = useState<string | null>(null);

  // Modal States
  const [lastBill, setLastBill] = useState<Bill | null>(null);
  const [showSuccessModal, setShowSuccessModal] = useState(false);
  const [showConfirmationModal, setShowConfirmationModal] = useState(false);

  // Derived state
  const selectedItemData = items.find(i => i.id === selectedItemId);
  const isOthers = selectedItemData?.name === 'Others' || selectedItemData?.category === 'Others';

  // Rate Logic: Purchase = Fixed Admin Rate, Sale = Manual/Negotiated Rate (Default to Admin Rate)
  const activeRate = transactionType === 'SALE' && manualRate 
    ? parseFloat(manualRate) 
    : (selectedItemData?.rate || 0);

  const currentAmount = (parseFloat(weight) || 0) * activeRate;
  const totalAmount = billItems.reduce((sum, item) => sum + item.amount, 0);

  // Filter customers for autocomplete
  const filteredCustomers = customers.filter(c => 
    c.name.toLowerCase().includes(customerSearch.toLowerCase()) || 
    c.phone.includes(customerSearch)
  );

  const selectCustomer = (customer: Customer) => {
    setCustomerName(customer.name);
    setCustomerPhone(customer.phone);
    setCustomerAddress(customer.address);
    setSelectedCustomerId(customer.id);
    setCustomerSearch('');
    setShowCustomerSuggestions(false);
  };

  const addItem = () => {
    // Validation
    if (!selectedItemId) return;
    if (!weight || parseFloat(weight) <= 0) {
      setFormError('weight');
      weightInputRef.current?.focus();
      return;
    }
    if (isOthers && !customName) {
      setFormError('customName');
      return;
    }

    setFormError(null);

    const resolvedName = isOthers && customName 
      ? `Others (${customName})` 
      : (selectedItemData?.name || 'Unknown');

    const newItem: BillItem = {
      id: Date.now().toString(),
      itemId: selectedItemId,
      itemName: resolvedName,
      customName: isOthers ? customName : undefined,
      rate: activeRate,
      weight: parseFloat(weight),
      amount: currentAmount
    };

    setBillItems([...billItems, newItem]);

    // Reset inputs
    setWeight('');
    setCustomName('');
    setManualRate('');

    // Focus back to Item Select for rapid entry
    if (window.innerWidth > 768) {
      itemSelectRef.current?.focus();
    }
  };

  const removeItem = (id: string) => {
    setBillItems(billItems.filter(item => item.id !== id));
  };

  const resetForm = () => {
    if (billItems.length === 0 || window.confirm("Reset the current form?")) {
      setCustomerName('');
      setCustomerPhone('');
      setCustomerAddress('');
      setSelectedCustomerId(undefined);
      setBillItems([]);
      setWeight('');
      setCustomName('');
      setManualRate('');
      setPaymentStatus('Paid');
      setFormError(null);
    }
  };

  const handleGenerateBill = () => {
    if (!customerName || billItems.length === 0) {
      alert("Please fill customer details and add at least one item.");
      return;
    }
    setShowConfirmationModal(true);
  };

  const finalizeBillGeneration = () => {
    // Auto-save new customer if phone doesn't exist
    if (customerPhone && !customers.some(c => c.phone === customerPhone)) {
      addCustomer({
        id: Date.now().toString(),
        name: customerName,
        phone: customerPhone,
        address: customerAddress
      });
    }

    // Create unique bill number (INV-YYYYMMDD-XXXX)
    const dateStr = new Date().toISOString().slice(0,10).replace(/-/g, '');
    const randomSuffix = Math.floor(1000 + Math.random() * 9000);
    const uniqueBillNo = `INV-${dateStr}-${randomSuffix}`;

    const bill: Bill = {
      id: Date.now().toString(),
      billNo: uniqueBillNo,
      transactionType,
      customerId: selectedCustomerId,
      customerName,
      customerPhone,
      customerAddress,
      items: billItems,
      totalAmount,
      paymentStatus,
      date: new Date().toISOString(),
      staffName: currentUser?.name || 'Staff',
      isFinalized: true, // Mark bill as immutable
    };

    addBill(bill);
    setLastBill(bill);

    // Clear form
    setCustomerName('');
    setCustomerPhone('');
    setCustomerAddress('');
    setSelectedCustomerId(undefined);
    setBillItems([]);
    setWeight('');
    setCustomName('');
    setManualRate('');
    setPaymentStatus('Paid');

    setShowConfirmationModal(false);
    setShowSuccessModal(true);
  };

  const shareViaWhatsApp = () => {
    if (!lastBill) return;
    const type = lastBill.transactionType === 'PURCHASE' ? 'Purchase Receipt' : 'Sales Invoice';
    const text = `*${company.name}*\n${type} #${lastBill.billNo}\nDate: ${new Date(lastBill.date).toLocaleDateString()}\nStatus: ${lastBill.paymentStatus}\n\nTotal Amount: *₹${lastBill.totalAmount.toFixed(2)}*\n\nThank you!`;
    const url = `https://wa.me/${lastBill.customerPhone}?text=${encodeURIComponent(text)}`;
    window.open(url, '_blank');
  };

  return (
    <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-6 relative">

      {/* Top Bar: Transaction Type Toggle */}
      <div className="lg:col-span-3 bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="flex items-center space-x-2">
           <ArrowRightLeft className="text-slate-400" />
           <span className="font-semibold text-slate-600">Transaction Mode:</span>
        </div>
        <div className="flex bg-slate-100 p-1 rounded-lg">
          <button 
            onClick={() => setTransactionType('PURCHASE')}
            className={`px-6 py-2 rounded-md font-medium transition-all ${transactionType === 'PURCHASE' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Purchase (Buy)
          </button>
          <button 
            onClick={() => setTransactionType('SALE')}
            className={`px-6 py-2 rounded-md font-medium transition-all ${transactionType === 'SALE' ? 'bg-emerald-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Sale (Sell)
          </button>
        </div>
      </div>

      {/* Left Column: Inputs */}
      <div className="lg:col-span-2 space-y-6">

        {/* Customer Details */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 relative">
          <h3 className="text-lg font-bold text-slate-800 mb-4 border-b pb-2 flex justify-between items-center">
            <span>Customer Details</span>
            {selectedCustomerId && <span className="text-xs bg-green-100 text-green-700 px-2 py-1 rounded-full">Existing Customer</span>}
          </h3>

          {/* Customer Search */}
          <div className="relative mb-4">
             <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                  type="text"
                  value={customerSearch}
                  onChange={(e) => {
                    setCustomerSearch(e.target.value);
                    setShowCustomerSuggestions(true);
                  }}
                  onFocus={() => setShowCustomerSuggestions(true)}
                  placeholder="Search existing customer by Name or Phone..."
                  className="w-full pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50"
                />
             </div>
             {showCustomerSuggestions && customerSearch && (
                <div className="absolute z-10 w-full bg-white mt-1 border border-slate-200 rounded-lg shadow-lg max-h-48 overflow-y-auto">
                   {filteredCustomers.length > 0 ? (
                      filteredCustomers.map(c => (
                        <div 
                          key={c.id} 
                          onClick={() => selectCustomer(c)}
                          className="p-3 hover:bg-slate-50 cursor-pointer border-b border-slate-100 last:border-0"
                        >
                          <p className="font-bold text-slate-800">{c.name}</p>
                          <p className="text-xs text-slate-500">{c.phone}</p>
                        </div>
                      ))
                   ) : (
                     <div className="p-3 text-sm text-slate-500">No existing customers found. Fill details below to add.</div>
                   )}
                </div>
             )}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Customer Name *</label>
              <input 
                type="text" 
                value={customerName}
                onChange={e => setCustomerName(e.target.value)}
                className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="Enter Name"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Phone Number</label>
              <input 
                type="tel" 
                value={customerPhone}
                onChange={e => setCustomerPhone(e.target.value)}
                className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="Mobile No."
              />
            </div>
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-slate-600 mb-1">Address</label>
              <input 
                type="text" 
                value={customerAddress}
                onChange={e => setCustomerAddress(e.target.value)}
                className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="City / Area"
              />
            </div>
          </div>
        </div>

        {/* Item Entry - Dynamic Theme */}
        <div className={`p-6 rounded-xl shadow-lg text-white transition-colors duration-300 ${transactionType === 'PURCHASE' ? 'bg-slate-800' : 'bg-emerald-800'}`}>
          <div className="flex justify-between items-center mb-4">
            <h3 className={`text-lg font-bold ${transactionType === 'PURCHASE' ? 'text-blue-300' : 'text-emerald-300'}`}>
              {transactionType === 'PURCHASE' ? 'Add Purchase Items' : 'Add Sale Items'}
            </h3>
            <span className="text-xs bg-white/10 px-2 py-1 rounded">
               Stock: {transactionType === 'PURCHASE' ? 'IN' : 'OUT'}
            </span>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-12 gap-4 items-end">

            <div className={`md:col-span-${isOthers ? '3' : '4'}`}>
              <label className="block text-sm text-slate-300 mb-1">Select Item</label>
              <select 
                ref={itemSelectRef}
                value={selectedItemId}
                onChange={e => {
                  setSelectedItemId(e.target.value);
                  setCustomName('');
                  setManualRate('');
                }}
                className="w-full p-3 bg-white/10 border border-white/20 rounded-lg focus:ring-2 focus:ring-white/50 outline-none text-white [&>option]:text-slate-900"
              >
                {items.map(item => (
                  <option key={item.id} value={item.id}>
                    {item.name}
                  </option>
                ))}
              </select>
            </div>

            {isOthers && (
              <div className="md:col-span-3">
                 <label className="block text-sm text-slate-300 mb-1">Description</label>
                 <input 
                  type="text" 
                  autoFocus
                  value={customName}
                  onChange={e => setCustomName(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && weightInputRef.current?.focus()}
                  className={`w-full p-3 bg-white/10 border rounded-lg focus:ring-2 focus:ring-white/50 outline-none text-white placeholder-slate-400 ${formError === 'customName' ? 'border-red-400 ring-1 ring-red-400' : 'border-white/20'}`}
                  placeholder="Specify item details"
                />
              </div>
            )}

            <div className={`md:col-span-${isOthers ? '2' : '3'}`}>
               <label className="block text-sm text-slate-300 mb-1">Rate (₹/kg)</label>
               {transactionType === 'SALE' ? (
                 <input 
                   type="number" 
                   value={manualRate || activeRate}
                   onChange={e => setManualRate(e.target.value)}
                   onKeyDown={(e) => e.key === 'Enter' && weightInputRef.current?.focus()}
                   className="w-full p-3 bg-white text-slate-900 border border-transparent rounded-lg focus:ring-2 focus:ring-white/50 outline-none font-bold"
                 />
               ) : (
                 <div className="w-full p-3 bg-black/20 border border-white/10 rounded-lg text-slate-300 cursor-not-allowed font-mono">
                   {activeRate.toFixed(2)}
                 </div>
               )}
            </div>

            <div className={`md:col-span-${isOthers ? '2' : '3'}`}>
              <label className="block text-sm text-slate-300 mb-1">Weight (Kg)</label>
              <input 
                ref={weightInputRef}
                type="number" 
                value={weight}
                onChange={e => {
                   setWeight(e.target.value);
                   if (formError === 'weight') setFormError(null);
                }}
                className={`w-full p-3 bg-white text-slate-900 border rounded-lg focus:ring-2 focus:ring-white/50 outline-none font-bold text-lg ${formError === 'weight' ? 'border-red-500 ring-2 ring-red-500' : 'border-transparent'}`}
                placeholder="0.00"
                step="0.01"
                min="0"
                onKeyDown={(e) => e.key === 'Enter' && addItem()}
              />
            </div>

            <div className="md:col-span-2">
              <button 
                onClick={addItem}
                className={`w-full p-3 font-bold rounded-lg transition-transform active:scale-95 flex justify-center items-center text-white shadow-lg
                  ${transactionType === 'PURCHASE' ? 'bg-blue-600 hover:bg-blue-500' : 'bg-emerald-600 hover:bg-emerald-500'}
                `}
              >
                <Plus size={24} />
              </button>
            </div>
          </div>

          <div className="mt-4 pt-3 border-t border-white/10 flex justify-between items-center text-slate-200">
             <div className="flex flex-col">
                <span className="text-xs uppercase tracking-wider opacity-70">Calculated Amount</span>
                <span className="text-xl font-bold text-white">₹{currentAmount.toFixed(2)}</span>
             </div>
             <span className="flex items-center text-amber-300 text-sm">
                {transactionType === 'SALE' && <span className="mr-1 text-xs">(Rate Editable)</span>}
                <AlertCircle size={14} className="mr-1"/> 
                {transactionType === 'PURCHASE' ? 'Rates fixed by Admin' : 'Verify Market Rate'}
             </span>
          </div>
        </div>

        {/* Items Table */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-600 text-sm uppercase">
              <tr>
                <th className="p-4">Item</th>
                <th className="p-4 text-right">Rate</th>
                <th className="p-4 text-right">Weight</th>
                <th className="p-4 text-right">Amount</th>
                <th className="p-4 text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {billItems.map((item) => {
                 return (
                  <tr key={item.id} className="hover:bg-slate-50">
                    <td className="p-4 font-medium text-slate-800">{item.itemName}</td>
                    <td className="p-4 text-right text-slate-500">{item.rate.toFixed(2)}</td>
                    <td className="p-4 text-right font-mono">{item.weight.toFixed(2)}</td>
                    <td className="p-4 text-right font-bold text-slate-800">₹{item.amount.toFixed(2)}</td>
                    <td className="p-4 text-center">
                      <button 
                        onClick={() => removeItem(item.id)}
                        className="text-red-500 hover:bg-red-50 p-2 rounded-full transition"
                      >
                        <Trash2 size={18} />
                      </button>
                    </td>
                  </tr>
                 );
              })}
              {billItems.length === 0 && (
                <tr>
                  <td colSpan={5} className="p-8 text-center text-slate-400 italic">No items added yet.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Confirmation Modal */}
      {showConfirmationModal && (
        <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-xl shadow-2xl max-w-md w-full p-6 animate-in fade-in zoom-in duration-200">
                <div className="flex flex-col items-center text-center">
                    <div className="bg-amber-100 p-3 rounded-full mb-4">
                        <AlertCircle className="text-amber-600" size={32} />
                    </div>
                    <h3 className="text-xl font-bold text-slate-800 mb-2">Confirm Invoice Generation</h3>
                    <p className="text-slate-500 mb-6">
                        You are about to generate a <strong>{transactionType}</strong> invoice for <strong>₹{totalAmount.toFixed(2)}</strong>. 
                        This action cannot be undone.
                    </p>
                    <div className="flex w-full space-x-3">
                        <button 
                            onClick={() => setShowConfirmationModal(false)}
                            className="flex-1 py-2.5 border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 font-medium transition"
                        >
                            Cancel
                        </button>
                        <button 
                            onClick={finalizeBillGeneration}
                            className={`flex-1 py-2.5 text-white rounded-lg font-medium transition shadow-md ${transactionType === 'PURCHASE' ? 'bg-blue-600 hover:bg-blue-700' : 'bg-emerald-600 hover:bg-emerald-700'}`}
                        >
                            Confirm & Generate
                        </button>
                    </div>
                </div>
             </div>
        </div>
      )}

      {/* POS Success Modal */}
      {showSuccessModal && lastBill && (
        <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl max-w-lg w-full p-8 text-center relative animate-in fade-in zoom-in duration-200">
            <div className="mx-auto w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mb-4">
              <CheckCircle className="text-green-600" size={32} />
            </div>

            <h2 className="text-2xl font-bold text-slate-800 mb-2">Invoice Generated!</h2>
            <p className="text-slate-500 mb-8">
              {lastBill.transactionType} Invoice #{lastBill.billNo} saved.
            </p>

            <div className="grid grid-cols-2 gap-4 mb-4">
               <button 
                 onClick={() => generateBillPDF(lastBill, company, 'print')}
                 className="flex flex-col items-center justify-center p-4 bg-slate-50 hover:bg-slate-100 rounded-xl border border-slate-200 transition"
               >
                 <Printer size={28} className="text-slate-700 mb-2" />
                 <span className="font-medium text-slate-700">Print Receipt</span>
               </button>

               <button 
                 onClick={() => generateBillPDF(lastBill, company, 'download')}
                 className="flex flex-col items-center justify-center p-4 bg-slate-50 hover:bg-slate-100 rounded-xl border border-slate-200 transition"
               >
                 <FileDown size={28} className="text-slate-700 mb-2" />
                 <span className="font-medium text-slate-700">Download PDF</span>
               </button>
            </div>

            <button 
              onClick={shareViaWhatsApp}
              className="w-full flex items-center justify-center space-x-2 py-3 bg-green-500 hover:bg-green-600 text-white rounded-xl font-bold transition mb-6"
            >
              <Share2 size={20} />
              <span>Send via WhatsApp</span>
            </button>

            <button 
              onClick={() => setShowSuccessModal(false)}
              className="text-slate-500 hover:text-slate-700 font-medium underline"
            >
              Start New Order
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

import jsPDF from 'jspdf';
import { Bill, CompanySettings } from '../types';

export const generateBillPDF = (bill: Bill, company: CompanySettings, action: 'download' | 'print' = 'download') => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a5',
  });

  const margin = 10;
  const pageWidth = 148;
  const contentWidth = pageWidth - (margin * 2);
  let y = margin;

  // --- HEADER ---
  // Company Name
  doc.setFontSize(16);
  doc.setFont('helvetica', 'bold');
  doc.text(company.name.toUpperCase(), pageWidth / 2, y, { align: 'center' });
  y += 6;

  // Subtitle
  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(80);
  doc.text(company.subtitle, pageWidth / 2, y, { align: 'center' });
  y += 5;

  // Address & Phone
  doc.setFontSize(9);
  doc.text(company.address, pageWidth / 2, y, { align: 'center' });
  y += 4;
  doc.text(`Ph: ${company.phone}`, pageWidth / 2, y, { align: 'center' });

  y += 6;
  doc.setDrawColor(200);
  doc.line(margin, y, pageWidth - margin, y);
  y += 6;

  // --- INVOICE TITLE & STATUS ---
  doc.setFontSize(12);
  doc.setFont('helvetica', 'bold');
  doc.setTextColor(0);

  const title = bill.transactionType === 'SALE' ? 'SALES INVOICE' : 'PURCHASE RECEIPT';
  doc.text(title, margin, y);

  // Status Badge
  const statusColor = bill.paymentStatus === 'Paid' ? [34, 197, 94] : [239, 68, 68]; // Green or Red
  doc.setFillColor(statusColor[0], statusColor[1], statusColor[2]);
  doc.roundedRect(pageWidth - margin - 25, y - 4, 25, 6, 1, 1, 'F');
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(8);
  doc.text(bill.paymentStatus.toUpperCase(), pageWidth - margin - 12.5, y, { align: 'center' });

  y += 8;

  // --- METADATA ---
  doc.setTextColor(0);
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(9);

  const colLeft = margin;
  const colRight = pageWidth / 2 + 5;

  // Left Column (Bill Details)
  doc.text(`Bill No:`, colLeft, y);
  doc.setFont('helvetica', 'bold');
  doc.text(bill.billNo, colLeft + 15, y);

  // Right Column (Date)
  doc.setFont('helvetica', 'normal');
  doc.text(`Date:`, colRight, y);
  doc.setFont('helvetica', 'bold');
  doc.text(new Date(bill.date).toLocaleDateString(), colRight + 12, y);

  y += 6;

  // Customer Details Box
  doc.setFillColor(248, 250, 252); // Very light grey
  doc.rect(margin, y, contentWidth, 22, 'F');
  doc.setDrawColor(226, 232, 240);
  doc.rect(margin, y, contentWidth, 22, 'S');

  let cy = y + 5;
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(9);
  doc.text('Customer Details:', margin + 4, cy);

  doc.setFont('helvetica', 'normal');
  cy += 5;
  doc.text(`Name: ${bill.customerName}`, margin + 4, cy);
  cy += 4;
  doc.text(`Phone: ${bill.customerPhone}`, margin + 4, cy);
  if (bill.customerAddress) {
    cy += 4;
    doc.text(`Addr: ${bill.customerAddress}`, margin + 4, cy);
  }

  y += 28;

  // --- ITEM TABLE ---
  const cols = {
    item: margin + 2,
    rate: 80,
    weight: 105,
    amount: pageWidth - margin - 2
  };

  // Table Header
  doc.setFillColor(51, 65, 85); // Slate 700
  doc.rect(margin, y, contentWidth, 8, 'F');
  doc.setTextColor(255);
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(9);

  doc.text('Item Name', cols.item, y + 5.5);
  doc.text('Rate', cols.rate, y + 5.5, { align: 'right' });
  doc.text('Weight', cols.weight, y + 5.5, { align: 'right' });
  doc.text('Amount', cols.amount, y + 5.5, { align: 'right' });

  y += 8;

  // Table Rows
  doc.setTextColor(0);
  doc.setFont('helvetica', 'normal');

  let totalWeight = 0;

  bill.items.forEach((item, index) => {
    // Determine alternating row color
    const isEven = index % 2 === 0;
    if (isEven) {
      doc.setFillColor(255, 255, 255);
    } else {
      doc.setFillColor(249, 250, 251);
    }

    // Use snapshot name if available, else fallback
    const itemName = item.itemName || item.customName || 'Unknown Item';

    // Calculate required height for row based on text wrapping
    const nameColWidth = 65; // Approx width available for name
    const splitText = doc.splitTextToSize(itemName, nameColWidth);
    const lineCount = splitText.length;
    const rowHeight = Math.max(8, lineCount * 4 + 3);

    // Draw background
    doc.rect(margin, y, contentWidth, rowHeight, 'F');

    // Draw wrapped Item Name
    doc.text(splitText, cols.item, y + 5);

    // Draw other columns aligned to top
    doc.text(item.rate.toFixed(2), cols.rate, y + 5, { align: 'right' });
    doc.text(item.weight.toFixed(2), cols.weight, y + 5, { align: 'right' });
    doc.text(item.amount.toFixed(2), cols.amount, y + 5, { align: 'right' });

    totalWeight += item.weight;
    y += rowHeight;

    // Page Break check
    if (y > 180) {
      doc.addPage();
      y = 20;
    }
  });

  // Table Border Bottom
  doc.setDrawColor(200);
  doc.line(margin, y, pageWidth - margin, y);
  y += 2;

  // --- TOTALS ---
  y += 4;
  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.text(`Total Items: ${bill.items.length}`, margin, y);
  doc.text(`Total Weight: ${totalWeight.toFixed(2)} Kg`, margin + 40, y);

  y += 8;
  doc.setFontSize(14);
  doc.setFont('helvetica', 'bold');

  // Highlight Total
  doc.setFillColor(240, 253, 244); // Light Green bg
  if (bill.transactionType === 'SALE') doc.setFillColor(255, 251, 235); // Light Yellow for Sale

  doc.roundedRect(pageWidth - margin - 60, y - 6, 60, 10, 1, 1, 'F');

  doc.text('TOTAL:', pageWidth - margin - 35, y, { align: 'right' });
  doc.text(`₹ ${bill.totalAmount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}`, pageWidth - margin - 5, y, { align: 'right' });

  // --- SIGNATURE ---
  y += 20; // Space for spacing
  if (y > 170) { doc.addPage(); y = 20; } // New page if low

  if (company.signatureUrl) {
    doc.addImage(company.signatureUrl, 'PNG', pageWidth - margin - 40, y, 35, 12);
    y += 12;
  } else {
    y += 10;
  }

  doc.setFontSize(8);
  doc.setFont('helvetica', 'normal');
  doc.text('Authorized Signature', pageWidth - margin - 22, y + 4, { align: 'center' });

  // Footer
  doc.setFontSize(7);
  doc.setTextColor(150);
  doc.text('Generated by Apna Kabadi Manager', pageWidth / 2, 200, { align: 'center' });

  if (action === 'print') {
    doc.autoPrint();
    const blob = doc.output('bloburl');
    window.open(blob, '_blank');
  } else {
    doc.save(`${bill.transactionType}_${bill.billNo}.pdf`);
  }
};

export const generateSummaryReportPDF = (bills: Bill[], company: CompanySettings, startDate: string, endDate: string) => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a4',
  });

  const margin = 15;
  const pageWidth = 210;
  const contentWidth = pageWidth - (margin * 2);
  let y = margin;

  // --- HEADER ---
  doc.setFontSize(18);
  doc.setFont('helvetica', 'bold');
  doc.text(company.name.toUpperCase(), margin, y);

  y += 8;
  doc.setFontSize(12);
  doc.setTextColor(100);
  doc.text("Business Summary Report", margin, y);
  doc.setTextColor(0);

  doc.setFontSize(10);
  doc.text(`Period: ${new Date(startDate).toLocaleDateString()} to ${new Date(endDate).toLocaleDateString()}`, pageWidth - margin, y - 8, { align: 'right' });
  doc.text(`Generated: ${new Date().toLocaleDateString()}`, pageWidth - margin, y, { align: 'right' });

  y += 10;
  doc.setDrawColor(200);
  doc.line(margin, y, pageWidth - margin, y);
  y += 10;

  // --- SUMMARY CARD ---
  const totalPurchases = bills.filter(b => b.transactionType === 'PURCHASE').reduce((sum, b) => sum + b.totalAmount, 0);
  const totalSales = bills.filter(b => b.transactionType === 'SALE').reduce((sum, b) => sum + b.totalAmount, 0);
  const totalBills = bills.length;
  const netFlow = totalSales - totalPurchases;

  // Draw Summary Boxes
  const boxWidth = contentWidth / 3 - 4;

  // Purchases
  doc.setFillColor(239, 246, 255); // Blue 50
  doc.roundedRect(margin, y, boxWidth, 25, 2, 2, 'F');
  doc.setFontSize(10);
  doc.setTextColor(59, 130, 246); // Blue 600
  doc.text("Total Purchases", margin + 5, y + 8);
  doc.setFontSize(14);
  doc.setFont('helvetica', 'bold');
  doc.text(`Rs. ${totalPurchases.toLocaleString('en-IN')}`, margin + 5, y + 18);

  // Sales
  doc.setFillColor(236, 253, 245); // Green 50
  doc.roundedRect(margin + boxWidth + 6, y, boxWidth, 25, 2, 2, 'F');
  doc.setFontSize(10);
  doc.setTextColor(16, 185, 129); // Emerald 600
  doc.setFont('helvetica', 'normal');
  doc.text("Total Sales", margin + boxWidth + 11, y + 8);
  doc.setFontSize(14);
  doc.setFont('helvetica', 'bold');
  doc.text(`Rs. ${totalSales.toLocaleString('en-IN')}`, margin + boxWidth + 11, y + 18);

  // Net
  doc.setFillColor(255, 251, 235); // Amber 50
  doc.roundedRect(margin + (boxWidth * 2) + 12, y, boxWidth, 25, 2, 2, 'F');
  doc.setFontSize(10);
  doc.setTextColor(180, 83, 9); // Amber 700
  doc.setFont('helvetica', 'normal');
  doc.text("Net Cash Flow", margin + (boxWidth * 2) + 17, y + 8);
  doc.setFontSize(14);
  doc.setFont('helvetica', 'bold');
  doc.text(`Rs. ${netFlow.toLocaleString('en-IN')}`, margin + (boxWidth * 2) + 17, y + 18);

  y += 35;

  // --- TRANSACTIONS TABLE ---
  doc.setFontSize(12);
  doc.setTextColor(0);
  doc.setFont('helvetica', 'bold');
  doc.text("Transaction History", margin, y);
  y += 6;

  // Headers
  const cols = {
    date: margin + 2,
    billNo: margin + 30,
    type: margin + 70,
    customer: margin + 100,
    amount: pageWidth - margin - 2
  };

  doc.setFillColor(51, 65, 85);
  doc.rect(margin, y, contentWidth, 10, 'F');
  doc.setTextColor(255);
  doc.setFontSize(9);
  doc.text("Date", cols.date, y + 6);
  doc.text("Bill No", cols.billNo, y + 6);
  doc.text("Type", cols.type, y + 6);
  doc.text("Customer", cols.customer, y + 6);
  doc.text("Amount", cols.amount, y + 6, { align: 'right' });

  y += 10;

  // Rows
  doc.setTextColor(0);
  doc.setFont('helvetica', 'normal');

  // Sort bills by date desc
  const sortedBills = [...bills].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  sortedBills.forEach((bill, index) => {
    if (y > 270) {
      doc.addPage();
      y = 20;
    }

    if (index % 2 !== 0) {
      doc.setFillColor(249, 250, 251);
      doc.rect(margin, y, contentWidth, 8, 'F');
    }

    doc.text(new Date(bill.date).toLocaleDateString(), cols.date, y + 5);
    doc.text(bill.billNo, cols.billNo, y + 5);

    // Type colored
    if (bill.transactionType === 'PURCHASE') {
      doc.setTextColor(37, 99, 235);
      doc.text("PURCHASE", cols.type, y + 5);
    } else {
      doc.setTextColor(5, 150, 105);
      doc.text("SALE", cols.type, y + 5);
    }

    doc.setTextColor(0);
    doc.text(bill.customerName.substring(0, 20), cols.customer, y + 5);
    doc.text(bill.totalAmount.toLocaleString('en-IN', { minimumFractionDigits: 2 }), cols.amount, y + 5, { align: 'right' });

    y += 8;
  });

  doc.save(`Report_${startDate}_${endDate}.pdf`);
};

import React, { useState, useMemo } from 'react';
import { useApp } from '../../context/AppContext';
import { generateSummaryReportPDF } from '../../utils/pdfGenerator';
import { Calendar, Filter, Download, TrendingUp, TrendingDown, DollarSign, FileText } from 'lucide-react';
import { TransactionType } from '../../types';

export const Reports = () => {
  const { bills, company } = useApp();

  // Date State: Default to current month
  const today = new Date();
  const firstDayOfMonth = new Date(today.getFullYear(), today.getMonth(), 1).toISOString().split('T')[0];
  const currentDay = today.toISOString().split('T')[0];

  const [startDate, setStartDate] = useState(firstDayOfMonth);
  const [endDate, setEndDate] = useState(currentDay);
  const [filterType, setFilterType] = useState<'ALL' | TransactionType>('ALL');

  // Quick Filters
  const setRange = (type: 'today' | 'week' | 'month' | 'year') => {
    const end = new Date();
    let start = new Date();

    if (type === 'today') {
        // start is today
    } else if (type === 'week') {
        start.setDate(end.getDate() - 7);
    } else if (type === 'month') {
        start = new Date(end.getFullYear(), end.getMonth(), 1);
    } else if (type === 'year') {
        start = new Date(end.getFullYear(), 0, 1);
    }

    setStartDate(start.toISOString().split('T')[0]);
    setEndDate(end.toISOString().split('T')[0]);
  };

  // Filter Data
  const filteredBills = useMemo(() => {
    return bills.filter(bill => {
      const billDate = bill.date.split('T')[0];
      const matchesDate = billDate >= startDate && billDate <= endDate;
      const matchesType = filterType === 'ALL' || bill.transactionType === filterType;
      return matchesDate && matchesType;
    });
  }, [bills, startDate, endDate, filterType]);

  // Aggregations
  const stats = useMemo(() => {
    const purchase = filteredBills.filter(b => b.transactionType === 'PURCHASE').reduce((s, b) => s + b.totalAmount, 0);
    const sale = filteredBills.filter(b => b.transactionType === 'SALE').reduce((s, b) => s + b.totalAmount, 0);
    const count = filteredBills.length;
    return { purchase, sale, count, net: sale - purchase };
  }, [filteredBills]);

  const handleDownload = () => {
    if (filteredBills.length === 0) {
        alert("No data available to report for this period.");
        return;
    }
    generateSummaryReportPDF(filteredBills, company, startDate, endDate);
  };

  return (
    <div className="max-w-6xl mx-auto space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Business Reports</h1>
          <p className="text-slate-500 mt-1">Generate sales and purchase summaries</p>
        </div>

        <button 
          onClick={handleDownload}
          className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-2.5 rounded-lg transition-colors font-bold shadow-sm"
        >
          <Download size={20} />
          <span>Download Report (PDF)</span>
        </button>
      </div>

      {/* Filter Control Bar */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200">
        <div className="flex flex-col lg:flex-row gap-4 items-end lg:items-center justify-between">

            {/* Presets */}
            <div className="flex gap-2 w-full lg:w-auto overflow-x-auto pb-2 lg:pb-0">
                <button onClick={() => setRange('today')} className="px-3 py-1.5 text-sm bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-md font-medium whitespace-nowrap">Today</button>
                <button onClick={() => setRange('week')} className="px-3 py-1.5 text-sm bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-md font-medium whitespace-nowrap">Last 7 Days</button>
                <button onClick={() => setRange('month')} className="px-3 py-1.5 text-sm bg-blue-50 text-blue-700 border border-blue-100 rounded-md font-medium whitespace-nowrap">This Month</button>
                <button onClick={() => setRange('year')} className="px-3 py-1.5 text-sm bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-md font-medium whitespace-nowrap">This Year</button>
            </div>

            {/* Custom Range */}
            <div className="flex gap-4 w-full lg:w-auto flex-wrap">
                <div className="flex-1 lg:flex-none">
                    <label className="block text-xs font-semibold text-slate-500 mb-1">From</label>
                    <div className="relative">
                        <Calendar size={16} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400"/>
                        <input 
                            type="date" 
                            value={startDate}
                            onChange={e => setStartDate(e.target.value)}
                            className="w-full lg:w-40 pl-9 pr-2 py-1.5 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                        />
                    </div>
                </div>
                <div className="flex-1 lg:flex-none">
                    <label className="block text-xs font-semibold text-slate-500 mb-1">To</label>
                    <div className="relative">
                        <Calendar size={16} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400"/>
                        <input 
                            type="date" 
                            value={endDate}
                            onChange={e => setEndDate(e.target.value)}
                            className="w-full lg:w-40 pl-9 pr-2 py-1.5 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                        />
                    </div>
                </div>
                <div className="flex-1 lg:flex-none">
                     <label className="block text-xs font-semibold text-slate-500 mb-1">Type</label>
                     <div className="relative">
                        <Filter size={16} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400"/>
                        <select 
                            value={filterType}
                            onChange={(e) => setFilterType(e.target.value as any)}
                            className="w-full lg:w-40 pl-9 pr-2 py-1.5 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none bg-white"
                        >
                            <option value="ALL">All Transactions</option>
                            <option value="PURCHASE">Purchases Only</option>
                            <option value="SALE">Sales Only</option>
                        </select>
                     </div>
                </div>
            </div>
        </div>
      </div>

      {/* Summary Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-200">
            <p className="text-sm font-medium text-slate-500 mb-2">Total Purchases</p>
            <div className="flex items-center space-x-3">
                <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
                    <TrendingDown size={24} />
                </div>
                <span className="text-2xl font-bold text-slate-800">₹{stats.purchase.toLocaleString()}</span>
            </div>
        </div>

        <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-200">
            <p className="text-sm font-medium text-slate-500 mb-2">Total Sales</p>
            <div className="flex items-center space-x-3">
                <div className="p-2 bg-emerald-50 text-emerald-600 rounded-lg">
                    <TrendingUp size={24} />
                </div>
                <span className="text-2xl font-bold text-slate-800">₹{stats.sale.toLocaleString()}</span>
            </div>
        </div>

        <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-200">
            <p className="text-sm font-medium text-slate-500 mb-2">Net Cash Flow</p>
            <div className="flex items-center space-x-3">
                <div className="p-2 bg-amber-50 text-amber-600 rounded-lg">
                    <DollarSign size={24} />
                </div>
                <span className={`text-2xl font-bold ${stats.net >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                    ₹{stats.net.toLocaleString()}
                </span>
            </div>
        </div>

        <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-200">
            <p className="text-sm font-medium text-slate-500 mb-2">Transaction Count</p>
            <div className="flex items-center space-x-3">
                <div className="p-2 bg-purple-50 text-purple-600 rounded-lg">
                    <FileText size={24} />
                </div>
                <span className="text-2xl font-bold text-slate-800">{stats.count}</span>
            </div>
        </div>
      </div>

      {/* Preview Table */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-200 bg-slate-50 flex justify-between items-center">
             <h3 className="font-bold text-slate-700">Preview: {filteredBills.length} Records found</h3>
        </div>
        <div className="max-h-96 overflow-y-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-white sticky top-0 shadow-sm">
              <tr className="text-slate-500 text-xs uppercase tracking-wider border-b border-slate-100">
                <th className="p-4">Date</th>
                <th className="p-4">Bill No</th>
                <th className="p-4">Type</th>
                <th className="p-4">Customer</th>
                <th className="p-4 text-right">Amount</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 text-sm">
              {filteredBills.length > 0 ? filteredBills.map((bill) => (
                <tr key={bill.id} className="hover:bg-slate-50">
                  <td className="p-4 text-slate-600">{new Date(bill.date).toLocaleDateString()}</td>
                  <td className="p-4 font-mono text-slate-800">{bill.billNo}</td>
                  <td className="p-4">
                    {bill.transactionType === 'PURCHASE' ? (
                       <span className="text-blue-600 font-bold text-xs bg-blue-50 px-2 py-1 rounded">PURCHASE</span>
                    ) : (
                       <span className="text-emerald-600 font-bold text-xs bg-emerald-50 px-2 py-1 rounded">SALE</span>
                    )}
                  </td>
                  <td className="p-4 text-slate-700">{bill.customerName}</td>
                  <td className="p-4 text-right font-bold text-slate-800">₹{bill.totalAmount.toLocaleString()}</td>
                </tr>
              )) : (
                <tr>
                    <td colSpan={5} className="p-10 text-center text-slate-400">
                        No transactions found for the selected range.
                    </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AppProvider, useApp } from './context/AppContext';
import { Layout } from './components/Layout';
import { Login } from './pages/Login';
import { Dashboard } from './pages/admin/Dashboard';
import { RateChart } from './pages/admin/RateChart';
import { Stock } from './pages/admin/Stock';
import { Staff } from './pages/admin/Staff';
import { Salary } from './pages/admin/Salary';
import { Customers } from './pages/admin/Customers';
import { CompanySettingsPage } from './pages/admin/CompanySettings';
import { Reports } from './pages/admin/Reports';
import { Billing } from './pages/staff/Billing';
import { BillHistory } from './pages/staff/BillHistory';

// Simple Route Guard
const RoleGuard = ({ children, allowedMode }: { children?: React.ReactNode, allowedMode: 'ADMIN' | 'STAFF' }) => {
  const { currentUser } = useApp();

  if (!currentUser) {
    return <Navigate to="/login" replace />;
  }

  // Derive mode from role
  const currentMode = currentUser.role === 'Manager' ? 'ADMIN' : 'STAFF';

  if (currentMode !== allowedMode) {
    return <Navigate to={allowedMode === 'ADMIN' ? '/staff/billing' : '/admin/dashboard'} replace />;
  }
  return <>{children}</>;
};

const AppRoutes = () => {
  return (
    <Routes>
      <Route path="/login" element={<Login />} />
      <Route path="/" element={<Navigate to="/login" replace />} />

      {/* Admin Routes */}
      <Route path="/admin/*" element={
        <RoleGuard allowedMode="ADMIN">
          <Layout>
             <Routes>
              <Route path="dashboard" element={<Dashboard />} />
