  itemId: string;
  itemName: string;
  purchased: number;
  sold: number;
  available: number;
}

export interface StaffMember {
  id: string;
  name: string;
  role: 'Manager' | 'Worker' | 'Driver';
  status: 'Active' | 'Inactive';
