import React, { useState, useRef, useEffect } from 'react';
import { useApp } from '../../context/AppContext';
import { BillItem, Bill, TransactionType, PaymentStatus, Customer } from '../../types';
import { generateBillPDF } from '../../utils/pdfGenerator';
import { Plus, Trash2, RotateCcw, Save, AlertCircle, Printer, Share2, CheckCircle, FileDown, Search, ArrowRightLeft, User, MapPin, Phone } from 'lucide-react';

export const Billing = () => {
  const { items, company, addBill, currentUser, customers, addCustomer } = useApp();

  // Refs for Focus Management
  const itemSelectRef = useRef<HTMLSelectElement>(null);
  const weightInputRef = useRef<HTMLInputElement>(null);
  const customNameRef = useRef<HTMLInputElement>(null);

  // Transaction Mode
  const [transactionType, setTransactionType] = useState<TransactionType>('PURCHASE');

  // Form State
  const [customerSearch, setCustomerSearch] = useState('');
  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);
  const [selectedCustomerId, setSelectedCustomerId] = useState<string | undefined>(undefined);

  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('Paid');

  const [billItems, setBillItems] = useState<BillItem[]>([]);

  // Item Entry State
  // Default to first item if available
  const [selectedItemId, setSelectedItemId] = useState(items.length > 0 ? items[0].id : '');
  const [weight, setWeight] = useState('');
  const [customName, setCustomName] = useState('');
  const [manualRate, setManualRate] = useState(''); // For Sales
  const [formError, setFormError] = useState<string | null>(null);

  // Modal States
  const [lastBill, setLastBill] = useState<Bill | null>(null);
  const [showSuccessModal, setShowSuccessModal] = useState(false);
  const [showConfirmationModal, setShowConfirmationModal] = useState(false);

  // Effect to ensure selectedItemId is valid on load
  useEffect(() => {
    if (!selectedItemId && items.length > 0) {
        setSelectedItemId(items[0].id);
    }
  }, [items, selectedItemId]);

  // Derived state
  const selectedItemData = items.find(i => i.id === selectedItemId);
  const isOthers = selectedItemData?.name === 'Others' || selectedItemData?.category === 'Others';

  // Rate Logic: Purchase = Fixed Admin Rate, Sale = Manual/Negotiated Rate (Default to Admin Rate)
  const activeRate = transactionType === 'SALE' && manualRate !== ''
    ? parseFloat(manualRate) 
    : (selectedItemData?.rate || 0);

  const currentAmount = (parseFloat(weight) || 0) * activeRate;
  const totalAmount = billItems.reduce((sum, item) => sum + item.amount, 0);
  const totalWeight = billItems.reduce((sum, item) => sum + item.weight, 0);

  // Filter customers for autocomplete
  const filteredCustomers = customers.filter(c => 
    c.name.toLowerCase().includes(customerSearch.toLowerCase()) || 
    c.phone.includes(customerSearch)
  );

  const selectCustomer = (customer: Customer) => {
    setCustomerName(customer.name);
    setCustomerPhone(customer.phone);
    setCustomerAddress(customer.address);
    setSelectedCustomerId(customer.id);
    setCustomerSearch('');
    setShowCustomerSuggestions(false);
  };

  const addItem = () => {
    // Validation
    if (!selectedItemId) return;
    if (!weight || parseFloat(weight) <= 0) {
      setFormError('weight');
      weightInputRef.current?.focus();
      return;
    }
    if (isOthers && !customName) {
      setFormError('customName');
      customNameRef.current?.focus();
      return;
    }

    setFormError(null);

    const resolvedName = isOthers && customName 
      ? `Others (${customName})` 
      : (selectedItemData?.name || 'Unknown');

    const newItem: BillItem = {
      id: Date.now().toString(),
      itemId: selectedItemId,
      itemName: resolvedName,
      customName: isOthers ? customName : undefined,
      rate: activeRate,
      weight: parseFloat(weight),
      amount: currentAmount
    };

    setBillItems([...billItems, newItem]);

    // Reset inputs
    setWeight('');
    setCustomName('');
    setManualRate('');

    // Focus logic for rapid entry
    if (window.innerWidth > 768) {
        // Desktop: Go back to item select
        itemSelectRef.current?.focus();
    } else {
        // Mobile: Blur to close keyboard
        (document.activeElement as HTMLElement)?.blur();
    }
  };

  const removeItem = (id: string) => {
    setBillItems(billItems.filter(item => item.id !== id));
  };

  const handleGenerateBill = () => {
    if (!customerName || billItems.length === 0) {
      alert("Please fill customer details and add at least one item.");
      return;
    }
    setShowConfirmationModal(true);
  };

  const finalizeBillGeneration = () => {
    // Auto-save new customer if phone doesn't exist
    if (customerPhone && !customers.some(c => c.phone === customerPhone)) {
      addCustomer({
        id: Date.now().toString(),
        name: customerName,
        phone: customerPhone,
        address: customerAddress
      });
    }

    // Create unique bill number (INV-YYYYMMDD-XXXX)
    const dateStr = new Date().toISOString().slice(0,10).replace(/-/g, '');
    const randomSuffix = Math.floor(1000 + Math.random() * 9000);
    const uniqueBillNo = `INV-${dateStr}-${randomSuffix}`;

    const bill: Bill = {
      id: Date.now().toString(),
      billNo: uniqueBillNo,
      transactionType,
      customerId: selectedCustomerId,
      customerName,
      customerPhone,
      customerAddress,
      items: billItems,
      totalAmount,
      paymentStatus,
      date: new Date().toISOString(),
      staffName: currentUser?.name || 'Staff',
      isFinalized: true, // Mark bill as immutable
    };

    addBill(bill);
    setLastBill(bill);

    // Clear form
    setCustomerName('');
    setCustomerPhone('');
    setCustomerAddress('');
    setSelectedCustomerId(undefined);
    setBillItems([]);
    setWeight('');
    setCustomName('');
    setManualRate('');
    setPaymentStatus('Paid');

    setShowConfirmationModal(false);
    setShowSuccessModal(true);
  };

  const shareViaWhatsApp = () => {
    if (!lastBill) return;
    const type = lastBill.transactionType === 'PURCHASE' ? 'Purchase Receipt' : 'Sales Invoice';
    const text = `*${company.name}*\n${type} #${lastBill.billNo}\nDate: ${new Date(lastBill.date).toLocaleDateString()}\nStatus: ${lastBill.paymentStatus}\n\nTotal Amount: *₹${lastBill.totalAmount.toFixed(2)}*\n\nThank you!`;
    const url = `https://wa.me/${lastBill.customerPhone}?text=${encodeURIComponent(text)}`;
    window.open(url, '_blank');
  };

  return (
    <div className="max-w-7xl mx-auto space-y-4 lg:space-y-6 pb-20 lg:pb-0">

      {/* Top Bar: Transaction Type Toggle */}
      <div className="bg-white p-3 lg:p-4 rounded-xl shadow-sm border border-slate-200">
        <div className="flex flex-col sm:flex-row justify-between items-center gap-3">
            <div className="flex items-center space-x-2 text-slate-600">
                <ArrowRightLeft size={20} />
                <span className="font-bold">Mode</span>
            </div>
            <div className="flex w-full sm:w-auto bg-slate-100 p-1 rounded-lg">
                <button 
                    onClick={() => setTransactionType('PURCHASE')}
                    className={`flex-1 sm:flex-none px-4 py-2 rounded-md font-bold text-sm transition-all shadow-sm ${transactionType === 'PURCHASE' ? 'bg-blue-600 text-white' : 'text-slate-500 hover:text-slate-700 bg-transparent shadow-none'}`}
                >
                    Purchase (Buy)
                </button>
                <button 
                    onClick={() => setTransactionType('SALE')}
                    className={`flex-1 sm:flex-none px-4 py-2 rounded-md font-bold text-sm transition-all shadow-sm ${transactionType === 'SALE' ? 'bg-emerald-600 text-white' : 'text-slate-500 hover:text-slate-700 bg-transparent shadow-none'}`}
                >
                    Sale (Sell)
                </button>
            </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 lg:gap-6 items-start">

        {/* Left Column: Customer & Item Entry */}
        <div className="lg:col-span-2 space-y-4 lg:space-y-6">

            {/* Customer Details Card */}
            <div className="bg-white p-4 lg:p-6 rounded-xl shadow-sm border border-slate-200">
                <div className="flex justify-between items-center mb-4 border-b border-slate-100 pb-3">
                    <h3 className="font-bold text-slate-800 flex items-center gap-2">
                        <User size={18} className="text-slate-400"/>
                        Customer Details
                    </h3>
                    {selectedCustomerId && <span className="text-[10px] uppercase font-bold bg-green-100 text-green-700 px-2 py-1 rounded-full">Existing</span>}
                </div>

                {/* Customer Search Dropdown */}
                <div className="relative mb-4">
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                        <input 
                            type="text"
                            value={customerSearch}
                            onChange={(e) => {
                                setCustomerSearch(e.target.value);
                                setShowCustomerSuggestions(true);
                            }}
                            onFocus={() => setShowCustomerSuggestions(true)}
                            onBlur={() => setTimeout(() => setShowCustomerSuggestions(false), 200)}
                            placeholder="Search by Name or Phone..."
                            className="w-full pl-10 pr-4 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 text-sm"
                        />
                    </div>
                    {showCustomerSuggestions && customerSearch && (
                        <div className="absolute z-30 w-full bg-white mt-1 border border-slate-200 rounded-lg shadow-xl max-h-48 overflow-y-auto">
                        {filteredCustomers.length > 0 ? (
                            filteredCustomers.map(c => (
                                <div 
                                key={c.id} 
                                onClick={() => selectCustomer(c)}
                                className="p-3 hover:bg-slate-50 cursor-pointer border-b border-slate-100 last:border-0"
                                >
                                <p className="font-bold text-slate-800 text-sm">{c.name}</p>
                                <p className="text-xs text-slate-500">{c.phone}</p>
                                </div>
                            ))
                        ) : (
                            <div className="p-3 text-sm text-slate-500">No existing customers found.</div>
                        )}
                        </div>
                    )}
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    <div className="relative">
                        <User className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                        <input 
                            type="text" 
                            value={customerName}
                            onChange={e => setCustomerName(e.target.value)}
                            className="w-full pl-9 pr-3 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm"
                            placeholder="Name *"
                        />
                    </div>
                    <div className="relative">
                        <Phone className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                        <input 
                            type="tel" 
                            value={customerPhone}
                            onChange={e => setCustomerPhone(e.target.value)}
                            className="w-full pl-9 pr-3 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm"
                            placeholder="Phone"
                        />
                    </div>
                    <div className="md:col-span-2 relative">
                        <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                        <input 
                            type="text" 
                            value={customerAddress}
                            onChange={e => setCustomerAddress(e.target.value)}
                            className="w-full pl-9 pr-3 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm"
                            placeholder="Address / Area"
                        />
                    </div>
                </div>
            </div>

            {/* Item Entry Card */}
            <div className={`p-4 lg:p-6 rounded-xl shadow-lg text-white transition-colors duration-300 ${transactionType === 'PURCHASE' ? 'bg-slate-800' : 'bg-emerald-800'}`}>
                <div className="flex justify-between items-center mb-4">
                    <h3 className={`font-bold ${transactionType === 'PURCHASE' ? 'text-blue-300' : 'text-emerald-300'}`}>
                    {transactionType === 'PURCHASE' ? 'Purchase Item' : 'Sell Item'}
                    </h3>
                    <span className="text-[10px] uppercase font-bold bg-white/10 px-2 py-1 rounded">
                        Stock: {transactionType === 'PURCHASE' ? 'IN' : 'OUT'}
                    </span>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-12 gap-4 items-end">

                    {/* Item Select */}
                    <div className={`md:col-span-${isOthers ? '3' : '4'}`}>
                        <label className="block text-xs text-slate-300 mb-1 font-medium">Item Name</label>
                        <select 
                            ref={itemSelectRef}
                            value={selectedItemId}
                            onChange={e => {
                                setSelectedItemId(e.target.value);
                                setCustomName('');
                                setManualRate('');
                            }}
                            className="w-full p-3 bg-white/10 border border-white/20 rounded-lg focus:ring-2 focus:ring-white/50 outline-none text-white [&>option]:text-slate-900 text-sm"
                        >
                            {items.map(item => (
                            <option key={item.id} value={item.id}>
                                {item.name}
                            </option>
                            ))}
                        </select>
                    </div>

                    {/* Custom Description (Conditional) */}
                    {isOthers && (
                        <div className="md:col-span-3">
                            <label className="block text-xs text-slate-300 mb-1 font-medium">Description</label>
                            <input 
                                ref={customNameRef}
                                type="text" 
                                value={customName}
                                onChange={e => setCustomName(e.target.value)}
                                onKeyDown={(e) => e.key === 'Enter' && weightInputRef.current?.focus()}
                                className={`w-full p-3 bg-white/10 border rounded-lg focus:ring-2 focus:ring-white/50 outline-none text-white placeholder-slate-400 text-sm ${formError === 'customName' ? 'border-red-400 ring-1 ring-red-400' : 'border-white/20'}`}
                                placeholder="Details..."
                            />
                        </div>
                    )}

                    {/* Rate Input */}
                    <div className={`md:col-span-${isOthers ? '2' : '3'}`}>
                        <label className="block text-xs text-slate-300 mb-1 font-medium">Rate (₹/kg)</label>
                        {transactionType === 'SALE' ? (
                            <input 
                            type="number" 
                            value={manualRate !== '' ? manualRate : (activeRate > 0 ? activeRate : '')}
                            onChange={e => setManualRate(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && weightInputRef.current?.focus()}
                            placeholder={activeRate.toString()}
                            className="w-full p-3 bg-white text-slate-900 border border-transparent rounded-lg focus:ring-2 focus:ring-white/50 outline-none font-bold text-center"
                            />
                        ) : (
                            <div className="w-full p-3 bg-black/20 border border-white/10 rounded-lg text-slate-300 cursor-not-allowed font-mono text-center">
                            {activeRate.toFixed(2)}
                            </div>
                        )}
                    </div>

                    {/* Weight Input */}
                    <div className={`md:col-span-${isOthers ? '2' : '3'}`}>
                        <label className="block text-xs text-slate-300 mb-1 font-medium">Weight (Kg)</label>
                        <input 
                            ref={weightInputRef}
                            type="number" 
                            value={weight}
                            onChange={e => {
                                setWeight(e.target.value);
                                if (formError === 'weight') setFormError(null);
                            }}
                            className={`w-full p-3 bg-white text-slate-900 border rounded-lg focus:ring-2 focus:ring-white/50 outline-none font-bold text-lg text-center ${formError === 'weight' ? 'border-red-500 ring-2 ring-red-500' : 'border-transparent'}`}
                            placeholder="0.00"
                            step="0.01"
                            min="0"
                            inputMode="decimal"
                            onKeyDown={(e) => e.key === 'Enter' && addItem()}
                        />
                    </div>

                    {/* Add Button */}
                    <div className="md:col-span-2">
                        <button 
                            onClick={addItem}
                            className={`w-full p-3 font-bold rounded-lg transition-transform active:scale-95 flex justify-center items-center text-white shadow-lg
                            ${transactionType === 'PURCHASE' ? 'bg-blue-600 hover:bg-blue-500' : 'bg-emerald-600 hover:bg-emerald-500'}
                            `}
                        >
                            <Plus size={24} />
                            <span className="md:hidden ml-2">Add Item</span>
                        </button>
                    </div>
                </div>

                {/* Footer of Card */}
                <div className="mt-4 pt-3 border-t border-white/10 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-2 text-slate-200">
                    <div className="flex flex-col">
                        <span className="text-[10px] uppercase tracking-wider opacity-70">Current Line Item</span>
                        <span className="text-xl font-bold text-white">₹{currentAmount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                    </div>
                    <span className="flex items-center text-amber-300 text-xs bg-amber-900/30 px-2 py-1 rounded">
                        <AlertCircle size={12} className="mr-1"/> 
                        {transactionType === 'PURCHASE' ? 'Admin Fixed Rate' : 'Market Rate Check'}
                    </span>
                </div>
            </div>
        </div>

        {/* Right Column: Invoice Summary */}
        <div className="lg:col-span-1 space-y-4">
             <div className="bg-white rounded-xl shadow-sm border border-slate-200 flex flex-col h-full overflow-hidden">
                <div className="p-4 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
                    <h3 className="font-bold text-slate-700">Invoice Items</h3>
                    <span className="bg-slate-200 text-slate-600 text-xs px-2 py-1 rounded-full font-bold">{billItems.length}</span>
                </div>

                <div className="flex-1 overflow-y-auto min-h-[200px] max-h-[400px]">
                    {billItems.length > 0 ? (
                        <div className="divide-y divide-slate-100">
                            {billItems.map((item) => (
                                <div key={item.id} className="p-3 hover:bg-slate-50 flex justify-between items-center group">
                                    <div className="flex-1">
                                        <div className="font-bold text-slate-800 text-sm">{item.itemName}</div>
                                        <div className="text-xs text-slate-500">
                                            {item.weight} kg × ₹{item.rate}
                                        </div>
                                    </div>
                                    <div className="text-right mx-3">
                                        <div className="font-bold text-slate-800 text-sm">₹{item.amount.toFixed(2)}</div>
                                    </div>
                                    <button 
                                        onClick={() => removeItem(item.id)}
                                        className="text-slate-300 hover:text-red-500 transition p-1"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 space-y-2">
                             <div className="w-12 h-12 rounded-full bg-slate-100 flex items-center justify-center">
                                <Plus size={24} className="opacity-50"/>
                             </div>
                             <p className="text-sm">Add items to bill</p>
                        </div>
                    )}
                </div>

                <div className="p-4 bg-slate-50 border-t border-slate-200">
                    <div className="flex justify-between items-center mb-2">
                        <span className="text-slate-600 font-medium">Total Weight</span>
                        <span className="text-lg font-bold text-slate-700">{totalWeight.toFixed(2)} kg</span>
                    </div>
                    <div className="flex justify-between items-center mb-4">
                        <span className="text-slate-600 font-medium">Total Amount</span>
                        <span className="text-2xl font-bold text-slate-900">₹{totalAmount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                    </div>
                    <button 
                        onClick={handleGenerateBill}
                        disabled={billItems.length === 0}
                        className={`w-full py-3 rounded-lg font-bold text-white shadow-md transition-all active:scale-95 flex items-center justify-center space-x-2
                            ${billItems.length === 0 ? 'bg-slate-300 cursor-not-allowed' : 
                              transactionType === 'PURCHASE' ? 'bg-blue-600 hover:bg-blue-700' : 'bg-emerald-600 hover:bg-emerald-700'}
                        `}
                    >
                        <Save size={20} />
                        <span>Generate Invoice</span>
                    </button>
                </div>
             </div>
        </div>

      </div>

      {/* Confirmation Modal */}
      {showConfirmationModal && (
        <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-xl shadow-2xl max-w-sm w-full p-6 animate-in fade-in zoom-in duration-200">
                <div className="flex flex-col items-center text-center">
                    <div className="bg-amber-100 p-3 rounded-full mb-4">
                        <AlertCircle className="text-amber-600" size={32} />
                    </div>
                    <h3 className="text-xl font-bold text-slate-800 mb-2">Confirm Invoice</h3>
                    <p className="text-slate-500 mb-6 text-sm">
                        Generate <strong>{transactionType}</strong> invoice for <strong>₹{totalAmount.toFixed(2)}</strong>?
                    </p>
                    <div className="flex w-full space-x-3">
                        <button 
                            onClick={() => setShowConfirmationModal(false)}
                            className="flex-1 py-2.5 border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 font-medium transition text-sm"
                        >
                            Cancel
                        </button>
                        <button 
                            onClick={finalizeBillGeneration}
                            className={`flex-1 py-2.5 text-white rounded-lg font-medium transition shadow-md text-sm ${transactionType === 'PURCHASE' ? 'bg-blue-600 hover:bg-blue-700' : 'bg-emerald-600 hover:bg-emerald-700'}`}
                        >
                            Confirm
                        </button>
                    </div>
                </div>
             </div>
        </div>
      )}

      {/* POS Success Modal */}
      {showSuccessModal && lastBill && (
        <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl max-w-md w-full p-6 text-center relative animate-in fade-in zoom-in duration-200">
            <div className="mx-auto w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mb-4">
              <CheckCircle className="text-green-600" size={32} />
            </div>

            <h2 className="text-xl font-bold text-slate-800 mb-1">Invoice Saved!</h2>
            <p className="text-slate-500 mb-6 text-sm">
              {lastBill.transactionType} #{lastBill.billNo}
            </p>

            <div className="grid grid-cols-2 gap-3 mb-4">
               <button 
                 onClick={() => generateBillPDF(lastBill, company, 'print')}
                 className="flex flex-col items-center justify-center p-3 bg-slate-50 hover:bg-slate-100 rounded-xl border border-slate-200 transition"
               >
                 <Printer size={24} className="text-slate-700 mb-2" />
                 <span className="font-medium text-slate-700 text-xs">Print</span>
               </button>

               <button 
                 onClick={() => generateBillPDF(lastBill, company, 'download')}
                 className="flex flex-col items-center justify-center p-3 bg-slate-50 hover:bg-slate-100 rounded-xl border border-slate-200 transition"
               >
                 <FileDown size={24} className="text-slate-700 mb-2" />
                 <span className="font-medium text-slate-700 text-xs">Download</span>
               </button>
            </div>

            <button 
              onClick={shareViaWhatsApp}
              className="w-full flex items-center justify-center space-x-2 py-3 bg-green-500 hover:bg-green-600 text-white rounded-xl font-bold transition mb-4 shadow-sm"
            >
              <Share2 size={18} />
              <span>WhatsApp</span>
            </button>

            <button 
              onClick={() => setShowSuccessModal(false)}
              className="text-slate-500 hover:text-slate-700 font-medium text-sm underline p-2"
            >
              Close & New Order
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../../context/AppContext';
import { Lead } from '../../types';
import { Search, Plus, MapPin, Phone, User, Filter, Edit, CheckCircle2, Clock, XCircle, AlertCircle } from 'lucide-react';

export const Leads = () => {
  const { leads, addLead, updateLead, staff } = useApp();
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('All');
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  // Filter staff to get only active ones for assignment
  const activeStaff = staff.filter(s => s.status === 'Active');

  const [formData, setFormData] = useState<Partial<Lead>>({
    name: '',
    phone: '',
    address: '',
    status: 'New',
    assignedTo: '',
    notes: ''
  });

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'New': return 'bg-blue-100 text-blue-700';
      case 'In Progress': return 'bg-yellow-100 text-yellow-700';
      case 'Converted': return 'bg-green-100 text-green-700';
      case 'Lost': return 'bg-red-100 text-red-700';
      default: return 'bg-slate-100 text-slate-700';
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'New': return <AlertCircle size={14} className="mr-1" />;
      case 'In Progress': return <Clock size={14} className="mr-1" />;
      case 'Converted': return <CheckCircle2 size={14} className="mr-1" />;
      case 'Lost': return <XCircle size={14} className="mr-1" />;
      default: return null;
    }
  };

  const filteredLeads = leads.filter(lead => {
    const matchesSearch = lead.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          lead.phone.includes(searchTerm) || 
                          lead.address.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = statusFilter === 'All' || lead.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const handleOpenModal = (lead?: Lead) => {
    if (lead) {
      setEditingId(lead.id);
      setFormData(lead);
    } else {
      setEditingId(null);
      setFormData({ 
        name: '', 
        phone: '', 
        address: '', 
        status: 'New', 
        assignedTo: activeStaff[0]?.id || '', 
        notes: '' 
      });
    }
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.phone || !formData.assignedTo) return;

    if (editingId) {
      updateLead(editingId, formData);
    } else {
      addLead({
        id: Date.now().toString(),
        name: formData.name || '',
        phone: formData.phone || '',
        address: formData.address || '',
        status: (formData.status || 'New') as any,
        assignedTo: formData.assignedTo || '',
        createdAt: new Date().toISOString(),
        notes: formData.notes || ''
      });
    }
    setShowModal(false);
  };

  return (
    <div className="max-w-6xl mx-auto space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
           <h1 className="text-2xl font-bold text-slate-800">Lead Management</h1>
           <p className="text-slate-500 mt-1">Track potential scrap sources and assign to staff</p>
        </div>

        <div className="flex flex-wrap gap-3">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="Search leads..." 
              className="pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none w-full md:w-56 bg-white text-slate-900"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="relative">
             <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
             <select 
               value={statusFilter}
               onChange={(e) => setStatusFilter(e.target.value)}
               className="pl-9 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none appearance-none bg-white text-slate-900 text-sm"
             >
               <option value="All">All Status</option>
               <option value="New">New</option>
               <option value="In Progress">In Progress</option>
               <option value="Converted">Converted</option>
               <option value="Lost">Lost</option>
             </select>
          </div>
          <button 
            onClick={() => handleOpenModal()}
            className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg transition-colors font-medium shadow-sm whitespace-nowrap"
          >
            <Plus size={18} />
            <span>Add Lead</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200 text-slate-600 text-sm uppercase tracking-wider">
                <th className="p-4 font-semibold">Lead Details</th>
                <th className="p-4 font-semibold">Status</th>
                <th className="p-4 font-semibold">Assigned Staff</th>
                <th className="p-4 font-semibold">Notes</th>
                <th className="p-4 font-semibold text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredLeads.map((lead) => {
                const assignedStaff = staff.find(s => s.id === lead.assignedTo);
                return (
                  <tr key={lead.id} className="hover:bg-slate-50 transition-colors">
                    <td className="p-4">
                      <div className="font-bold text-slate-800">{lead.name}</div>
                      <div className="flex items-center text-slate-500 text-xs mt-1 space-x-2">
                        <span className="flex items-center"><Phone size={10} className="mr-1"/> {lead.phone}</span>
                        <span className="flex items-center"><MapPin size={10} className="mr-1"/> {lead.address}</span>
                      </div>
                    </td>
                    <td className="p-4">
                      <span className={`inline-flex items-center px-2.5 py-1 rounded-full text-xs font-medium ${getStatusColor(lead.status)}`}>
                         {getStatusIcon(lead.status)}
                         {lead.status}
                      </span>
                    </td>
                    <td className="p-4">
                       <div className="flex items-center text-slate-700 text-sm font-medium">
                         <div className="w-6 h-6 rounded-full bg-slate-200 flex items-center justify-center text-xs mr-2 text-slate-600">
                            {assignedStaff?.name.charAt(0) || '?'}
                         </div>
                         {assignedStaff?.name || 'Unassigned'}
                       </div>
                    </td>
                    <td className="p-4 text-sm text-slate-500 max-w-xs truncate">
                       {lead.notes || '-'}
                    </td>
                    <td className="p-4 text-center">
                      <button 
                        onClick={() => handleOpenModal(lead)}
                        className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-full transition"
                      >
                        <Edit size={18} />
                      </button>
                    </td>
                  </tr>
                );
              })}
              {filteredLeads.length === 0 && (
                <tr>
                   <td colSpan={5} className="p-8 text-center text-slate-500">
                      No leads found.
                   </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add/Edit Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-lg max-w-lg w-full p-6">
            <h3 className="text-xl font-bold text-slate-800 mb-4">
              {editingId ? 'Edit Lead Details' : 'Create New Lead'}
            </h3>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Source Name</label>
                    <input 
                    type="text" 
                    required
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                    value={formData.name}
                    onChange={e => setFormData({...formData, name: e.target.value})}
                    placeholder="e.g. Hotel Plaza"
                    />
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Contact Phone</label>
                    <input 
                    type="tel" 
                    required
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                    value={formData.phone}
                    onChange={e => setFormData({...formData, phone: e.target.value})}
                    placeholder="98XXXXXXXX"
                    />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Address / Location</label>
                <input 
                  type="text" 
                  className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                  value={formData.address}
                  onChange={e => setFormData({...formData, address: e.target.value})}
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Assign To</label>
                    <select 
                    required
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                    value={formData.assignedTo}
                    onChange={e => setFormData({...formData, assignedTo: e.target.value})}
                    >
                        <option value="">-- Select Staff --</option>
                        {activeStaff.map(s => (
                            <option key={s.id} value={s.id}>{s.name} ({s.role})</option>
                        ))}
                    </select>
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Status</label>
                    <select 
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                    value={formData.status}
                    onChange={e => setFormData({...formData, status: e.target.value as any})}
                    >
                        <option value="New">New</option>
                        <option value="In Progress">In Progress</option>
                        <option value="Converted">Converted</option>
                        <option value="Lost">Lost</option>
                    </select>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Notes</label>
                <textarea 
                  className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                  rows={3}
                  value={formData.notes}
                  onChange={e => setFormData({...formData, notes: e.target.value})}
                  placeholder="Details about scrap material..."
                />
              </div>

              <div className="flex space-x-3 pt-4">
                <button 
                  type="button" 
                  onClick={() => setShowModal(false)}
                  className="flex-1 py-2 border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50"
                >
                  Cancel
                </button>
                <button 
                  type="submit" 
                  className="flex-1 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
                >
                  {editingId ? 'Update Lead' : 'Create Lead'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { useApp } from '../../context/AppContext';
import { BillItem, Bill, TransactionType, PaymentStatus, Customer } from '../../types';
import { generateBillPDF } from '../../utils/pdfGenerator';
import { Plus, Trash2, RotateCcw, Save, AlertCircle, Printer, Share2, CheckCircle, FileDown, Search, ArrowRightLeft, User, MapPin, Phone } from 'lucide-react';

export const Billing = () => {
  const { items, company, addBill, currentUser, customers, addCustomer } = useApp();

  // Refs for Focus Management
  const itemSelectRef = useRef<HTMLSelectElement>(null);
  const weightInputRef = useRef<HTMLInputElement>(null);
  const customNameRef = useRef<HTMLInputElement>(null);

  // Transaction Mode
  const [transactionType, setTransactionType] = useState<TransactionType>('PURCHASE');

  // Form State
  const [customerSearch, setCustomerSearch] = useState('');
  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);
  const [selectedCustomerId, setSelectedCustomerId] = useState<string | undefined>(undefined);

  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('Paid');

  const [billItems, setBillItems] = useState<BillItem[]>([]);

  // Item Entry State
  // Default to first item if available
  const [selectedItemId, setSelectedItemId] = useState(items.length > 0 ? items[0].id : '');
  const [weight, setWeight] = useState('');
  const [customName, setCustomName] = useState('');
  const [manualRate, setManualRate] = useState(''); // For Sales
  const [formError, setFormError] = useState<string | null>(null);

  // Modal States
  const [lastBill, setLastBill] = useState<Bill | null>(null);
  const [showSuccessModal, setShowSuccessModal] = useState(false);
  const [showConfirmationModal, setShowConfirmationModal] = useState(false);

  // Effect to ensure selectedItemId is valid on load
  useEffect(() => {
    if (!selectedItemId && items.length > 0) {
        setSelectedItemId(items[0].id);
    }
  }, [items, selectedItemId]);

  // Derived state
  const selectedItemData = items.find(i => i.id === selectedItemId);
  const isOthers = selectedItemData?.name === 'Others' || selectedItemData?.category === 'Others';

  // Rate Logic: Purchase = Fixed Admin Rate, Sale = Manual/Negotiated Rate (Default to Admin Rate)
  const activeRate = transactionType === 'SALE' && manualRate !== ''
    ? parseFloat(manualRate) 
    : (selectedItemData?.rate || 0);

  const currentAmount = (parseFloat(weight) || 0) * activeRate;
  const totalAmount = billItems.reduce((sum, item) => sum + item.amount, 0);
  const totalWeight = billItems.reduce((sum, item) => sum + item.weight, 0);

  // Filter customers for autocomplete
  const filteredCustomers = customers.filter(c => 
    c.name.toLowerCase().includes(customerSearch.toLowerCase()) || 
    c.phone.includes(customerSearch)
  );

  const selectCustomer = (customer: Customer) => {
    setCustomerName(customer.name);
    setCustomerPhone(customer.phone);
    setCustomerAddress(customer.address);
    setSelectedCustomerId(customer.id);
    setCustomerSearch('');
    setShowCustomerSuggestions(false);
  };

  const addItem = () => {
    // Validation
    if (!selectedItemId) return;
    if (!weight || parseFloat(weight) <= 0) {
      setFormError('weight');
      weightInputRef.current?.focus();
      return;
    }
    if (isOthers && !customName) {
      setFormError('customName');
      customNameRef.current?.focus();
      return;
    }

    setFormError(null);

    const resolvedName = isOthers && customName 
      ? `Others (${customName})` 
      : (selectedItemData?.name || 'Unknown');

    const newItem: BillItem = {
      id: Date.now().toString(),
      itemId: selectedItemId,
      itemName: resolvedName,
      customName: isOthers ? customName : undefined,
      rate: activeRate,
      weight: parseFloat(weight),
      amount: currentAmount
    };

    setBillItems([...billItems, newItem]);

    // Reset inputs
    setWeight('');
    setCustomName('');
    setManualRate('');

    // Focus logic for rapid entry
    if (window.innerWidth > 768) {
        // Desktop: Go back to item select
        itemSelectRef.current?.focus();
    } else {
        // Mobile: Blur to close keyboard
        (document.activeElement as HTMLElement)?.blur();
    }
  };

  const removeItem = (id: string) => {
    setBillItems(billItems.filter(item => item.id !== id));
  };

  const handleGenerateBill = () => {
    if (!customerName || billItems.length === 0) {
      alert("Please fill customer details and add at least one item.");
      return;
    }
    setShowConfirmationModal(true);
  };

  const finalizeBillGeneration = () => {
    // Auto-save new customer if phone doesn't exist
    if (customerPhone && !customers.some(c => c.phone === customerPhone)) {
      addCustomer({
        id: Date.now().toString(),
        name: customerName,
        phone: customerPhone,
        address: customerAddress
      });
    }

    // Create unique bill number (INV-YYYYMMDD-XXXX)
    const dateStr = new Date().toISOString().slice(0,10).replace(/-/g, '');
    const randomSuffix = Math.floor(1000 + Math.random() * 9000);
    const uniqueBillNo = `INV-${dateStr}-${randomSuffix}`;

    const bill: Bill = {
      id: Date.now().toString(),
      billNo: uniqueBillNo,
      transactionType,
      customerId: selectedCustomerId,
      customerName,
      customerPhone,
      customerAddress,
      items: billItems,
      totalAmount,
      paymentStatus,
      date: new Date().toISOString(),
      staffName: currentUser?.name || 'Staff',
      isFinalized: true, // Mark bill as immutable
    };

    addBill(bill);
    setLastBill(bill);

    // Clear form
    setCustomerName('');
    setCustomerPhone('');
    setCustomerAddress('');
    setSelectedCustomerId(undefined);
    setBillItems([]);
    setWeight('');
    setCustomName('');
    setManualRate('');
    setPaymentStatus('Paid');

    setShowConfirmationModal(false);
    setShowSuccessModal(true);
  };

  const shareViaWhatsApp = () => {
    if (!lastBill) return;
    const type = lastBill.transactionType === 'PURCHASE' ? 'Purchase Receipt' : 'Sales Invoice';
    const text = `*${company.name}*\n${type} #${lastBill.billNo}\nDate: ${new Date(lastBill.date).toLocaleDateString()}\nStatus: ${lastBill.paymentStatus}\n\nTotal Amount: *₹${lastBill.totalAmount.toFixed(2)}*\n\nThank you!`;
    const url = `https://wa.me/${lastBill.customerPhone}?text=${encodeURIComponent(text)}`;
    window.open(url, '_blank');
  };

  const isPurchase = transactionType === 'PURCHASE';

  return (
    <div className="max-w-7xl mx-auto space-y-4 lg:space-y-6 pb-20 lg:pb-0">

      {/* Top Bar: Transaction Type Toggle */}
      <div className="bg-white p-3 lg:p-4 rounded-xl shadow-sm border border-slate-200">
        <div className="flex flex-col sm:flex-row justify-between items-center gap-3">
            <div className="flex items-center space-x-2 text-slate-600">
                <ArrowRightLeft size={20} />
                <span className="font-bold">Mode</span>
            </div>
            <div className="flex w-full sm:w-auto bg-slate-100 p-1 rounded-lg">
                <button 
                    onClick={() => setTransactionType('PURCHASE')}
                    className={`flex-1 sm:flex-none px-4 py-2 rounded-md font-bold text-sm transition-all shadow-sm ${transactionType === 'PURCHASE' ? 'bg-blue-600 text-white' : 'text-slate-500 hover:text-slate-700 bg-transparent shadow-none'}`}
                >
                    Purchase (Buy)
                </button>
                <button 
                    onClick={() => setTransactionType('SALE')}
                    className={`flex-1 sm:flex-none px-4 py-2 rounded-md font-bold text-sm transition-all shadow-sm ${transactionType === 'SALE' ? 'bg-emerald-600 text-white' : 'text-slate-500 hover:text-slate-700 bg-transparent shadow-none'}`}
                >
                    Sale (Sell)
                </button>
            </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 lg:gap-6 items-start">

        {/* Left Column: Customer & Item Entry */}
        <div className="lg:col-span-2 space-y-4 lg:space-y-6">

            {/* Customer Details Card */}
            <div className="bg-white p-4 lg:p-6 rounded-xl shadow-sm border border-slate-200">
                <div className="flex justify-between items-center mb-4 border-b border-slate-100 pb-3">
                    <h3 className="font-bold text-slate-800 flex items-center gap-2">
                        <User size={18} className="text-slate-400"/>
                        Customer Details
                    </h3>
                    {selectedCustomerId && <span className="text-[10px] uppercase font-bold bg-green-100 text-green-700 px-2 py-1 rounded-full">Existing</span>}
                </div>

                {/* Customer Search Dropdown */}
                <div className="relative mb-4">
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                        <input 
                            type="text"
                            value={customerSearch}
                            onChange={(e) => {
                                setCustomerSearch(e.target.value);
                                setShowCustomerSuggestions(true);
                            }}
                            onFocus={() => setShowCustomerSuggestions(true)}
                            onBlur={() => setTimeout(() => setShowCustomerSuggestions(false), 200)}
                            placeholder="Search by Name or Phone..."
                            className="w-full pl-10 pr-4 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 text-slate-900 text-sm"
                        />
                    </div>
                    {showCustomerSuggestions && customerSearch && (
                        <div className="absolute z-30 w-full bg-white mt-1 border border-slate-200 rounded-lg shadow-xl max-h-48 overflow-y-auto">
                        {filteredCustomers.length > 0 ? (
                            filteredCustomers.map(c => (
                                <div 
                                key={c.id} 
                                onClick={() => selectCustomer(c)}
                                className="p-3 hover:bg-slate-50 cursor-pointer border-b border-slate-100 last:border-0"
                                >
                                <p className="font-bold text-slate-800 text-sm">{c.name}</p>
                                <p className="text-xs text-slate-500">{c.phone}</p>
                                </div>
                            ))
                        ) : (
                            <div className="p-3 text-sm text-slate-500">No existing customers found.</div>
                        )}
                        </div>
                    )}
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    <div className="relative">
                        <User className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                        <input 
                            type="text" 
                            value={customerName}
                            onChange={e => setCustomerName(e.target.value)}
                            className="w-full pl-9 pr-3 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900 text-sm"
                            placeholder="Name *"
                        />
                    </div>
                    <div className="relative">
                        <Phone className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                        <input 
                            type="tel" 
                            value={customerPhone}
                            onChange={e => setCustomerPhone(e.target.value)}
                            className="w-full pl-9 pr-3 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900 text-sm"
                            placeholder="Phone"
                        />
                    </div>
                    <div className="md:col-span-2 relative">
                        <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                        <input 
                            type="text" 
                            value={customerAddress}
                            onChange={e => setCustomerAddress(e.target.value)}
                            className="w-full pl-9 pr-3 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900 text-sm"
                            placeholder="Address / Area"
                        />
                    </div>
                </div>
            </div>

            {/* Item Entry Card (Light Theme) */}
            <div className={`p-4 lg:p-6 rounded-xl shadow-lg transition-colors duration-300 bg-white border-t-4 ${isPurchase ? 'border-blue-600' : 'border-emerald-600'}`}>
                <div className="flex justify-between items-center mb-4">
                    <h3 className={`font-bold ${isPurchase ? 'text-blue-700' : 'text-emerald-700'}`}>
                    {isPurchase ? 'Purchase Item' : 'Sell Item'}
                    </h3>
                    <span className={`text-[10px] uppercase font-bold px-2 py-1 rounded border ${isPurchase ? 'bg-blue-50 text-blue-700 border-blue-200' : 'bg-emerald-50 text-emerald-700 border-emerald-200'}`}>
                        Stock: {isPurchase ? 'IN' : 'OUT'}
                    </span>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-12 gap-4 items-end">

                    {/* Item Select */}
                    <div className={`md:col-span-${isOthers ? '3' : '4'}`}>
                        <label className="block text-xs text-slate-600 mb-1 font-medium">Item Name</label>
                        <select 
                            ref={itemSelectRef}
                            value={selectedItemId}
                            onChange={e => {
                                setSelectedItemId(e.target.value);
                                setCustomName('');
                                setManualRate('');
                            }}
                            className="w-full p-3 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-slate-900 text-sm"
                        >
                            {items.map(item => (
                            <option key={item.id} value={item.id}>
                                {item.name}
                            </option>
                            ))}
                        </select>
                    </div>

                    {/* Custom Description (Conditional) */}
                    {isOthers && (
                        <div className="md:col-span-3">
                            <label className="block text-xs text-slate-600 mb-1 font-medium">Description</label>
                            <input 
                                ref={customNameRef}
                                type="text" 
                                value={customName}
                                onChange={e => setCustomName(e.target.value)}
                                onKeyDown={(e) => e.key === 'Enter' && weightInputRef.current?.focus()}
                                className={`w-full p-3 bg-white border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-slate-900 placeholder-slate-400 text-sm ${formError === 'customName' ? 'border-red-400 ring-1 ring-red-400' : 'border-slate-300'}`}
                                placeholder="Details..."
                            />
                        </div>
                    )}

                    {/* Rate Input */}
                    <div className={`md:col-span-${isOthers ? '2' : '3'}`}>
                        <label className="block text-xs text-slate-600 mb-1 font-medium">Rate (₹/kg)</label>
                        {transactionType === 'SALE' ? (
                            <input 
                            type="number" 
                            value={manualRate !== '' ? manualRate : (activeRate > 0 ? activeRate : '')}
                            onChange={e => setManualRate(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && weightInputRef.current?.focus()}
                            placeholder={activeRate.toString()}
                            className="w-full p-3 bg-white text-slate-900 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-center"
                            />
                        ) : (
                            <div className="w-full p-3 bg-slate-100 border border-slate-300 rounded-lg text-slate-500 cursor-not-allowed font-mono text-center font-bold">
                            {activeRate.toFixed(2)}
                            </div>
                        )}
                    </div>

                    {/* Weight Input */}
                    <div className={`md:col-span-${isOthers ? '2' : '3'}`}>
                        <label className="block text-xs text-slate-600 mb-1 font-medium">Weight (Kg)</label>
                        <input 
                            ref={weightInputRef}
                            type="number" 
                            value={weight}
                            onChange={e => {
                                setWeight(e.target.value);
                                if (formError === 'weight') setFormError(null);
                            }}
                            className={`w-full p-3 bg-white text-slate-900 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-lg text-center ${formError === 'weight' ? 'border-red-500 ring-2 ring-red-500' : 'border-slate-300'}`}
                            placeholder="0.00"
                            step="0.01"
                            min="0"
                            inputMode="decimal"
                            onKeyDown={(e) => e.key === 'Enter' && addItem()}
                        />
                    </div>

                    {/* Add Button */}
                    <div className="md:col-span-2">
                        <button 
                            onClick={addItem}
                            className={`w-full p-3 font-bold rounded-lg transition-transform active:scale-95 flex justify-center items-center text-white shadow-lg
                            ${isPurchase ? 'bg-blue-600 hover:bg-blue-500' : 'bg-emerald-600 hover:bg-emerald-500'}
                            `}
                        >
                            <Plus size={24} />
                            <span className="md:hidden ml-2">Add</span>
                        </button>
                    </div>
                </div>

                {/* Footer of Card */}
                <div className="mt-4 pt-3 border-t border-slate-100 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-2">
                    <div className="flex flex-col">
                        <span className="text-[10px] uppercase tracking-wider text-slate-400 font-bold">Current Line Item</span>
                        <span className="text-xl font-bold text-slate-800">₹{currentAmount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                    </div>
                    <span className="flex items-center text-amber-600 text-xs bg-amber-50 border border-amber-100 px-2 py-1 rounded font-medium">
                        <AlertCircle size={12} className="mr-1"/> 
                        {isPurchase ? 'Admin Fixed Rate' : 'Market Rate Check'}
                    </span>
                </div>
            </div>
        </div>

        {/* Right Column: Invoice Summary */}
        <div className="lg:col-span-1 space-y-4">
             <div className="bg-white rounded-xl shadow-sm border border-slate-200 flex flex-col h-full overflow-hidden">
                <div className="p-4 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
                    <h3 className="font-bold text-slate-700">Invoice Items</h3>
                    <span className="bg-slate-200 text-slate-600 text-xs px-2 py-1 rounded-full font-bold">{billItems.length}</span>
                </div>

                <div className="flex-1 overflow-y-auto min-h-[200px] max-h-[400px]">
                    {billItems.length > 0 ? (
                        <div className="divide-y divide-slate-100">
                            {billItems.map((item) => (
                                <div key={item.id} className="p-3 hover:bg-slate-50 flex justify-between items-center group">
                                    <div className="flex-1">
                                        <div className="font-bold text-slate-800 text-sm">{item.itemName}</div>
                                        <div className="text-xs text-slate-500">
                                            {item.weight} kg × ₹{item.rate}
                                        </div>
                                    </div>
                                    <div className="text-right mx-3">
                                        <div className="font-bold text-slate-800 text-sm">₹{item.amount.toFixed(2)}</div>
                                    </div>
                                    <button 
                                        onClick={() => removeItem(item.id)}
                                        className="text-slate-300 hover:text-red-500 transition p-1"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 space-y-2">
                             <div className="w-12 h-12 rounded-full bg-slate-100 flex items-center justify-center">
                                <Plus size={24} className="opacity-50"/>
                             </div>
                             <p className="text-sm">Add items to bill</p>
                        </div>
                    )}
                </div>

                <div className="p-4 bg-slate-50 border-t border-slate-200">
                    <div className="flex justify-between items-center mb-2">
                        <span className="text-slate-600 font-medium">Total Weight</span>
                        <span className="text-lg font-bold text-slate-700">{totalWeight.toFixed(2)} kg</span>
                    </div>
                    <div className="flex justify-between items-center mb-4">
                        <span className="text-slate-600 font-medium">Total Amount</span>
                        <span className="text-2xl font-bold text-slate-900">₹{totalAmount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                    </div>
                    <button 
                        onClick={handleGenerateBill}
                        disabled={billItems.length === 0}
                        className={`w-full py-3 rounded-lg font-bold text-white shadow-md transition-all active:scale-95 flex items-center justify-center space-x-2
                            ${billItems.length === 0 ? 'bg-slate-300 cursor-not-allowed' : 
                              isPurchase ? 'bg-blue-600 hover:bg-blue-700' : 'bg-emerald-600 hover:bg-emerald-700'}
                        `}
                    >
                        <Save size={20} />
