                  <td className={`p-4 text-right font-bold ${bill.transactionType === 'PURCHASE' ? 'text-blue-600' : 'text-emerald-600'}`}>
                      ₹{bill.totalAmount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}
