                  <td className="p-4">
                     <span className={`px-2 py-1 text-xs font-semibold rounded ${
                      leave.status === 'Approved' ? 'bg-green-100 text-green-700' : 
                      leave.status === 'Rejected' ? 'bg-red-100 text-red-700' : 
                      'bg-yellow-100 text-yellow-700'
                    }`}>
                      {leave.status}
                    </span>
                  </td>
                  <td className="p-4 text-right space-x-2">
                    {leave.status === 'Pending' && (
                      <>
                        <button 
                          onClick={() => updateLeaveStatus(leave.id, 'Approved')}
                          className="p-1.5 bg-green-100 text-green-600 rounded hover:bg-green-200 transition"
                          title="Approve"
                        >
                          <Check size={16} />
                        </button>
                        <button 
                          onClick={() => updateLeaveStatus(leave.id, 'Rejected')}
                          className="p-1.5 bg-red-100 text-red-600 rounded hover:bg-red-200 transition"
                          title="Reject"
                        >
                          <X size={16} />
                        </button>
                      </>
                    )}
                  </td>
                </tr>
              ))}
              {leaves.length === 0 && (
                <tr>
                  <td colSpan={5} className="p-8 text-center text-slate-500">No leave requests found.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      )}

      {/* Add Staff Modal */}
      {showAddModal && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-lg max-w-md w-full p-6">
            <h3 className="text-xl font-bold text-slate-800 mb-4">Add New Staff Member</h3>
            <form onSubmit={handleAddStaff} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Full Name</label>
                <input 
                  type="text" 
                  required
                  className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                  value={newStaff.name || ''}
                  onChange={e => setNewStaff({...newStaff, name: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Phone Number</label>
                <input 
                  type="tel" 
                  required
                  className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                  value={newStaff.phone || ''}
                  onChange={e => setNewStaff({...newStaff, phone: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Password</label>
                <input 
                  type="password" 
                  required
                  className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                  value={newStaff.password || ''}
                  onChange={e => setNewStaff({...newStaff, password: e.target.value})}
                  placeholder="Set login password"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Role</label>
                <select 
                  className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                  value={newStaff.role}
                  onChange={e => setNewStaff({...newStaff, role: e.target.value as any})}
                >
                  <option value="Worker">Worker</option>
                  <option value="Driver">Driver</option>
                  <option value="Manager">Manager</option>
                </select>
              </div>
              <div className="flex space-x-3 pt-4">
                <button 
                  type="button" 
                  onClick={() => setShowAddModal(false)}
                  className="flex-1 py-2 border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50"
                >
                  Cancel
                </button>
                <button 
                  type="submit" 
                  className="flex-1 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
                >
                  Add Staff
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../../context/AppContext';
import { Edit2, Save, X, AlertTriangle, Search, Plus, Trash2 } from 'lucide-react';

export const RateChart = () => {
  const { items, updateItemRate, addItem, deleteItem } = useApp();
  const [editingId, setEditingId] = useState<string | null>(null);
  const [tempRate, setTempRate] = useState<string>('');
  const [searchTerm, setSearchTerm] = useState('');

  // Add Item Modal State
  const [showAddModal, setShowAddModal] = useState(false);
  const [newItem, setNewItem] = useState({ name: '', category: 'Metal', rate: '' });

  const startEdit = (id: string, currentRate: number) => {
    setEditingId(id);
    setTempRate(currentRate.toString());
  };

  const saveEdit = (id: string) => {
    const rate = parseFloat(tempRate);
    if (!isNaN(rate) && rate >= 0) {
      updateItemRate(id, rate);
    }
    setEditingId(null);
  };

  const cancelEdit = () => {
    setEditingId(null);
    setTempRate('');
  };

  const handleDelete = (id: string, name: string) => {
    if (confirm(`Are you sure you want to delete "${name}"? This item will be removed from the selection list.`)) {
      deleteItem(id);
    }
  };

  const handleAddItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (newItem.name && newItem.rate) {
      addItem({
        id: Date.now().toString(),
        name: newItem.name,
        category: newItem.category as any,
        rate: parseFloat(newItem.rate),
        lastUpdated: new Date().toISOString().split('T')[0]
      });
      setShowAddModal(false);
      setNewItem({ name: '', category: 'Metal', rate: '' });
    }
  };

  const filteredItems = items.filter(item => 
    item.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    item.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
           <h1 className="text-2xl font-bold text-slate-800">Rate Chart Management</h1>
           <p className="text-slate-500 mt-1">Manage daily scrap buying rates</p>
        </div>

        <div className="flex space-x-3">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="Search items..." 
              className="pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none w-full md:w-64 bg-white text-slate-900"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={() => setShowAddModal(true)}
            className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg transition-colors font-medium shadow-sm whitespace-nowrap"
          >
            <Plus size={18} />
            <span>Add Item</span>
          </button>
        </div>
      </div>

      <div className="bg-amber-50 border-l-4 border-amber-500 p-4 rounded-r-lg flex items-start space-x-3">
        <AlertTriangle className="text-amber-600 shrink-0 mt-0.5" size={20} />
        <div>
          <h4 className="font-bold text-amber-800">Critical Warning</h4>
          <p className="text-sm text-amber-700 mt-1">
            Rates updated here reflect instantly in the staff billing panel. Do not change rates while a purchase is being negotiated to avoid discrepancies.
          </p>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200 text-slate-600 text-sm uppercase tracking-wider">
                <th className="p-4 font-semibold">Item Name</th>
                <th className="p-4 font-semibold">Category</th>
                <th className="p-4 font-semibold text-right">Current Rate (₹/Kg)</th>
                <th className="p-4 font-semibold text-right">Last Updated</th>
                <th className="p-4 font-semibold text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredItems.map((item) => (
                <tr key={item.id} className="hover:bg-slate-50 transition-colors">
                  <td className="p-4 font-medium text-slate-800">{item.name}</td>
                  <td className="p-4">
                    <span className="px-2 py-1 bg-slate-100 text-slate-600 rounded text-xs font-semibold">
                      {item.category}
                    </span>
                  </td>
                  <td className="p-4 text-right">
                    {editingId === item.id ? (
                      <input 
                        type="number" 
                        value={tempRate}
                        onChange={(e) => setTempRate(e.target.value)}
                        className="w-24 text-right p-1 border border-blue-400 rounded focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                        autoFocus
                      />
                    ) : (
                      <span className="font-bold text-slate-700">₹{item.rate.toFixed(2)}</span>
                    )}
                  </td>
                  <td className="p-4 text-right text-sm text-slate-500">{item.lastUpdated}</td>
                  <td className="p-4 flex justify-center space-x-2">
                    {editingId === item.id ? (
                      <>
                        <button 
                          onClick={() => saveEdit(item.id)}
                          className="p-2 bg-green-100 text-green-700 rounded-lg hover:bg-green-200 transition"
                          title="Save"
                        >
                          <Save size={18} />
                        </button>
                        <button 
                          onClick={cancelEdit}
                          className="p-2 bg-red-100 text-red-700 rounded-lg hover:bg-red-200 transition"
                          title="Cancel"
                        >
                          <X size={18} />
                        </button>
                      </>
                    ) : (
                      <>
                        <button 
                            onClick={() => startEdit(item.id, item.rate)}
                            className="p-2 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-100 transition"
                            title="Edit Rate"
                            disabled={item.name === 'Others' && item.rate === 0} 
                        >
                            <Edit2 size={18} />
                        </button>
                        {item.name !== 'Others' && (
                            <button 
                                onClick={() => handleDelete(item.id, item.name)}
                                className="p-2 bg-red-50 text-red-600 rounded-lg hover:bg-red-100 transition"
                                title="Delete Item"
                            >
                                <Trash2 size={18} />
                            </button>
                        )}
                      </>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {filteredItems.length === 0 && (
          <div className="p-8 text-center text-slate-500">
            No items found matching your search.
          </div>
        )}
      </div>

      {/* Add Item Modal */}
      {showAddModal && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-lg max-w-sm w-full p-6 animate-in fade-in zoom-in duration-200">
            <h3 className="text-xl font-bold text-slate-800 mb-4">Add New Item</h3>
            <form onSubmit={handleAddItem} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Item Name</label>
                <input 
                  type="text" 
                  required
                  className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                  value={newItem.name}
                  onChange={e => setNewItem({...newItem, name: e.target.value})}
                  placeholder="e.g. Copper Wire"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Category</label>
                <select 
                  className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                  value={newItem.category}
                  onChange={e => setNewItem({...newItem, category: e.target.value})}
                >
                  <option value="Metal">Metal</option>
                  <option value="Paper">Paper</option>
                  <option value="Plastic">Plastic</option>
                  <option value="Electronics">Electronics</option>
                  <option value="Others">Others</option>
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Initial Rate (₹/Kg)</label>
                <input 
                  type="number" 
                  required
                  className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                  value={newItem.rate}
                  onChange={e => setNewItem({...newItem, rate: e.target.value})}
                  placeholder="0.00"
                  step="0.01"
                />
              </div>
              <div className="flex space-x-3 pt-2">
                <button 
                  type="button" 
                  onClick={() => setShowAddModal(false)}
                  className="flex-1 py-2 border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50"
                >
                  Cancel
                </button>
                <button 
                  type="submit" 
                  className="flex-1 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
                >
                  Save Item
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../../context/AppContext';
import { Lead } from '../../types';
import { Search, Plus, MapPin, Phone, User, Filter, Edit, CheckCircle2, Clock, XCircle, AlertCircle, Trash2 } from 'lucide-react';

export const Leads = () => {
  const { leads, addLead, updateLead, deleteLead, staff } = useApp();
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('All');
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  // Filter staff to get only active ones for assignment
  const activeStaff = staff.filter(s => s.status === 'Active');

  const [formData, setFormData] = useState<Partial<Lead>>({
    name: '',
    phone: '',
    address: '',
    status: 'New',
    assignedTo: '',
    notes: ''
  });

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'New': return 'bg-blue-100 text-blue-700';
      case 'In Progress': return 'bg-yellow-100 text-yellow-700';
      case 'Converted': return 'bg-green-100 text-green-700';
      case 'Lost': return 'bg-red-100 text-red-700';
      default: return 'bg-slate-100 text-slate-700';
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'New': return <AlertCircle size={14} className="mr-1" />;
      case 'In Progress': return <Clock size={14} className="mr-1" />;
      case 'Converted': return <CheckCircle2 size={14} className="mr-1" />;
      case 'Lost': return <XCircle size={14} className="mr-1" />;
      default: return null;
    }
  };

  const filteredLeads = leads.filter(lead => {
    const matchesSearch = lead.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          lead.phone.includes(searchTerm) || 
                          lead.address.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = statusFilter === 'All' || lead.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const handleOpenModal = (lead?: Lead) => {
    if (lead) {
      setEditingId(lead.id);
      setFormData(lead);
    } else {
      setEditingId(null);
      setFormData({ 
        name: '', 
        phone: '', 
        address: '', 
        status: 'New', 
        assignedTo: activeStaff[0]?.id || '', 
        notes: '' 
      });
    }
    setShowModal(true);
  };

  const handleDelete = (id: string, name: string) => {
    if (confirm(`Are you sure you want to delete lead "${name}"?`)) {
      deleteLead(id);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.phone || !formData.assignedTo) return;

    if (editingId) {
      updateLead(editingId, formData);
    } else {
      addLead({
        id: Date.now().toString(),
        name: formData.name || '',
        phone: formData.phone || '',
        address: formData.address || '',
        status: (formData.status || 'New') as any,
        assignedTo: formData.assignedTo || '',
        createdAt: new Date().toISOString(),
        notes: formData.notes || ''
      });
    }
    setShowModal(false);
  };

  return (
    <div className="max-w-6xl mx-auto space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
           <h1 className="text-2xl font-bold text-slate-800">Lead Management</h1>
           <p className="text-slate-500 mt-1">Track potential scrap sources and assign to staff</p>
        </div>

        <div className="flex flex-wrap gap-3">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="Search leads..." 
              className="pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none w-full md:w-56 bg-white text-slate-900"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="relative">
             <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
             <select 
               value={statusFilter}
               onChange={(e) => setStatusFilter(e.target.value)}
               className="pl-9 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none appearance-none bg-white text-slate-900 text-sm"
             >
               <option value="All">All Status</option>
               <option value="New">New</option>
               <option value="In Progress">In Progress</option>
               <option value="Converted">Converted</option>
               <option value="Lost">Lost</option>
             </select>
          </div>
          <button 
            onClick={() => handleOpenModal()}
            className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg transition-colors font-medium shadow-sm whitespace-nowrap"
          >
            <Plus size={18} />
            <span>Add Lead</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200 text-slate-600 text-sm uppercase tracking-wider">
                <th className="p-4 font-semibold">Lead Details</th>
                <th className="p-4 font-semibold">Status</th>
                <th className="p-4 font-semibold">Assigned Staff</th>
                <th className="p-4 font-semibold">Notes</th>
                <th className="p-4 font-semibold text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredLeads.map((lead) => {
                const assignedStaff = staff.find(s => s.id === lead.assignedTo);
                return (
                  <tr key={lead.id} className="hover:bg-slate-50 transition-colors">
                    <td className="p-4">
                      <div className="font-bold text-slate-800">{lead.name}</div>
                      <div className="flex items-center text-slate-500 text-xs mt-1 space-x-2">
                        <span className="flex items-center"><Phone size={10} className="mr-1"/> {lead.phone}</span>
                        <span className="flex items-center"><MapPin size={10} className="mr-1"/> {lead.address}</span>
                      </div>
                    </td>
                    <td className="p-4">
                      <span className={`inline-flex items-center px-2.5 py-1 rounded-full text-xs font-medium ${getStatusColor(lead.status)}`}>
                         {getStatusIcon(lead.status)}
                         {lead.status}
                      </span>
                    </td>
                    <td className="p-4">
                       <div className="flex items-center text-slate-700 text-sm font-medium">
                         <div className="w-6 h-6 rounded-full bg-slate-200 flex items-center justify-center text-xs mr-2 text-slate-600">
                            {assignedStaff?.name.charAt(0) || '?'}
                         </div>
                         {assignedStaff?.name || 'Unassigned'}
                       </div>
                    </td>
                    <td className="p-4 text-sm text-slate-500 max-w-xs truncate">
                       {lead.notes || '-'}
                    </td>
                    <td className="p-4 text-center space-x-2">
                      <button 
                        onClick={() => handleOpenModal(lead)}
                        className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-full transition"
                      >
                        <Edit size={18} />
                      </button>
                      <button 
                        onClick={() => handleDelete(lead.id, lead.name)}
                        className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-full transition"
                      >
                        <Trash2 size={18} />
                      </button>
                    </td>
                  </tr>
                );
              })}
              {filteredLeads.length === 0 && (
                <tr>
                   <td colSpan={5} className="p-8 text-center text-slate-500">
                      No leads found.
                   </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add/Edit Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-lg max-w-lg w-full p-6">
            <h3 className="text-xl font-bold text-slate-800 mb-4">
              {editingId ? 'Edit Lead Details' : 'Create New Lead'}
            </h3>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Source Name</label>
                    <input 
                    type="text" 
                    required
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                    value={formData.name}
                    onChange={e => setFormData({...formData, name: e.target.value})}
                    placeholder="e.g. Hotel Plaza"
                    />
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Contact Phone</label>
                    <input 
                    type="tel" 
                    required
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                    value={formData.phone}
                    onChange={e => setFormData({...formData, phone: e.target.value})}
                    placeholder="98XXXXXXXX"
                    />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Address / Location</label>
                <input 
                  type="text" 
                  className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                  value={formData.address}
                  onChange={e => setFormData({...formData, address: e.target.value})}
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Assign To</label>
                    <select 
                    required
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                    value={formData.assignedTo}
                    onChange={e => setFormData({...formData, assignedTo: e.target.value})}
                    >
                        <option value="">-- Select Staff --</option>
                        {activeStaff.map(s => (
                            <option key={s.id} value={s.id}>{s.name} ({s.role})</option>
                        ))}
                    </select>
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Status</label>
                    <select 
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                    value={formData.status}
                    onChange={e => setFormData({...formData, status: e.target.value as any})}
                    >
                        <option value="New">New</option>
                        <option value="In Progress">In Progress</option>
                        <option value="Converted">Converted</option>
                        <option value="Lost">Lost</option>
                    </select>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Notes</label>
                <textarea 
                  className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                  rows={3}
                  value={formData.notes}
                  onChange={e => setFormData({...formData, notes: e.target.value})}
                  placeholder="Details about scrap material..."
                />
              </div>

              <div className="flex space-x-3 pt-4">
                <button 
                  type="button" 
                  onClick={() => setShowModal(false)}
                  className="flex-1 py-2 border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50"
                >
                  Cancel
                </button>
                <button 
                  type="submit" 
                  className="flex-1 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
                >
                  {editingId ? 'Update Lead' : 'Create Lead'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export interface ScrapItem {
  id: string;
  name: string;
  rate: number;
  lastUpdated: string;
  category: 'Metal' | 'Paper' | 'Plastic' | 'Electronics' | 'Others';
}

export interface StockItem {
  itemId: string;
  itemName: string;
  purchased: number;
  sold: number;
  available: number;
}

export interface StaffMember {
  id: string;
  name: string;
  role: 'Manager' | 'Worker' | 'Driver';
  status: 'Active' | 'Inactive';
  phone: string;
  password?: string;
}

export interface Customer {
  id: string;
  name: string;
  phone: string;
  address: string;
}

export interface Lead {
  id: string;
  name: string;
  phone: string;
  address: string;
  status: 'New' | 'In Progress' | 'Converted' | 'Lost';
  assignedTo: string; // Staff ID
  createdAt: string;
  notes?: string;
}

export interface LeaveRequest {
  id: string;
  staffName: string;
  fromDate: string;
  toDate: string;
  reason: string;
  status: 'Pending' | 'Approved' | 'Rejected';
}

export interface SalaryPayment {
  id: string;
  staffId: string;
  staffName: string;
  amount: number;
  paymentDate: string;
  type: 'Salary' | 'Advance' | 'Bonus';
  remarks?: string;
}

export interface CompanySettings {
  name: string;
  subtitle: string;
  address: string;
  phone: string;
  signatureUrl: string | null; // Base64 string for demo
}

export interface BillItem {
  id: string; // unique row id
  itemId: string; // ref to ScrapItem
  itemName: string; // Snapshot of item name
  customName?: string; // for 'Others'
  rate: number;
  weight: number;
  totalWeight: number;
  amount: number;
}

export type TransactionType = 'PURCHASE' | 'SALE';
export type PaymentStatus = 'Paid' | 'Pending';

export interface Bill {
  id: string;
  billNo: string;
  transactionType: TransactionType;
  customerId?: string;
  customerName: string;
  customerAddress: string;
  customerPhone: string;
  items: BillItem[];
  totalAmount: number;
  paymentStatus: PaymentStatus;
  date: string;
  staffName: string;
  isFinalized?: boolean;
}

export type ViewMode = 'ADMIN' | 'STAFF';

import React, { useState, useRef, useEffect } from 'react';
import { useApp } from '../../context/AppContext';
import { BillItem, Bill, TransactionType, PaymentStatus, Customer } from '../../types';
import { generateBillPDF } from '../../utils/pdfGenerator';
import { Plus, Trash2, RotateCcw, Save, AlertCircle, Printer, Share2, CheckCircle, FileDown, Search, ArrowRightLeft, User, MapPin, Phone, Lock } from 'lucide-react';

export const Billing = () => {
  const { items, company, addBill, currentUser, customers, addCustomer } = useApp();

  // Refs for Focus Management
  const itemSelectRef = useRef<HTMLSelectElement>(null);
  const weightInputRef = useRef<HTMLInputElement>(null);
  const customNameRef = useRef<HTMLInputElement>(null);

  // Transaction Mode
  const [transactionType, setTransactionType] = useState<TransactionType>('PURCHASE');

  // Form State
  const [customerSearch, setCustomerSearch] = useState('');
  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);
  const [selectedCustomerId, setSelectedCustomerId] = useState<string | undefined>(undefined);

  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('Paid');

  const [billItems, setBillItems] = useState<BillItem[]>([]);

  // Item Entry State
  // Default to first item if available
  const [selectedItemId, setSelectedItemId] = useState(items.length > 0 ? items[0].id : '');
  const [weight, setWeight] = useState('');
  const [customName, setCustomName] = useState('');
  const [manualRate, setManualRate] = useState(''); // For Sales
  const [formError, setFormError] = useState<string | null>(null);

  // Modal States
  const [lastBill, setLastBill] = useState<Bill | null>(null);
  const [showSuccessModal, setShowSuccessModal] = useState(false);
  const [showConfirmationModal, setShowConfirmationModal] = useState(false);

  // Effect to ensure selectedItemId is valid on load
  useEffect(() => {
    if (!selectedItemId && items.length > 0) {
        setSelectedItemId(items[0].id);
    }
  }, [items, selectedItemId]);

  // Derived state
  const selectedItemData = items.find(i => i.id === selectedItemId);
  const isOthers = selectedItemData?.name === 'Others' || selectedItemData?.category === 'Others';

  // Rate Logic: Purchase = Fixed Admin Rate, Sale = Manual/Negotiated Rate (Default to Admin Rate)
  const activeRate = transactionType === 'SALE' && manualRate !== ''
    ? parseFloat(manualRate) 
    : (selectedItemData?.rate || 0);

  const currentAmount = (parseFloat(weight) || 0) * activeRate;
  const totalAmount = billItems.reduce((sum, item) => sum + item.amount, 0);
  const totalWeight = billItems.reduce((sum, item) => sum + (item.totalWeight || item.weight), 0);

  // Filter customers for autocomplete
  const filteredCustomers = customers.filter(c => 
    c.name.toLowerCase().includes(customerSearch.toLowerCase()) || 
    c.phone.includes(customerSearch)
  );

  const selectCustomer = (customer: Customer) => {
    setCustomerName(customer.name);
    setCustomerPhone(customer.phone);
    setCustomerAddress(customer.address);
    setSelectedCustomerId(customer.id);
    setCustomerSearch('');
    setShowCustomerSuggestions(false);
  };

  const addItem = () => {
    // Validation
    if (!selectedItemId) return;
    if (!weight || parseFloat(weight) <= 0) {
      setFormError('weight');
      weightInputRef.current?.focus();
      return;
    }
    if (isOthers && !customName) {
      setFormError('customName');
      customNameRef.current?.focus();
      return;
    }

    setFormError(null);

    const resolvedName = isOthers && customName 
      ? `Others (${customName})` 
      : (selectedItemData?.name || 'Unknown');

    const weightVal = parseFloat(weight);

    const newItem: BillItem = {
      id: Date.now().toString(),
      itemId: selectedItemId,
      itemName: resolvedName,
      customName: isOthers ? customName : undefined,
      rate: activeRate,
      weight: weightVal,
      totalWeight: weightVal,
      amount: currentAmount
    };

    setBillItems([...billItems, newItem]);

    // Reset inputs
    setWeight('');
    setCustomName('');
    setManualRate('');

    // Focus logic for rapid entry
    if (window.innerWidth > 768) {
        // Desktop: Go back to item select
        itemSelectRef.current?.focus();
    } else {
        // Mobile: Blur to close keyboard
        (document.activeElement as HTMLElement)?.blur();
    }
  };

  const removeItem = (id: string) => {
    setBillItems(billItems.filter(item => item.id !== id));
  };

  const handleGenerateBill = () => {
    if (!customerName || billItems.length === 0) {
      alert("Please fill customer details and add at least one item.");
      return;
    }
    setShowConfirmationModal(true);
  };

  const finalizeBillGeneration = () => {
    // Auto-save new customer if phone doesn't exist
    if (customerPhone && !customers.some(c => c.phone === customerPhone)) {
      addCustomer({
        id: Date.now().toString(),
        name: customerName,
        phone: customerPhone,
        address: customerAddress
      });
    }

    // Create unique bill number (INV-YYYYMMDD-XXXX)
    const dateStr = new Date().toISOString().slice(0,10).replace(/-/g, '');
    const randomSuffix = Math.floor(1000 + Math.random() * 9000);
    const uniqueBillNo = `INV-${dateStr}-${randomSuffix}`;

    const bill: Bill = {
      id: Date.now().toString(),
      billNo: uniqueBillNo,
      transactionType,
      customerId: selectedCustomerId,
      customerName,
      customerPhone,
      customerAddress,
      items: billItems,
      totalAmount,
      paymentStatus,
      date: new Date().toISOString(),
      staffName: currentUser?.name || 'Staff',
      isFinalized: true, // Mark bill as immutable
    };

    addBill(bill);
    setLastBill(bill);

    // Clear form
    setCustomerName('');
    setCustomerPhone('');
    setCustomerAddress('');
    setSelectedCustomerId(undefined);
    setBillItems([]);
    setWeight('');
    setCustomName('');
    setManualRate('');
    setPaymentStatus('Paid');

    setShowConfirmationModal(false);
    setShowSuccessModal(true);
  };

  const shareViaWhatsApp = () => {
    if (!lastBill) return;
    const type = lastBill.transactionType === 'PURCHASE' ? 'Purchase Receipt' : 'Sales Invoice';
    const text = `*${company.name}*\n${type} #${lastBill.billNo}\nDate: ${new Date(lastBill.date).toLocaleDateString()}\nStatus: ${lastBill.paymentStatus}\n\nTotal Amount: *₹${lastBill.totalAmount.toFixed(2)}*\n\nThank you!`;
    const url = `https://wa.me/${lastBill.customerPhone}?text=${encodeURIComponent(text)}`;
    window.open(url, '_blank');
  };

  const isPurchase = transactionType === 'PURCHASE';

  return (
    <div className="max-w-7xl mx-auto space-y-4 lg:space-y-6 pb-20 lg:pb-0">

      {/* Top Bar: Transaction Type Toggle */}
      <div className="bg-white p-3 lg:p-4 rounded-xl shadow-sm border border-slate-200">
        <div className="flex flex-col sm:flex-row justify-between items-center gap-3">
            <div className="flex items-center space-x-2 text-slate-600">
                <ArrowRightLeft size={20} />
                <span className="font-bold">Mode</span>
            </div>
            <div className="flex w-full sm:w-auto bg-slate-100 p-1 rounded-lg">
                <button 
                    onClick={() => setTransactionType('PURCHASE')}
                    className={`flex-1 sm:flex-none px-4 py-2 rounded-md font-bold text-sm transition-all shadow-sm ${transactionType === 'PURCHASE' ? 'bg-blue-600 text-white' : 'text-slate-500 hover:text-slate-700 bg-transparent shadow-none'}`}
                >
                    Purchase (Buy)
                </button>
                <button 
                    onClick={() => setTransactionType('SALE')}
                    className={`flex-1 sm:flex-none px-4 py-2 rounded-md font-bold text-sm transition-all shadow-sm ${transactionType === 'SALE' ? 'bg-emerald-600 text-white' : 'text-slate-500 hover:text-slate-700 bg-transparent shadow-none'}`}
                >
                    Sale (Sell)
                </button>
            </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 lg:gap-6 items-start">

        {/* Left Column: Customer & Item Entry */}
        <div className="lg:col-span-2 space-y-4 lg:space-y-6">

            {/* Customer Details Card */}
            <div className="bg-white p-4 lg:p-6 rounded-xl shadow-sm border border-slate-200">
                <div className="flex justify-between items-center mb-4 border-b border-slate-100 pb-3">
                    <h3 className="font-bold text-slate-800 flex items-center gap-2">
                        <User size={18} className="text-slate-400"/>
                        Customer Details
                    </h3>
                    {selectedCustomerId && <span className="text-[10px] uppercase font-bold bg-green-100 text-green-700 px-2 py-1 rounded-full">Existing</span>}
                </div>

                {/* Customer Search Dropdown */}
                <div className="relative mb-4">
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                        <input 
                            type="text"
                            value={customerSearch}
                            onChange={(e) => {
                                setCustomerSearch(e.target.value);
                                setShowCustomerSuggestions(true);
                            }}
                            onFocus={() => setShowCustomerSuggestions(true)}
                            onBlur={() => setTimeout(() => setShowCustomerSuggestions(false), 200)}
                            placeholder="Search by Name or Phone..."
                            className="w-full pl-10 pr-4 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 text-slate-900 text-sm"
                        />
                    </div>
                    {showCustomerSuggestions && customerSearch && (
                        <div className="absolute z-30 w-full bg-white mt-1 border border-slate-200 rounded-lg shadow-xl max-h-48 overflow-y-auto">
                        {filteredCustomers.length > 0 ? (
                            filteredCustomers.map(c => (
                                <div 
                                key={c.id} 
                                onClick={() => selectCustomer(c)}
                                className="p-3 hover:bg-slate-50 cursor-pointer border-b border-slate-100 last:border-0"
                                >
                                <p className="font-bold text-slate-800 text-sm">{c.name}</p>
                                <p className="text-xs text-slate-500">{c.phone}</p>
                                </div>
                            ))
                        ) : (
                            <div className="p-3 text-sm text-slate-500">No existing customers found.</div>
                        )}
                        </div>
                    )}
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    <div className="relative">
                        <User className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                        <input 
                            type="text" 
                            value={customerName}
                            onChange={e => setCustomerName(e.target.value)}
                            className="w-full pl-9 pr-3 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900 text-sm"
                            placeholder="Name *"
                        />
                    </div>
                    <div className="relative">
                        <Phone className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                        <input 
                            type="tel" 
                            value={customerPhone}
                            onChange={e => setCustomerPhone(e.target.value)}
                            className="w-full pl-9 pr-3 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900 text-sm"
                            placeholder="Phone"
                        />
                    </div>
                    <div className="md:col-span-2 relative">
                        <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                        <input 
                            type="text" 
                            value={customerAddress}
                            onChange={e => setCustomerAddress(e.target.value)}
                            className="w-full pl-9 pr-3 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900 text-sm"
                            placeholder="Address / Area"
                        />
                    </div>
                </div>
            </div>

            {/* Item Entry Card (Light Theme) */}
            <div className={`p-4 lg:p-6 rounded-xl shadow-lg transition-colors duration-300 bg-white border-t-4 ${isPurchase ? 'border-blue-600' : 'border-emerald-600'}`}>
                <div className="flex justify-between items-center mb-4">
                    <h3 className={`font-bold ${isPurchase ? 'text-blue-700' : 'text-emerald-700'}`}>
                    {isPurchase ? 'Purchase Item' : 'Sell Item'}
                    </h3>
                    <span className={`text-[10px] uppercase font-bold px-2 py-1 rounded border ${isPurchase ? 'bg-blue-50 text-blue-700 border-blue-200' : 'bg-emerald-50 text-emerald-700 border-emerald-200'}`}>
                        Stock: {isPurchase ? 'IN' : 'OUT'}
                    </span>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-12 gap-4 items-end">

                    {/* Item Select */}
                    <div className={`md:col-span-${isOthers ? '3' : '4'}`}>
                        <label className="block text-xs text-slate-600 mb-1 font-medium">Item Name</label>
                        <select 
                            ref={itemSelectRef}
                            value={selectedItemId}
                            onChange={e => {
                                setSelectedItemId(e.target.value);
                                setCustomName('');
                                setManualRate('');
                            }}
                            className="w-full p-3 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-slate-900 text-sm"
                        >
                            {items.map(item => (
                            <option key={item.id} value={item.id}>
                                {item.name}
                            </option>
                            ))}
                        </select>
                    </div>

                    {/* Custom Description (Conditional) */}
                    {isOthers && (
                        <div className="md:col-span-3">
                            <label className="block text-xs text-slate-600 mb-1 font-medium">Description</label>
                            <input 
                                ref={customNameRef}
                                type="text" 
                                value={customName}
                                onChange={e => setCustomName(e.target.value)}
                                onKeyDown={(e) => e.key === 'Enter' && weightInputRef.current?.focus()}
                                className={`w-full p-3 bg-white border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-slate-900 placeholder-slate-400 text-sm ${formError === 'customName' ? 'border-red-400 ring-1 ring-red-400' : 'border-slate-300'}`}
                                placeholder="Details..."
                            />
                        </div>
                    )}

                    {/* Rate Input */}
                    <div className={`md:col-span-${isOthers ? '2' : '3'}`}>
                        <label className="block text-xs text-slate-600 mb-1 font-medium">Rate (₹/kg)</label>
                        {transactionType === 'SALE' ? (
                            <input 
                            type="number" 
                            value={manualRate !== '' ? manualRate : (activeRate > 0 ? activeRate : '')}
                            onChange={e => setManualRate(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && weightInputRef.current?.focus()}
                            placeholder={activeRate.toString()}
                            className="w-full p-3 bg-white text-slate-900 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-center"
                            />
                        ) : (
                            <div className="w-full p-3 bg-slate-100 border border-slate-300 rounded-lg text-slate-500 cursor-not-allowed font-mono text-center font-bold">
                            {activeRate.toFixed(2)}
                            </div>
                        )}
                    </div>

                    {/* Weight Input */}
                    <div className={`md:col-span-${isOthers ? '2' : '3'}`}>
                        <label className="block text-xs text-slate-600 mb-1 font-medium">Weight (Kg)</label>
                        <input 
                            ref={weightInputRef}
                            type="number" 
                            value={weight}
                            onChange={e => {
                                setWeight(e.target.value);
                                if (formError === 'weight') setFormError(null);
                            }}
                            className={`w-full p-3 bg-white text-slate-900 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-lg text-center ${formError === 'weight' ? 'border-red-500 ring-2 ring-red-500' : 'border-slate-300'}`}
                            placeholder="0.00"
                            step="0.01"
                            min="0"
                            inputMode="decimal"
                            onKeyDown={(e) => e.key === 'Enter' && addItem()}
                        />
                    </div>

                    {/* Add Button */}
                    <div className="md:col-span-2">
                        <button 
                            onClick={addItem}
                            className={`w-full p-3 font-bold rounded-lg transition-transform active:scale-95 flex justify-center items-center text-white shadow-lg
                            ${isPurchase ? 'bg-blue-600 hover:bg-blue-500' : 'bg-emerald-600 hover:bg-emerald-500'}
                            `}
                        >
                            <Plus size={24} />
                            <span className="md:hidden ml-2">Add</span>
                        </button>
                    </div>
                </div>

                {/* Footer of Card */}
                <div className="mt-4 pt-3 border-t border-slate-100 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-2">
                    <div className="flex flex-col">
                        <span className="text-[10px] uppercase tracking-wider text-slate-400 font-bold">Current Line Item</span>
                        <span className="text-xl font-bold text-slate-800">₹{currentAmount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                    </div>
                    <span className="flex items-center text-amber-600 text-xs bg-amber-50 border border-amber-100 px-2 py-1 rounded font-medium">
                        <AlertCircle size={12} className="mr-1"/> 
                        {isPurchase ? 'Admin Fixed Rate' : 'Market Rate Check'}
                    </span>
                </div>
            </div>
        </div>

        {/* Right Column: Invoice Summary */}
        <div className="lg:col-span-1 space-y-4">
             <div className="bg-white rounded-xl shadow-sm border border-slate-200 flex flex-col h-full overflow-hidden">
                <div className="p-4 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
                    <h3 className="font-bold text-slate-700">Invoice Items</h3>
                    <span className="bg-slate-200 text-slate-600 text-xs px-2 py-1 rounded-full font-bold">{billItems.length}</span>
                </div>

                <div className="flex-1 overflow-y-auto min-h-[200px] max-h-[400px]">
                    {billItems.length > 0 ? (
                        <div className="divide-y divide-slate-100">
                            {billItems.map((item) => (
                                <div key={item.id} className="p-3 hover:bg-slate-50 flex justify-between items-center group">
                                    <div className="flex-1">
                                        <div className="font-bold text-slate-800 text-sm">{item.itemName}</div>
                                        <div className="text-xs text-slate-500">
                                            {item.totalWeight || item.weight} kg × ₹{item.rate}
                                        </div>
                                    </div>
                                    <div className="text-right mx-3">
                                        <div className="font-bold text-slate-800 text-sm">₹{item.amount.toFixed(2)}</div>
                                    </div>
                                    <button 
                                        onClick={() => removeItem(item.id)}
                                        className="text-slate-300 hover:text-red-500 transition p-1"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 space-y-2">
                             <div className="w-12 h-12 rounded-full bg-slate-100 flex items-center justify-center">
                                <Plus size={24} className="opacity-50"/>
                             </div>
                             <p className="text-sm">Add items to bill</p>
                        </div>
                    )}
                </div>

                <div className="p-4 bg-slate-50 border-t border-slate-200">
                    {/* Customer Summary in Right Panel */}
                    {customerName && (
                        <div className="mb-4 p-3 bg-white border border-slate-200 rounded-lg">
                            <div className="flex justify-between items-center mb-1">
                                <span className="text-[10px] uppercase font-bold text-slate-400 tracking-wider">Bill To</span>
                                <span className="text-[10px] text-blue-600 font-bold bg-blue-50 px-1.5 py-0.5 rounded cursor-pointer hover:bg-blue-100 transition" onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}>EDIT</span>
                            </div>
                            <div className="font-bold text-slate-800 text-sm truncate">{customerName}</div>
                            {customerPhone && <div className="text-xs text-slate-500">{customerPhone}</div>}
                        </div>
                    )}

                    <div className="flex justify-between items-center mb-2">
                        <span className="text-slate-600 font-medium">Total Weight</span>
                        <span className="text-lg font-bold text-slate-700">{totalWeight.toFixed(2)} kg</span>
                    </div>
                    <div className="flex justify-between items-center mb-4">
                        <span className="text-slate-600 font-medium">Total Amount</span>
                        <span className="text-2xl font-bold text-slate-900">₹{totalAmount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                    </div>
                    <button 
                        onClick={handleGenerateBill}
                        disabled={billItems.length === 0}
                        className={`w-full py-3 rounded-lg font-bold text-white shadow-md transition-all active:scale-95 flex items-center justify-center space-x-2
                            ${billItems.length === 0 ? 'bg-slate-300 cursor-not-allowed' : 
                              isPurchase ? 'bg-blue-600 hover:bg-blue-700' : 'bg-emerald-600 hover:bg-emerald-700'}
                        `}
                    >
                        <Save size={20} />
                        <span>Generate Invoice</span>
                    </button>
                </div>
             </div>
        </div>

      </div>

      {/* Confirmation Modal */}
      {showConfirmationModal && (
        <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-xl shadow-2xl max-w-sm w-full p-6 animate-in fade-in zoom-in duration-200">
                <div className="flex flex-col items-center text-center">
                    <div className="bg-amber-100 p-3 rounded-full mb-4">
                        <Lock className="text-amber-600" size={32} />
                    </div>
                    <h3 className="text-xl font-bold text-slate-800 mb-2">Confirm & Finalize</h3>

                    {/* Customer Summary in Modal */}
                    <div className="w-full bg-slate-50 border border-slate-100 rounded-lg p-3 mb-4 text-left">
                        <span className="text-[10px] uppercase font-bold text-slate-400 tracking-wider">Bill To</span>
                        <div className="font-bold text-slate-800 text-sm truncate">{customerName}</div>
                        {customerPhone && <div className="text-xs text-slate-500">{customerPhone}</div>}
                        {customerAddress && <div className="text-xs text-slate-400 mt-0.5 truncate">{customerAddress}</div>}
                    </div>

                    <div className="bg-red-50 border border-red-100 rounded-lg p-3 mb-6 text-left">
                        <h4 className="text-red-800 font-bold text-xs flex items-center uppercase tracking-wide mb-1">
                            <AlertCircle size={12} className="mr-1"/> Warning
                        </h4>
                        <p className="text-red-700 text-xs leading-relaxed">
                            Once confirmed, this bill becomes <strong>immutable</strong> (cannot be edited). 
                            If you need to make changes later, you must create a completely new bill.
                        </p>
                    </div>

                    <div className="flex w-full space-x-3">
                        <button 
                            onClick={() => setShowConfirmationModal(false)}
                            className="flex-1 py-2.5 border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 font-medium transition text-sm"
                        >
                            Cancel
                        </button>
                        <button 
                            onClick={finalizeBillGeneration}
                            className={`flex-1 py-2.5 text-white rounded-lg font-medium transition shadow-md text-sm ${isPurchase ? 'bg-blue-600 hover:bg-blue-700' : 'bg-emerald-600 hover:bg-emerald-700'}`}
                        >
                            Confirm Final Bill
                        </button>
                    </div>
                </div>
             </div>
        </div>
      )}

      {/* POS Success Modal */}
      {showSuccessModal && lastBill && (
        <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl max-w-md w-full p-6 text-center relative animate-in fade-in zoom-in duration-200">
            <div className="mx-auto w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mb-4">
              <CheckCircle className="text-green-600" size={32} />
            </div>

            <h2 className="text-xl font-bold text-slate-800 mb-1">Invoice Saved!</h2>
            <p className="text-slate-500 mb-6 text-sm">
              {lastBill.transactionType} #{lastBill.billNo}
            </p>

            <div className="grid grid-cols-2 gap-3 mb-4">
               <button 
                 onClick={() => generateBillPDF(lastBill, company, 'print')}
                 className="flex flex-col items-center justify-center p-3 bg-slate-50 hover:bg-slate-100 rounded-xl border border-slate-200 transition"
               >
                 <Printer size={24} className="text-slate-700 mb-2" />
                 <span className="font-medium text-slate-700 text-xs">Print</span>
               </button>

               <button 
                 onClick={() => generateBillPDF(lastBill, company, 'download')}
                 className="flex flex-col items-center justify-center p-3 bg-slate-50 hover:bg-slate-100 rounded-xl border border-slate-200 transition"
               >
                 <FileDown size={24} className="text-slate-700 mb-2" />
                 <span className="font-medium text-slate-700 text-xs">Download</span>
               </button>
            </div>

            <button 
              onClick={shareViaWhatsApp}
              className="w-full flex items-center justify-center space-x-2 py-3 bg-green-500 hover:bg-green-600 text-white rounded-xl font-bold transition mb-4 shadow-sm"
            >
              <Share2 size={18} />
              <span>WhatsApp</span>
            </button>

            <button 
              onClick={() => setShowSuccessModal(false)}
              className="text-slate-500 hover:text-slate-700 font-medium text-sm underline p-2"
            >
              Close & New Order
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

import jsPDF from 'jspdf';
import { Bill, CompanySettings } from '../types';

export const generateBillPDF = (bill: Bill, company: CompanySettings, action: 'download' | 'print' = 'download') => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a5',
  });

  const pageWidth = doc.internal.pageSize.getWidth();
  const pageHeight = doc.internal.pageSize.getHeight();
  const margin = 10;
  const contentWidth = pageWidth - (margin * 2);
  let y = margin;

  // Design Colors
  const colors = {
    primary: [37, 99, 235], // Blue 600
    slate: [51, 65, 85], // Slate 700
    gray: [100, 116, 139], // Slate 500
    lightGray: [248, 250, 252], // Slate 50
    border: [226, 232, 240], // Slate 200
  };

  // Helper for right aligned text
  const rightText = (text: string, y: number, x: number = pageWidth - margin, fontSize: number = 10, font: string = 'normal') => {
    doc.setFontSize(fontSize);
    doc.setFont('helvetica', font);
    doc.text(text, x, y, { align: 'right' });
  };

  // --- HEADER SECTION ---

  // Left: Company Logo/Name
  doc.setTextColor(colors.primary[0], colors.primary[1], colors.primary[2]);
  doc.setFontSize(16);
  doc.setFont('helvetica', 'bold');
  doc.text(company.name.toUpperCase(), margin, y + 6);

  // Right: Invoice Label
  const title = bill.transactionType === 'SALE' ? 'SALES INVOICE' : 'PURCHASE RECEIPT';
  doc.setTextColor(colors.slate[0], colors.slate[1], colors.slate[2]);
  doc.setFontSize(12);
  doc.setFont('helvetica', 'bold');
  doc.text(title, pageWidth - margin, y + 6, { align: 'right' });

  y += 14;

  // Company Details (Left) vs Bill Details (Right)
  doc.setTextColor(colors.gray[0], colors.gray[1], colors.gray[2]);
  doc.setFontSize(8);
  doc.setFont('helvetica', 'normal');

  // Company Info
  if (company.subtitle) {
      doc.text(company.subtitle, margin, y);
      y += 4;
  }
  doc.text(company.address, margin, y);
  doc.text(`Phone: ${company.phone}`, margin, y + 4);

  // Bill Info (Right Aligned - Reset Y to align with top of details)
  let infoY = y - (company.subtitle ? 4 : 0);
  doc.setTextColor(0);
  rightText(`Bill No: ${bill.billNo}`, infoY, pageWidth - margin, 9, 'bold');
  rightText(`Date: ${new Date(bill.date).toLocaleDateString()}`, infoY + 4, pageWidth - margin, 9, 'normal');

  doc.setTextColor(colors.gray[0], colors.gray[1], colors.gray[2]);
  rightText(`${new Date(bill.date).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}`, infoY + 8, pageWidth - margin, 8, 'normal');

  y += 10;

  // Divider
  doc.setDrawColor(colors.border[0], colors.border[1], colors.border[2]);
  doc.setLineWidth(0.5);
  doc.line(margin, y, pageWidth - margin, y);
  y += 6;

  // --- CUSTOMER SECTION ---
  const customerY = y;
  doc.setFontSize(9);
  doc.setTextColor(colors.gray[0], colors.gray[1], colors.gray[2]);
  doc.setFont('helvetica', 'bold');
  doc.text('Bill To:', margin, y);

  // Status Badge (Right side)
  const statusColor = bill.paymentStatus === 'Paid' ? [22, 163, 74] : [220, 38, 38];
  doc.setFillColor(statusColor[0], statusColor[1], statusColor[2]);
  doc.roundedRect(pageWidth - margin - 20, y - 4, 20, 5, 1, 1, 'F');
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(7);
  doc.setFont('helvetica', 'bold');
  doc.text(bill.paymentStatus.toUpperCase(), pageWidth - margin - 10, y - 0.5, { align: 'center' });

  y += 5;
  doc.setTextColor(0);
  doc.setFontSize(10);
  doc.setFont('helvetica', 'bold');
  doc.text(bill.customerName, margin, y);

  doc.setFontSize(9);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(colors.gray[0], colors.gray[1], colors.gray[2]);
  doc.text(bill.customerPhone, margin, y + 4);
  if (bill.customerAddress) {
    doc.text(bill.customerAddress, margin, y + 8);
    y += 4;
  }

  y += 12;

  // --- TABLE HEADER ---
  const cols = {
    item: margin + 2,
    rate: 85,
    weight: 110,
    amount: pageWidth - margin - 2
  };

  doc.setFillColor(colors.lightGray[0], colors.lightGray[1], colors.lightGray[2]);
  doc.rect(margin, y, contentWidth, 7, 'F');
  doc.setDrawColor(colors.border[0], colors.border[1], colors.border[2]);
  doc.line(margin, y, pageWidth - margin, y); 
  doc.line(margin, y + 7, pageWidth - margin, y + 7);

  doc.setTextColor(colors.slate[0], colors.slate[1], colors.slate[2]);
  doc.setFontSize(8);
  doc.setFont('helvetica', 'bold');
  doc.text('ITEM DESCRIPTION', cols.item, y + 4.5);
  doc.text('RATE', cols.rate, y + 4.5, { align: 'right' });
  doc.text('TOTAL WEIGHT', cols.weight, y + 4.5, { align: 'right' });
  doc.text('AMOUNT', cols.amount, y + 4.5, { align: 'right' });

  y += 10;

  // --- TABLE ROWS ---
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(0);
  let totalWeight = 0;

  bill.items.forEach((item, index) => {
    const itemName = item.itemName || item.customName || 'Item';

    // Auto wrap text
    const maxNameWidth = 60;
    const splitText = doc.splitTextToSize(itemName, maxNameWidth);
    const rows = splitText.length;
    const rowHeight = Math.max(6, rows * 4 + 2);

    // Check page break
    if (y + rowHeight > pageHeight - 40) {
       doc.addPage();
       y = margin;
       // Optional: Redraw header here
    }

    doc.setFontSize(9);
    doc.text(splitText, cols.item, y);
    doc.text(item.rate.toFixed(2), cols.rate, y, { align: 'right' });

    const itemWeight = item.totalWeight || item.weight;
    doc.text(itemWeight.toFixed(2), cols.weight, y, { align: 'right' });

    doc.setFont('helvetica', 'bold');
    doc.text(item.amount.toFixed(2), cols.amount, y, { align: 'right' });
    doc.setFont('helvetica', 'normal');

    totalWeight += itemWeight;
    y += rowHeight;

    // Light separator line
    doc.setDrawColor(241, 245, 249);
    doc.line(margin, y - rowHeight + 2, pageWidth - margin, y - rowHeight + 2);
  });

  y += 2;

  // --- SUMMARY SECTION ---

  // Summary Box Background
  const summaryHeight = 22;
  // Check page break for summary
  if (y + summaryHeight > pageHeight - 30) {
    doc.addPage();
    y = margin;
  }

  // Draw background for total
  doc.setFillColor(colors.lightGray[0], colors.lightGray[1], colors.lightGray[2]);
  doc.roundedRect(pageWidth - margin - 60, y, 60, summaryHeight, 2, 2, 'F');

  // Stats inside box
  let sy = y + 5;
  doc.setTextColor(colors.gray[0], colors.gray[1], colors.gray[2]);
  doc.setFontSize(8);

  doc.text(`Total Items:`, pageWidth - margin - 55, sy);
  doc.text(`${bill.items.length}`, pageWidth - margin - 5, sy, { align: 'right' });

  sy += 5;
  doc.text(`Total Weight:`, pageWidth - margin - 55, sy);
  doc.text(`${totalWeight.toFixed(2)} Kg`, pageWidth - margin - 5, sy, { align: 'right' });

  // Divider inside box
  sy += 3;
  doc.setDrawColor(colors.border[0], colors.border[1], colors.border[2]);
  doc.line(pageWidth - margin - 55, sy, pageWidth - margin - 5, sy);

  // Grand Total
  sy += 6;
  doc.setTextColor(colors.primary[0], colors.primary[1], colors.primary[2]);
  doc.setFontSize(11);
  doc.setFont('helvetica', 'bold');
  doc.text(`Total:`, pageWidth - margin - 55, sy);
  doc.text(`Rs. ${bill.totalAmount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}`, pageWidth - margin - 5, sy, { align: 'right' });

  // --- FOOTER & SIGNATURE ---

  // Push footer to bottom
  const footerH = 30;
  let footerY = pageHeight - margin - footerH;

  // If content overlaps footer, add page
  if (y + summaryHeight + 10 > footerY) {
      doc.addPage();
      footerY = pageHeight - margin - footerH;
  }

  // Signature
  let sigY = footerY;
  if (company.signatureUrl) {
    try {
        doc.addImage(company.signatureUrl, 'PNG', pageWidth - margin - 35, sigY, 30, 10);
        sigY += 10;
    } catch(e) { /* ignore */ }
  } else {
    sigY += 10;
  }

  doc.setTextColor(0);
  doc.setFontSize(7);
  doc.setFont('helvetica', 'normal');
  doc.text('Authorized Signature', pageWidth - margin - 20, sigY + 4, { align: 'center' });

  // Bottom Branding
  doc.setFontSize(7);
  doc.setTextColor(150);
  const bottomY = pageHeight - 8;
  doc.text('Thank you for your business!', pageWidth / 2, bottomY - 3, { align: 'center' });
  doc.text('Generated by Apna Kabadi Manager', pageWidth / 2, bottomY, { align: 'center' });

  // Output
  if (action === 'print') {
    doc.autoPrint();
    const blob = doc.output('bloburl');
    window.open(blob, '_blank');
  } else {
    doc.save(`${bill.transactionType}_${bill.billNo}.pdf`);
  }
};

export const generateSummaryReportPDF = (bills: Bill[], company: CompanySettings, startDate: string, endDate: string) => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a4',
  });

  const margin = 15;
  const pageWidth = 210;
  const contentWidth = pageWidth - (margin * 2);
  let y = margin;

  // Colors
  const colors = {
    primary: [37, 99, 235],
    slate: [51, 65, 85],
    light: [248, 250, 252]
  };

  // --- HEADER ---
  doc.setFontSize(20);
  doc.setFont('helvetica', 'bold');
  doc.setTextColor(colors.primary[0], colors.primary[1], colors.primary[2]);
  doc.text(company.name.toUpperCase(), margin, y);

  y += 8;
  doc.setFontSize(12);
  doc.setTextColor(100);
  doc.text("Business Summary Report", margin, y);
  doc.setTextColor(0);

  doc.setFontSize(10);
  doc.text(`Period: ${new Date(startDate).toLocaleDateString()} to ${new Date(endDate).toLocaleDateString()}`, pageWidth - margin, y - 8, { align: 'right' });
  doc.text(`Generated: ${new Date().toLocaleDateString()}`, pageWidth - margin, y, { align: 'right' });

  y += 10;
  doc.setDrawColor(200);
  doc.line(margin, y, pageWidth - margin, y);
  y += 10;

  // --- SUMMARY CARDS ---
  const totalPurchases = bills.filter(b => b.transactionType === 'PURCHASE').reduce((sum, b) => sum + b.totalAmount, 0);
  const totalSales = bills.filter(b => b.transactionType === 'SALE').reduce((sum, b) => sum + b.totalAmount, 0);
  const netFlow = totalSales - totalPurchases;

  // Draw Summary Boxes
  const boxWidth = contentWidth / 3 - 4;

  // Helper to draw box
  const drawBox = (x: number, title: string, amount: number, color: number[]) => {
      doc.setFillColor(color[0], color[1], color[2]); // BG
      doc.roundedRect(x, y, boxWidth, 25, 2, 2, 'F');

      doc.setFontSize(9);
      doc.setTextColor(colors.slate[0], colors.slate[1], colors.slate[2]);
      doc.text(title, x + 5, y + 8);

      doc.setFontSize(14);
      doc.setFont('helvetica', 'bold');
      doc.setTextColor(0);
      doc.text(`Rs. ${amount.toLocaleString('en-IN')}`, x + 5, y + 18);
  };

  drawBox(margin, "Total Purchases", totalPurchases, [239, 246, 255]);
  drawBox(margin + boxWidth + 6, "Total Sales", totalSales, [236, 253, 245]);
  drawBox(margin + (boxWidth * 2) + 12, "Net Cash Flow", netFlow, [255, 251, 235]);

  y += 35;

  // --- TRANSACTIONS TABLE ---
  doc.setFontSize(12);
  doc.setTextColor(colors.slate[0], colors.slate[1], colors.slate[2]);
  doc.setFont('helvetica', 'bold');
  doc.text("Transaction History", margin, y);
  y += 6;

  // Headers
  const cols = {
    date: margin + 2,
    billNo: margin + 30,
    type: margin + 70,
    customer: margin + 100,
    amount: pageWidth - margin - 2
  };

  doc.setFillColor(colors.slate[0], colors.slate[1], colors.slate[2]);
  doc.rect(margin, y, contentWidth, 9, 'F');
  doc.setTextColor(255);
  doc.setFontSize(9);
  doc.text("Date", cols.date, y + 6);
  doc.text("Bill No", cols.billNo, y + 6);
  doc.text("Type", cols.type, y + 6);
  doc.text("Customer", cols.customer, y + 6);
  doc.text("Amount", cols.amount, y + 6, { align: 'right' });

  y += 10;

  // Rows
  doc.setTextColor(0);
  doc.setFont('helvetica', 'normal');

  // Sort bills by date desc
  const sortedBills = [...bills].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  sortedBills.forEach((bill, index) => {
    if (y > 270) {
      doc.addPage();
      y = 20;
    }

    if (index % 2 !== 0) {
      doc.setFillColor(colors.light[0], colors.light[1], colors.light[2]);
      doc.rect(margin, y, contentWidth, 8, 'F');
    }

    doc.text(new Date(bill.date).toLocaleDateString(), cols.date, y + 5);
    doc.text(bill.billNo, cols.billNo, y + 5);

    // Type colored
    if (bill.transactionType === 'PURCHASE') {
      doc.setTextColor(37, 99, 235);
      doc.text("PURCHASE", cols.type, y + 5);
    } else {
      doc.setTextColor(5, 150, 105);
      doc.text("SALE", cols.type, y + 5);
    }

    doc.setTextColor(0);
    doc.text(bill.customerName.substring(0, 20), cols.customer, y + 5);
    doc.text(bill.totalAmount.toLocaleString('en-IN', { minimumFractionDigits: 2 }), cols.amount, y + 5, { align: 'right' });

    y += 8;
  });

  doc.save(`Report_${startDate}_${endDate}.pdf`);
};

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { useApp } from '../../context/AppContext';
import { BillItem, Bill, TransactionType, PaymentStatus, Customer } from '../../types';
import { generateBillPDF } from '../../utils/pdfGenerator';
import { Plus, Trash2, RotateCcw, Save, AlertCircle, Printer, Share2, CheckCircle, FileDown, Search, ArrowRightLeft, User, MapPin, Phone, Lock, Briefcase } from 'lucide-react';

export const Billing = () => {
  const { items, company, addBill, currentUser, customers, addCustomer, leads } = useApp();

  // Refs for Focus Management
  const itemSelectRef = useRef<HTMLSelectElement>(null);
  const weightInputRef = useRef<HTMLInputElement>(null);
  const customNameRef = useRef<HTMLInputElement>(null);

  // Transaction Mode
  const [transactionType, setTransactionType] = useState<TransactionType>('PURCHASE');

  // Form State
  const [customerSearch, setCustomerSearch] = useState('');
  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);
  const [selectedCustomerId, setSelectedCustomerId] = useState<string | undefined>(undefined);

  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('Paid');

  const [billItems, setBillItems] = useState<BillItem[]>([]);

  // Item Entry State
  // Default to first item if available
  const [selectedItemId, setSelectedItemId] = useState(items.length > 0 ? items[0].id : '');
  const [weight, setWeight] = useState('');
  const [customName, setCustomName] = useState('');
  const [manualRate, setManualRate] = useState(''); // For Sales
  const [formError, setFormError] = useState<string | null>(null);

  // Modal States
  const [lastBill, setLastBill] = useState<Bill | null>(null);
  const [showSuccessModal, setShowSuccessModal] = useState(false);
  const [showConfirmationModal, setShowConfirmationModal] = useState(false);

  // Effect to ensure selectedItemId is valid on load
  useEffect(() => {
    if (!selectedItemId && items.length > 0) {
        setSelectedItemId(items[0].id);
    }
  }, [items, selectedItemId]);

  // Derived state
  const selectedItemData = items.find(i => i.id === selectedItemId);
  const isOthers = selectedItemData?.name === 'Others' || selectedItemData?.category === 'Others';

  // Rate Logic: Purchase = Fixed Admin Rate, Sale = Manual/Negotiated Rate (Default to Admin Rate)
  const activeRate = transactionType === 'SALE' && manualRate !== ''
    ? parseFloat(manualRate) 
    : (selectedItemData?.rate || 0);

  const currentAmount = (parseFloat(weight) || 0) * activeRate;
  const totalAmount = billItems.reduce((sum, item) => sum + item.amount, 0);
  const totalWeight = billItems.reduce((sum, item) => sum + (item.totalWeight || item.weight), 0);

  // --- UNIFIED CONTACT SEARCH LOGIC ---
  // Combine Customers and Leads into one searchable list
  // Priority: Customer > Lead (based on phone number)
  const allContacts = useMemo(() => {
    const combined = new Map<string, { id?: string, name: string, phone: string, address: string, type: 'Customer' | 'Lead' }>();

    // 1. Add Existing Customers first
    customers.forEach(c => {
      combined.set(c.phone, { ...c, type: 'Customer' });
    });

    // 2. Add Leads (only if phone doesn't exist in customers)
    leads.forEach(l => {
      if (!combined.has(l.phone)) {
        combined.set(l.phone, {
          id: l.id,
          name: l.name,
          phone: l.phone,
          address: l.address,
          type: 'Lead'
        });
      }
    });

    return Array.from(combined.values());
  }, [customers, leads]);

  // Filter the unified list
  const filteredContacts = allContacts.filter(c => 
    c.name.toLowerCase().includes(customerSearch.toLowerCase()) || 
    c.phone.includes(customerSearch)
  );

  const selectContact = (contact: { id?: string, name: string, phone: string, address: string, type: 'Customer' | 'Lead' }) => {
    setCustomerName(contact.name);
    setCustomerPhone(contact.phone);
    setCustomerAddress(contact.address);
    // Only set ID if it's already a customer, otherwise leave undefined so a new customer is created on save
    setSelectedCustomerId(contact.type === 'Customer' ? contact.id : undefined);
    setCustomerSearch('');
    setShowCustomerSuggestions(false);
  };

  const addItem = () => {
    // Validation
    if (!selectedItemId) return;
    if (!weight || parseFloat(weight) <= 0) {
      setFormError('weight');
      weightInputRef.current?.focus();
      return;
    }
    if (isOthers && !customName) {
      setFormError('customName');
      customNameRef.current?.focus();
      return;
    }

    setFormError(null);

    const resolvedName = isOthers && customName 
      ? `Others (${customName})` 
      : (selectedItemData?.name || 'Unknown');

    const weightVal = parseFloat(weight);

    const newItem: BillItem = {
      id: Date.now().toString(),
      itemId: selectedItemId,
      itemName: resolvedName,
      customName: isOthers ? customName : undefined,
      rate: activeRate,
      weight: weightVal,
      totalWeight: weightVal,
      amount: currentAmount
    };

    setBillItems([...billItems, newItem]);

    // Reset inputs
    setWeight('');
    setCustomName('');
    setManualRate('');

    // Focus logic for rapid entry
    if (window.innerWidth > 768) {
        // Desktop: Go back to item select
        itemSelectRef.current?.focus();
    } else {
        // Mobile: Blur to close keyboard
        (document.activeElement as HTMLElement)?.blur();
    }
  };

  const removeItem = (id: string) => {
    setBillItems(billItems.filter(item => item.id !== id));
  };

  const handleGenerateBill = () => {
    if (!customerName || billItems.length === 0) {
      alert("Please fill customer details and add at least one item.");
      return;
    }
    setShowConfirmationModal(true);
  };

  const finalizeBillGeneration = () => {
    // Auto-save new customer if phone doesn't exist
    // This effectively converts a 'Lead' to a 'Customer' automatically
    if (customerPhone && !customers.some(c => c.phone === customerPhone)) {
      addCustomer({
        id: Date.now().toString(),
        name: customerName,
        phone: customerPhone,
        address: customerAddress
      });
    }

    // Create unique bill number (INV-YYYYMMDD-XXXX)
    const dateStr = new Date().toISOString().slice(0,10).replace(/-/g, '');
    const randomSuffix = Math.floor(1000 + Math.random() * 9000);
    const uniqueBillNo = `INV-${dateStr}-${randomSuffix}`;

    const bill: Bill = {
      id: Date.now().toString(),
      billNo: uniqueBillNo,
      transactionType,
      customerId: selectedCustomerId,
      customerName,
      customerPhone,
      customerAddress,
      items: billItems,
      totalAmount,
      paymentStatus,
      date: new Date().toISOString(),
      staffName: currentUser?.name || 'Staff',
      isFinalized: true, // Mark bill as immutable
    };

    addBill(bill);
    setLastBill(bill);

    // Clear form
    setCustomerName('');
    setCustomerPhone('');
    setCustomerAddress('');
    setSelectedCustomerId(undefined);
    setBillItems([]);
    setWeight('');
    setCustomName('');
    setManualRate('');
    setPaymentStatus('Paid');

    setShowConfirmationModal(false);
    setShowSuccessModal(true);
  };

  const shareViaWhatsApp = () => {
    if (!lastBill) return;
    const type = lastBill.transactionType === 'PURCHASE' ? 'Purchase Receipt' : 'Sales Invoice';
    const text = `*${company.name}*\n${type} #${lastBill.billNo}\nDate: ${new Date(lastBill.date).toLocaleDateString()}\nStatus: ${lastBill.paymentStatus}\n\nTotal Amount: *₹${lastBill.totalAmount.toFixed(2)}*\n\nThank you!`;
    const url = `https://wa.me/${lastBill.customerPhone}?text=${encodeURIComponent(text)}`;
    window.open(url, '_blank');
  };

  const isPurchase = transactionType === 'PURCHASE';

  return (
    <div className="max-w-7xl mx-auto space-y-4 lg:space-y-6 pb-20 lg:pb-0">

      {/* Top Bar: Transaction Type Toggle */}
      <div className="bg-white p-3 lg:p-4 rounded-xl shadow-sm border border-slate-200">
        <div className="flex flex-col sm:flex-row justify-between items-center gap-3">
            <div className="flex items-center space-x-2 text-slate-600">
                <ArrowRightLeft size={20} />
                <span className="font-bold">Mode</span>
            </div>
            <div className="flex w-full sm:w-auto bg-slate-100 p-1 rounded-lg">
                <button 
                    onClick={() => setTransactionType('PURCHASE')}
                    className={`flex-1 sm:flex-none px-4 py-2 rounded-md font-bold text-sm transition-all shadow-sm ${transactionType === 'PURCHASE' ? 'bg-blue-600 text-white' : 'text-slate-500 hover:text-slate-700 bg-transparent shadow-none'}`}
                >
                    Purchase (Buy)
                </button>
                <button 
                    onClick={() => setTransactionType('SALE')}
                    className={`flex-1 sm:flex-none px-4 py-2 rounded-md font-bold text-sm transition-all shadow-sm ${transactionType === 'SALE' ? 'bg-emerald-600 text-white' : 'text-slate-500 hover:text-slate-700 bg-transparent shadow-none'}`}
                >
                    Sale (Sell)
                </button>
            </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 lg:gap-6 items-start">

        {/* Left Column: Customer & Item Entry */}
        <div className="lg:col-span-2 space-y-4 lg:space-y-6">

            {/* Customer Details Card */}
            <div className="bg-white p-4 lg:p-6 rounded-xl shadow-sm border border-slate-200">
                <div className="flex justify-between items-center mb-4 border-b border-slate-100 pb-3">
                    <h3 className="font-bold text-slate-800 flex items-center gap-2">
                        <User size={18} className="text-slate-400"/>
                        Customer Details
                    </h3>
                    {selectedCustomerId && <span className="text-[10px] uppercase font-bold bg-green-100 text-green-700 px-2 py-1 rounded-full">Existing</span>}
                </div>

                {/* Customer Search Dropdown */}
                <div className="relative mb-4">
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                        <input 
                            type="text"
                            value={customerSearch}
                            onChange={(e) => {
                                setCustomerSearch(e.target.value);
                                setShowCustomerSuggestions(true);
                            }}
                            onFocus={() => setShowCustomerSuggestions(true)}
                            onBlur={() => setTimeout(() => setShowCustomerSuggestions(false), 200)}
                            placeholder="Search Customer or Lead..."
                            className="w-full pl-10 pr-4 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 text-slate-900 text-sm"
                        />
                    </div>
                    {showCustomerSuggestions && customerSearch && (
                        <div className="absolute z-30 w-full bg-white mt-1 border border-slate-200 rounded-lg shadow-xl max-h-48 overflow-y-auto">
                        {filteredContacts.length > 0 ? (
                            filteredContacts.map((c, idx) => (
                                <div 
                                key={idx} 
                                onClick={() => selectContact(c)}
                                className="p-3 hover:bg-slate-50 cursor-pointer border-b border-slate-100 last:border-0 flex justify-between items-center"
                                >
                                    <div>
                                        <p className="font-bold text-slate-800 text-sm">{c.name}</p>
                                        <p className="text-xs text-slate-500">{c.phone}</p>
                                    </div>
                                    <span className={`text-[10px] uppercase font-bold px-2 py-0.5 rounded ${
                                        c.type === 'Customer' ? 'bg-green-100 text-green-700' : 'bg-blue-100 text-blue-700'
                                    }`}>
                                        {c.type === 'Customer' ? 'Existing' : 'Lead'}
                                    </span>
                                </div>
                            ))
                        ) : (
                            <div className="p-3 text-sm text-slate-500">No matching contacts found.</div>
                        )}
                        </div>
                    )}
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    <div className="relative">
                        <User className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                        <input 
                            type="text" 
                            value={customerName}
                            onChange={e => setCustomerName(e.target.value)}
                            className="w-full pl-9 pr-3 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900 text-sm"
                            placeholder="Name *"
                        />
                    </div>
                    <div className="relative">
                        <Phone className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                        <input 
                            type="tel" 
                            value={customerPhone}
                            onChange={e => setCustomerPhone(e.target.value)}
                            className="w-full pl-9 pr-3 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900 text-sm"
                            placeholder="Phone"
                        />
                    </div>
                    <div className="md:col-span-2 relative">
                        <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                        <input 
                            type="text" 
                            value={customerAddress}
                            onChange={e => setCustomerAddress(e.target.value)}
                            className="w-full pl-9 pr-3 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900 text-sm"
                            placeholder="Address / Area"
                        />
                    </div>
                </div>
            </div>

            {/* Item Entry Card (Light Theme) */}
            <div className={`p-4 lg:p-6 rounded-xl shadow-lg transition-colors duration-300 bg-white border-t-4 ${isPurchase ? 'border-blue-600' : 'border-emerald-600'}`}>
                <div className="flex justify-between items-center mb-4">
                    <h3 className={`font-bold ${isPurchase ? 'text-blue-700' : 'text-emerald-700'}`}>
                    {isPurchase ? 'Purchase Item' : 'Sell Item'}
                    </h3>
                    <span className={`text-[10px] uppercase font-bold px-2 py-1 rounded border ${isPurchase ? 'bg-blue-50 text-blue-700 border-blue-200' : 'bg-emerald-50 text-emerald-700 border-emerald-200'}`}>
                        Stock: {isPurchase ? 'IN' : 'OUT'}
                    </span>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-12 gap-4 items-end">

                    {/* Item Select */}
                    <div className={`md:col-span-${isOthers ? '3' : '4'}`}>
                        <label className="block text-xs text-slate-600 mb-1 font-medium">Item Name</label>
                        <select 
                            ref={itemSelectRef}
                            value={selectedItemId}
                            onChange={e => {
                                setSelectedItemId(e.target.value);
                                setCustomName('');
                                setManualRate('');
                            }}
                            className="w-full p-3 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-slate-900 text-sm"
                        >
                            {items.map(item => (
                            <option key={item.id} value={item.id}>
                                {item.name}
                            </option>
                            ))}
                        </select>
                    </div>

                    {/* Custom Description (Conditional) */}
                    {isOthers && (
                        <div className="md:col-span-3">
                            <label className="block text-xs text-slate-600 mb-1 font-medium">Description</label>
                            <input 
                                ref={customNameRef}
                                type="text" 
                                value={customName}
                                onChange={e => setCustomName(e.target.value)}
                                onKeyDown={(e) => e.key === 'Enter' && weightInputRef.current?.focus()}
                                className={`w-full p-3 bg-white border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-slate-900 placeholder-slate-400 text-sm ${formError === 'customName' ? 'border-red-400 ring-1 ring-red-400' : 'border-slate-300'}`}
                                placeholder="Details..."
                            />
                        </div>
                    )}

                    {/* Rate Input */}
                    <div className={`md:col-span-${isOthers ? '2' : '3'}`}>
                        <label className="block text-xs text-slate-600 mb-1 font-medium">Rate (₹/kg)</label>
                        {transactionType === 'SALE' ? (
                            <input 
                            type="number" 
                            value={manualRate !== '' ? manualRate : (activeRate > 0 ? activeRate : '')}
                            onChange={e => setManualRate(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && weightInputRef.current?.focus()}
                            placeholder={activeRate.toString()}
                            className="w-full p-3 bg-white text-slate-900 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-center"
                            />
                        ) : (
                            <div className="w-full p-3 bg-slate-100 border border-slate-300 rounded-lg text-slate-500 cursor-not-allowed font-mono text-center font-bold">
                            {activeRate.toFixed(2)}
                            </div>
                        )}
                    </div>

                    {/* Weight Input */}
                    <div className={`md:col-span-${isOthers ? '2' : '3'}`}>
                        <label className="block text-xs text-slate-600 mb-1 font-medium">Weight (Kg)</label>
                        <input 
                            ref={weightInputRef}
                            type="number" 
                            value={weight}
                            onChange={e => {
                                setWeight(e.target.value);
                                if (formError === 'weight') setFormError(null);
                            }}
                            className={`w-full p-3 bg-white text-slate-900 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-lg text-center ${formError === 'weight' ? 'border-red-500 ring-2 ring-red-500' : 'border-slate-300'}`}
                            placeholder="0.00"
                            step="0.01"
                            min="0"
                            inputMode="decimal"
                            onKeyDown={(e) => e.key === 'Enter' && addItem()}
                        />
                    </div>

                    {/* Add Button */}
                    <div className="md:col-span-2">
                        <button 
                            onClick={addItem}
                            className={`w-full p-3 font-bold rounded-lg transition-transform active:scale-95 flex justify-center items-center text-white shadow-lg
                            ${isPurchase ? 'bg-blue-600 hover:bg-blue-500' : 'bg-emerald-600 hover:bg-emerald-500'}
                            `}
                        >
                            <Plus size={24} />
                            <span className="md:hidden ml-2">Add</span>
                        </button>
                    </div>
                </div>

                {/* Footer of Card */}
                <div className="mt-4 pt-3 border-t border-slate-100 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-2">
                    <div className="flex flex-col">
                        <span className="text-[10px] uppercase tracking-wider text-slate-400 font-bold">Current Line Item</span>
                        <span className="text-xl font-bold text-slate-800">₹{currentAmount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                    </div>
                    <span className="flex items-center text-amber-600 text-xs bg-amber-50 border border-amber-100 px-2 py-1 rounded font-medium">
                        <AlertCircle size={12} className="mr-1"/> 
                        {isPurchase ? 'Admin Fixed Rate' : 'Market Rate Check'}
                    </span>
                </div>
            </div>
        </div>

        {/* Right Column: Invoice Summary */}
        <div className="lg:col-span-1 space-y-4">
             <div className="bg-white rounded-xl shadow-sm border border-slate-200 flex flex-col h-full overflow-hidden">
                <div className="p-4 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
                    <h3 className="font-bold text-slate-700">Invoice Items</h3>
                    <span className="bg-slate-200 text-slate-600 text-xs px-2 py-1 rounded-full font-bold">{billItems.length}</span>
                </div>

                <div className="flex-1 overflow-y-auto min-h-[200px] max-h-[400px]">
                    {billItems.length > 0 ? (
                        <div className="divide-y divide-slate-100">
                            {billItems.map((item) => (
                                <div key={item.id} className="p-3 hover:bg-slate-50 flex justify-between items-center group">
                                    <div className="flex-1">
                                        <div className="font-bold text-slate-800 text-sm">{item.itemName}</div>
                                        <div className="text-xs text-slate-500">
                                            {item.totalWeight || item.weight} kg × ₹{item.rate}
                                        </div>
                                    </div>
                                    <div className="text-right mx-3">
                                        <div className="font-bold text-slate-800 text-sm">₹{item.amount.toFixed(2)}</div>
                                    </div>
                                    <button 
                                        onClick={() => removeItem(item.id)}
                                        className="text-slate-300 hover:text-red-500 transition p-1"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 space-y-2">
                             <div className="w-12 h-12 rounded-full bg-slate-100 flex items-center justify-center">
                                <Plus size={24} className="opacity-50"/>
                             </div>
                             <p className="text-sm">Add items to bill</p>
                        </div>
                    )}
                </div>

                <div className="p-4 bg-slate-50 border-t border-slate-200">
                    {/* Customer Summary in Right Panel */}
                    {customerName && (
                        <div className="mb-4 p-3 bg-white border border-slate-200 rounded-lg">
                            <div className="flex justify-between items-center mb-1">
                                <span className="text-[10px] uppercase font-bold text-slate-400 tracking-wider">Bill To</span>
                                <span className="text-[10px] text-blue-600 font-bold bg-blue-50 px-1.5 py-0.5 rounded cursor-pointer hover:bg-blue-100 transition" onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}>EDIT</span>
                            </div>
                            <div className="font-bold text-slate-800 text-sm truncate">{customerName}</div>
                            {customerPhone && <div className="text-xs text-slate-500">{customerPhone}</div>}
                        </div>
                    )}

                    <div className="flex justify-between items-center mb-2">
                        <span className="text-slate-600 font-medium">Total Weight</span>
                        <span className="text-lg font-bold text-slate-700">{totalWeight.toFixed(2)} kg</span>
                    </div>
                    <div className="flex justify-between items-center mb-4">
                        <span className="text-slate-600 font-medium">Total Amount</span>
                        <span className="text-2xl font-bold text-slate-900">₹{totalAmount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                    </div>
                    <button 
                        onClick={handleGenerateBill}
                        disabled={billItems.length === 0}
                        className={`w-full py-3 rounded-lg font-bold text-white shadow-md transition-all active:scale-95 flex items-center justify-center space-x-2
                            ${billItems.length === 0 ? 'bg-slate-300 cursor-not-allowed' : 
                              isPurchase ? 'bg-blue-600 hover:bg-blue-700' : 'bg-emerald-600 hover:bg-emerald-700'}
                        `}
                    >
                        <Save size={20} />
                        <span>Generate Invoice</span>
                    </button>
                </div>
             </div>
        </div>

      </div>

      {/* Confirmation Modal */}
      {showConfirmationModal && (
        <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-xl shadow-2xl max-w-sm w-full p-6 animate-in fade-in zoom-in duration-200">
                <div className="flex flex-col items-center text-center">
                    <div className="bg-amber-100 p-3 rounded-full mb-4">
                        <Lock className="text-amber-600" size={32} />
                    </div>
                    <h3 className="text-xl font-bold text-slate-800 mb-2">Confirm & Finalize</h3>

                    {/* Customer Summary in Modal */}
                    <div className="w-full bg-slate-50 border border-slate-100 rounded-lg p-3 mb-4 text-left">
                        <span className="text-[10px] uppercase font-bold text-slate-400 tracking-wider">Bill To</span>
                        <div className="font-bold text-slate-800 text-sm truncate">{customerName}</div>
                        {customerPhone && <div className="text-xs text-slate-500">{customerPhone}</div>}
                        {customerAddress && <div className="text-xs text-slate-400 mt-0.5 truncate">{customerAddress}</div>}
                    </div>

                    <div className="bg-red-50 border border-red-100 rounded-lg p-3 mb-6 text-left">
                        <h4 className="text-red-800 font-bold text-xs flex items-center uppercase tracking-wide mb-1">
                            <AlertCircle size={12} className="mr-1"/> Warning
                        </h4>
                        <p className="text-red-700 text-xs leading-relaxed">
                            Once confirmed, this bill becomes <strong>immutable</strong> (cannot be edited). 
                            If you need to make changes later, you must create a completely new bill.
                        </p>
                    </div>

                    <div className="flex w-full space-x-3">
                        <button 
                            onClick={() => setShowConfirmationModal(false)}
                            className="flex-1 py-2.5 border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 font-medium transition text-sm"
                        >
                            Cancel
                        </button>
                        <button 
                            onClick={finalizeBillGeneration}
                            className={`flex-1 py-2.5 text-white rounded-lg font-medium transition shadow-md text-sm ${isPurchase ? 'bg-blue-600 hover:bg-blue-700' : 'bg-emerald-600 hover:bg-emerald-700'}`}
                        >
                            Confirm Final Bill
                        </button>
                    </div>
                </div>
             </div>
        </div>
      )}

      {/* POS Success Modal */}
      {showSuccessModal && lastBill && (
        <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl max-w-md w-full p-6 text-center relative animate-in fade-in zoom-in duration-200">
            <div className="mx-auto w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mb-4">
              <CheckCircle className="text-green-600" size={32} />
            </div>

            <h2 className="text-xl font-bold text-slate-800 mb-1">Invoice Saved!</h2>
            <p className="text-slate-500 mb-6 text-sm">
              {lastBill.transactionType} #{lastBill.billNo}
            </p>

            <div className="grid grid-cols-2 gap-3 mb-4">
               <button 
                 onClick={() => generateBillPDF(lastBill, company, 'print')}
                 className="flex flex-col items-center justify-center p-3 bg-slate-50 hover:bg-slate-100 rounded-xl border border-slate-200 transition"
               >
                 <Printer size={24} className="text-slate-700 mb-2" />
                 <span className="font-medium text-slate-700 text-xs">Print</span>
               </button>

               <button 
                 onClick={() => generateBillPDF(lastBill, company, 'download')}
                 className="flex flex-col items-center justify-center p-3 bg-slate-50 hover:bg-slate-100 rounded-xl border border-slate-200 transition"
               >
                 <FileDown size={24} className="text-slate-700 mb-2" />
                 <span className="font-medium text-slate-700 text-xs">Download</span>
               </button>
            </div>

            <button 
              onClick={shareViaWhatsApp}
              className="w-full flex items-center justify-center space-x-2 py-3 bg-green-500 hover:bg-green-600 text-white rounded-xl font-bold transition mb-4 shadow-sm"
            >
              <Share2 size={18} />
              <span>WhatsApp</span>
            </button>

            <button 
              onClick={() => setShowSuccessModal(false)}
              className="text-slate-500 hover:text-slate-700 font-medium text-sm underline p-2"
            >
              Close & New Order
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export interface ScrapItem {
  id: string;
  name: string;
  rate: number;
  lastUpdated: string;
  category: 'Metal' | 'Paper' | 'Plastic' | 'Electronics' | 'Others';
}

export interface StockItem {
  itemId: string;
  itemName: string;
  purchased: number;
  sold: number;
  available: number;
}

export interface StaffMember {
  id: string;
  name: string;
  role: 'Manager' | 'Worker' | 'Driver';
  status: 'Active' | 'Inactive';
  phone: string;
  password?: string;
}

export interface Customer {
  id: string;
  name: string;
  phone: string;
  address: string;
}

export interface Lead {
  id: string;
  name: string;
  phone: string;
  address: string;
  status: 'New' | 'In Progress' | 'Converted' | 'Lost';
  assignedTo: string; // Staff ID
  createdAt: string;
  notes?: string;
}

export interface LeaveRequest {
  id: string;
  staffId?: string;
  staffName: string;
  fromDate: string;
  toDate: string;
  reason: string;
  status: 'Pending' | 'Approved' | 'Rejected';
}

export interface Reimbursement {
  id: string;
  staffId: string;
  staffName: string;
  date: string;
  amount: number;
  description: string;
  status: 'Pending' | 'Approved' | 'Rejected';
}

export interface SalaryPayment {
  id: string;
  staffId: string;
  staffName: string;
  amount: number;
  paymentDate: string;
  type: 'Salary' | 'Advance' | 'Bonus';
  remarks?: string;
}

export interface CompanySettings {
  name: string;
  subtitle: string;
  address: string;
  phone: string;
  signatureUrl: string | null; // Base64 string for demo
}

export interface BillItem {
  id: string; // unique row id
  itemId: string; // ref to ScrapItem
  itemName: string; // Snapshot of item name
  customName?: string; // for 'Others'
  rate: number;
  weight: number;
  totalWeight: number;
  amount: number;
}

export type TransactionType = 'PURCHASE' | 'SALE';
export type PaymentStatus = 'Paid' | 'Pending';

export interface Bill {
  id: string;
  billNo: string;
  transactionType: TransactionType;
  customerId?: string;
  customerName: string;
  customerAddress: string;
  customerPhone: string;
  items: BillItem[];
  totalAmount: number;
  paymentStatus: PaymentStatus;
  date: string;
  staffName: string;
  isFinalized?: boolean;
}

export type ViewMode = 'ADMIN' | 'STAFF';

import React, { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { ScrapItem, StaffMember, LeaveRequest, CompanySettings, Bill, ViewMode, Customer, SalaryPayment, Lead, Reimbursement } from '../types';
import { INITIAL_ITEMS, INITIAL_STAFF, INITIAL_LEAVES, DEFAULT_COMPANY, INITIAL_LEADS } from '../constants';

interface AppContextType {
  items: ScrapItem[];
  addItem: (item: ScrapItem) => void;
  updateItemRate: (id: string, newRate: number) => void;
  deleteItem: (id: string) => void;
  staff: StaffMember[];
  addStaff: (member: StaffMember) => void;
  updateStaffStatus: (id: string, status: 'Active' | 'Inactive') => void;
  updateStaffPassword: (id: string, newPass: string) => void;
  deleteStaff: (id: string) => void;
  customers: Customer[];
  addCustomer: (customer: Customer) => void;
  updateCustomer: (id: string, data: Partial<Customer>) => void;
  deleteCustomer: (id: string) => void;
  leads: Lead[];
  addLead: (lead: Lead) => void;
  updateLead: (id: string, updates: Partial<Lead>) => void;
  deleteLead: (id: string) => void;
  leaves: LeaveRequest[];
  addLeaveRequest: (leave: LeaveRequest) => void;
  updateLeaveStatus: (id: string, status: 'Approved' | 'Rejected') => void;
  reimbursements: Reimbursement[];
  addReimbursement: (reimbursement: Reimbursement) => void;
  updateReimbursementStatus: (id: string, status: 'Approved' | 'Rejected') => void;
  salaryPayments: SalaryPayment[];
  addSalaryPayment: (payment: SalaryPayment) => void;
  company: CompanySettings;
  updateCompany: (settings: CompanySettings) => void;
  bills: Bill[];
  addBill: (bill: Bill) => void;
  deleteBill: (id: string) => void;
  currentUser: StaffMember | null;
  login: (phone: string, password: string) => boolean;
  logout: () => void;
  viewMode: ViewMode;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider = ({ children }: { children?: ReactNode }) => {
  const [items, setItems] = useState<ScrapItem[]>(INITIAL_ITEMS);
  const [staff, setStaff] = useState<StaffMember[]>(INITIAL_STAFF);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [leads, setLeads] = useState<Lead[]>(INITIAL_LEADS);
  const [leaves, setLeaves] = useState<LeaveRequest[]>(INITIAL_LEAVES);
  const [reimbursements, setReimbursements] = useState<Reimbursement[]>([]);
  const [salaryPayments, setSalaryPayments] = useState<SalaryPayment[]>([]);
  const [company, setCompany] = useState<CompanySettings>(DEFAULT_COMPANY);
  const [bills, setBills] = useState<Bill[]>([]);

  // Auth State
  const [currentUser, setCurrentUser] = useState<StaffMember | null>(null);

  // Load from localStorage on mount (Simulating persistence)
  useEffect(() => {
    const savedBills = localStorage.getItem('apna_kabadi_bills');
    if (savedBills) setBills(JSON.parse(savedBills));

    const savedRates = localStorage.getItem('apna_kabadi_rates');
    if (savedRates) setItems(JSON.parse(savedRates));

    const savedStaff = localStorage.getItem('apna_kabadi_staff');
    if (savedStaff) setStaff(JSON.parse(savedStaff));

    const savedCustomers = localStorage.getItem('apna_kabadi_customers');
    if (savedCustomers) setCustomers(JSON.parse(savedCustomers));

    const savedLeads = localStorage.getItem('apna_kabadi_leads');
    if (savedLeads) setLeads(JSON.parse(savedLeads));

    const savedLeaves = localStorage.getItem('apna_kabadi_leaves');
    if (savedLeaves) setLeaves(JSON.parse(savedLeaves));

    const savedReimbursements = localStorage.getItem('apna_kabadi_reimbursements');
    if (savedReimbursements) setReimbursements(JSON.parse(savedReimbursements));

    const savedSalaries = localStorage.getItem('apna_kabadi_salaries');
    if (savedSalaries) setSalaryPayments(JSON.parse(savedSalaries));

    // Try to restore session
    const savedUser = localStorage.getItem('apna_kabadi_user');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
  }, []);

  // Save changes
  useEffect(() => {
    localStorage.setItem('apna_kabadi_bills', JSON.stringify(bills));
  }, [bills]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_rates', JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_staff', JSON.stringify(staff));
  }, [staff]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_customers', JSON.stringify(customers));
  }, [customers]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_leads', JSON.stringify(leads));
  }, [leads]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_leaves', JSON.stringify(leaves));
  }, [leaves]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_reimbursements', JSON.stringify(reimbursements));
  }, [reimbursements]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_salaries', JSON.stringify(salaryPayments));
  }, [salaryPayments]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('apna_kabadi_user', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('apna_kabadi_user');
    }
  }, [currentUser]);

  const addItem = (item: ScrapItem) => {
    setItems(prev => {
        // Ensure "Others" stays at the bottom if it exists
        const others = prev.find(i => i.name === 'Others');
        const rest = prev.filter(i => i.name !== 'Others');
        return others ? [...rest, item, others] : [...prev, item];
    });
  };

  const updateItemRate = (id: string, newRate: number) => {
    setItems(prev => prev.map(item => 
      item.id === id ? { ...item, rate: newRate, lastUpdated: new Date().toISOString().split('T')[0] } : item
    ));
  };

  const deleteItem = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
  };

  const addStaff = (member: StaffMember) => {
    setStaff(prev => [...prev, member]);
  };

  const updateStaffStatus = (id: string, status: 'Active' | 'Inactive') => {
    setStaff(prev => prev.map(s => s.id === id ? { ...s, status } : s));
  };

  const updateStaffPassword = (id: string, newPass: string) => {
    setStaff(prev => prev.map(s => s.id === id ? { ...s, password: newPass } : s));
  };

  const deleteStaff = (id: string) => {
    setStaff(prev => prev.filter(s => s.id !== id));
  };

  const addCustomer = (customer: Customer) => {
    // Check if exists
    if (!customers.some(c => c.phone === customer.phone)) {
      setCustomers(prev => [...prev, customer]);
    }
  };

  const updateCustomer = (id: string, data: Partial<Customer>) => {
    setCustomers(prev => prev.map(c => c.id === id ? { ...c, ...data } : c));
  };

  const deleteCustomer = (id: string) => {
    setCustomers(prev => prev.filter(c => c.id !== id));
  };

  const addLead = (lead: Lead) => {
    setLeads(prev => [lead, ...prev]);
  };

  const updateLead = (id: string, updates: Partial<Lead>) => {
    setLeads(prev => prev.map(l => l.id === id ? { ...l, ...updates } : l));
  };

  const deleteLead = (id: string) => {
    setLeads(prev => prev.filter(l => l.id !== id));
  };

  const addLeaveRequest = (leave: LeaveRequest) => {
    setLeaves(prev => [leave, ...prev]);
  };

  const updateLeaveStatus = (id: string, status: 'Approved' | 'Rejected') => {
    setLeaves(prev => prev.map(l => l.id === id ? { ...l, status } : l));
  };

  const addReimbursement = (reimbursement: Reimbursement) => {
    setReimbursements(prev => [reimbursement, ...prev]);
  };

  const updateReimbursementStatus = (id: string, status: 'Approved' | 'Rejected') => {
    setReimbursements(prev => prev.map(r => r.id === id ? { ...r, status } : r));
  };

  const addSalaryPayment = (payment: SalaryPayment) => {
    setSalaryPayments(prev => [payment, ...prev]);
  };

  const updateCompany = (settings: CompanySettings) => {
    setCompany(settings);
  };

  const addBill = (bill: Bill) => {
    setBills(prev => [bill, ...prev]);
  };

  const deleteBill = (id: string) => {
    setBills(prev => prev.filter(b => b.id !== id));
  };

  const login = (phone: string, pass: string): boolean => {
    const user = staff.find(s => s.phone === phone && s.password === pass && s.status === 'Active');
    if (user) {
      setCurrentUser(user);
      return true;
    }
    return false;
  };

  const logout = () => {
    setCurrentUser(null);
  };

  const viewMode: ViewMode = currentUser?.role === 'Manager' ? 'ADMIN' : 'STAFF';

  return (
    <AppContext.Provider value={{
      items, addItem, updateItemRate, deleteItem,
      staff, addStaff, updateStaffStatus, updateStaffPassword, deleteStaff,
      customers, addCustomer, updateCustomer, deleteCustomer,
      leads, addLead, updateLead, deleteLead,
      leaves, addLeaveRequest, updateLeaveStatus,
      reimbursements, addReimbursement, updateReimbursementStatus,
      salaryPayments, addSalaryPayment,
      company, updateCompany,
      bills, addBill, deleteBill,
      currentUser, login, logout, viewMode
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

