import React, { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { ScrapItem, StaffMember, LeaveRequest, CompanySettings, Bill, ViewMode, Customer, SalaryPayment, Lead, Reimbursement, AttendanceRecord } from '../types';
import { INITIAL_ITEMS, INITIAL_STAFF, INITIAL_LEAVES, DEFAULT_COMPANY, INITIAL_LEADS } from '../constants';

interface AppContextType {
  items: ScrapItem[];
  addItem: (item: ScrapItem) => void;
  updateItemRate: (id: string, newRate: number) => void;
  deleteItem: (id: string) => void;
  staff: StaffMember[];
  addStaff: (member: StaffMember) => void;
  updateStaffStatus: (id: string, status: 'Active' | 'Inactive') => void;
  updateStaffPassword: (id: string, newPass: string) => void;
  deleteStaff: (id: string) => void;
  customers: Customer[];
  addCustomer: (customer: Customer) => void;
  updateCustomer: (id: string, data: Partial<Customer>) => void;
  deleteCustomer: (id: string) => void;
  leads: Lead[];
  addLead: (lead: Lead) => void;
  updateLead: (id: string, updates: Partial<Lead>) => void;
  deleteLead: (id: string) => void;
  leaves: LeaveRequest[];
  addLeaveRequest: (leave: LeaveRequest) => void;
  updateLeaveStatus: (id: string, status: 'Approved' | 'Rejected') => void;
  attendance: AttendanceRecord[];
  markAttendance: (record: AttendanceRecord) => void;
  updateAttendanceStatus: (id: string, status: 'Present' | 'Rejected') => void;
  reimbursements: Reimbursement[];
  addReimbursement: (reimbursement: Reimbursement) => void;
  updateReimbursementStatus: (id: string, status: 'Approved' | 'Rejected') => void;
  salaryPayments: SalaryPayment[];
  addSalaryPayment: (payment: SalaryPayment) => void;
  company: CompanySettings;
  updateCompany: (settings: CompanySettings) => void;
  bills: Bill[];
  addBill: (bill: Bill) => void;
  deleteBill: (id: string) => void;
  currentUser: StaffMember | null;
  login: (phone: string, password: string) => boolean;
  logout: () => void;
  viewMode: ViewMode;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider = ({ children }: { children?: ReactNode }) => {
  const [items, setItems] = useState<ScrapItem[]>(INITIAL_ITEMS);
  const [staff, setStaff] = useState<StaffMember[]>(INITIAL_STAFF);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [leads, setLeads] = useState<Lead[]>(INITIAL_LEADS);
  const [leaves, setLeaves] = useState<LeaveRequest[]>(INITIAL_LEAVES);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [reimbursements, setReimbursements] = useState<Reimbursement[]>([]);
  const [salaryPayments, setSalaryPayments] = useState<SalaryPayment[]>([]);
  const [company, setCompany] = useState<CompanySettings>(DEFAULT_COMPANY);
  const [bills, setBills] = useState<Bill[]>([]);

  // Auth State
  const [currentUser, setCurrentUser] = useState<StaffMember | null>(null);

  // Load from localStorage on mount (Simulating persistence)
  useEffect(() => {
    const savedBills = localStorage.getItem('apna_kabadi_bills');
    if (savedBills) setBills(JSON.parse(savedBills));

    const savedRates = localStorage.getItem('apna_kabadi_rates');
    if (savedRates) setItems(JSON.parse(savedRates));

    const savedStaff = localStorage.getItem('apna_kabadi_staff');
    if (savedStaff) setStaff(JSON.parse(savedStaff));

    const savedCustomers = localStorage.getItem('apna_kabadi_customers');
    if (savedCustomers) setCustomers(JSON.parse(savedCustomers));

    const savedLeads = localStorage.getItem('apna_kabadi_leads');
    if (savedLeads) setLeads(JSON.parse(savedLeads));

    const savedLeaves = localStorage.getItem('apna_kabadi_leaves');
    if (savedLeaves) setLeaves(JSON.parse(savedLeaves));

    const savedAttendance = localStorage.getItem('apna_kabadi_attendance');
    if (savedAttendance) setAttendance(JSON.parse(savedAttendance));

    const savedReimbursements = localStorage.getItem('apna_kabadi_reimbursements');
    if (savedReimbursements) setReimbursements(JSON.parse(savedReimbursements));

    const savedSalaries = localStorage.getItem('apna_kabadi_salaries');
    if (savedSalaries) setSalaryPayments(JSON.parse(savedSalaries));

    // Try to restore session
    const savedUser = localStorage.getItem('apna_kabadi_user');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
  }, []);

  // Save changes
  useEffect(() => {
    localStorage.setItem('apna_kabadi_bills', JSON.stringify(bills));
  }, [bills]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_rates', JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_staff', JSON.stringify(staff));
  }, [staff]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_customers', JSON.stringify(customers));
  }, [customers]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_leads', JSON.stringify(leads));
  }, [leads]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_leaves', JSON.stringify(leaves));
  }, [leaves]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_attendance', JSON.stringify(attendance));
  }, [attendance]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_reimbursements', JSON.stringify(reimbursements));
  }, [reimbursements]);

  useEffect(() => {
    localStorage.setItem('apna_kabadi_salaries', JSON.stringify(salaryPayments));
  }, [salaryPayments]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('apna_kabadi_user', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('apna_kabadi_user');
    }
  }, [currentUser]);

  const addItem = (item: ScrapItem) => {
    setItems(prev => {
        // Ensure "Others" stays at the bottom if it exists
        const others = prev.find(i => i.name === 'Others');
        const rest = prev.filter(i => i.name !== 'Others');
        return others ? [...rest, item, others] : [...prev, item];
    });
  };

  const updateItemRate = (id: string, newRate: number) => {
    setItems(prev => prev.map(item => 
      item.id === id ? { ...item, rate: newRate, lastUpdated: new Date().toISOString().split('T')[0] } : item
    ));
  };

  const deleteItem = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
  };

  const addStaff = (member: StaffMember) => {
    setStaff(prev => [...prev, member]);
  };

  const updateStaffStatus = (id: string, status: 'Active' | 'Inactive') => {
    setStaff(prev => prev.map(s => s.id === id ? { ...s, status } : s));
  };

  const updateStaffPassword = (id: string, newPass: string) => {
    setStaff(prev => prev.map(s => s.id === id ? { ...s, password: newPass } : s));
  };

  const deleteStaff = (id: string) => {
    setStaff(prev => prev.filter(s => s.id !== id));
  };

  const addCustomer = (customer: Customer) => {
    // Check if exists
    if (!customers.some(c => c.phone === customer.phone)) {
      setCustomers(prev => [...prev, customer]);
    }
  };

  const updateCustomer = (id: string, data: Partial<Customer>) => {
    setCustomers(prev => prev.map(c => c.id === id ? { ...c, ...data } : c));
  };

  const deleteCustomer = (id: string) => {
    setCustomers(prev => prev.filter(c => c.id !== id));
  };

  const addLead = (lead: Lead) => {
    setLeads(prev => [lead, ...prev]);
  };

  const updateLead = (id: string, updates: Partial<Lead>) => {
    setLeads(prev => prev.map(l => l.id === id ? { ...l, ...updates } : l));
  };

  const deleteLead = (id: string) => {
    setLeads(prev => prev.filter(l => l.id !== id));
  };

  const addLeaveRequest = (leave: LeaveRequest) => {
    setLeaves(prev => [leave, ...prev]);
  };

  const updateLeaveStatus = (id: string, status: 'Approved' | 'Rejected') => {
    setLeaves(prev => prev.map(l => l.id === id ? { ...l, status } : l));
  };

  const markAttendance = (record: AttendanceRecord) => {
    setAttendance(prev => [record, ...prev]);
  };

  const updateAttendanceStatus = (id: string, status: 'Present' | 'Rejected') => {
    setAttendance(prev => prev.map(r => r.id === id ? { ...r, status } : r));
  };

  const addReimbursement = (reimbursement: Reimbursement) => {
    setReimbursements(prev => [reimbursement, ...prev]);
  };

  const updateReimbursementStatus = (id: string, status: 'Approved' | 'Rejected') => {
    setReimbursements(prev => prev.map(r => r.id === id ? { ...r, status } : r));
  };

  const addSalaryPayment = (payment: SalaryPayment) => {
    setSalaryPayments(prev => [payment, ...prev]);
  };

  const updateCompany = (settings: CompanySettings) => {
    setCompany(settings);
  };

  const addBill = (bill: Bill) => {
    setBills(prev => [bill, ...prev]);
  };

  const deleteBill = (id: string) => {
    setBills(prev => prev.filter(b => b.id !== id));
  };

  const login = (phone: string, pass: string): boolean => {
    const user = staff.find(s => s.phone === phone && s.password === pass && s.status === 'Active');
    if (user) {
      setCurrentUser(user);
      return true;
    }
    return false;
  };

  const logout = () => {
    setCurrentUser(null);
  };

  const viewMode: ViewMode = currentUser?.role === 'Manager' ? 'ADMIN' : 'STAFF';

  return (
    <AppContext.Provider value={{
      items, addItem, updateItemRate, deleteItem,
      staff, addStaff, updateStaffStatus, updateStaffPassword, deleteStaff,
      customers, addCustomer, updateCustomer, deleteCustomer,
      leads, addLead, updateLead, deleteLead,
      leaves, addLeaveRequest, updateLeaveStatus,
      attendance, markAttendance, updateAttendanceStatus,
      reimbursements, addReimbursement, updateReimbursementStatus,
      salaryPayments, addSalaryPayment,
      company, updateCompany,
      bills, addBill, deleteBill,
      currentUser, login, logout, viewMode
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

import React, { useState } from 'react';
import { useApp } from '../../context/AppContext';
import { Lead } from '../../types';
import { Search, Plus, MapPin, Phone, User, Filter, Edit, CheckCircle2, Clock, XCircle, AlertCircle, Trash2, ArrowRight } from 'lucide-react';

export const Leads = () => {
  const { leads, addLead, updateLead, deleteLead, staff, customers } = useApp();
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('All');
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  // Filter staff to get only active ones for assignment
  const activeStaff = staff.filter(s => s.status === 'Active');

  const [formData, setFormData] = useState<Partial<Lead>>({
    name: '',
    phone: '',
    address: '',
    status: 'New',
    assignedTo: '',
    notes: ''
  });

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'New': return 'bg-blue-100 text-blue-700';
      case 'In Progress': return 'bg-yellow-100 text-yellow-700';
      case 'Converted': return 'bg-green-100 text-green-700';
      case 'Lost': return 'bg-red-100 text-red-700';
      default: return 'bg-slate-100 text-slate-700';
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'New': return <AlertCircle size={14} className="mr-1" />;
      case 'In Progress': return <Clock size={14} className="mr-1" />;
      case 'Converted': return <CheckCircle2 size={14} className="mr-1" />;
      case 'Lost': return <XCircle size={14} className="mr-1" />;
      default: return null;
    }
  };

  const filteredLeads = leads.filter(lead => {
    const matchesSearch = lead.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          lead.phone.includes(searchTerm) || 
                          lead.address.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = statusFilter === 'All' || lead.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const handleOpenModal = (lead?: Lead) => {
    if (lead) {
      setEditingId(lead.id);
      setFormData(lead);
    } else {
      setEditingId(null);
      setFormData({ 
        name: '', 
        phone: '', 
        address: '', 
        status: 'New', 
        assignedTo: activeStaff[0]?.id || '', 
        notes: '' 
      });
    }
    setShowModal(true);
  };

  const handleCustomerSelect = (e: React.ChangeEvent<HTMLSelectElement>) => {
      const selectedId = e.target.value;
      if (!selectedId) return;

      const customer = customers.find(c => c.id === selectedId);
      if (customer) {
          setFormData(prev => ({
              ...prev,
              name: customer.name,
              phone: customer.phone,
              address: customer.address
          }));
      }
  };

  const handleDelete = (id: string, name: string) => {
    if (confirm(`Are you sure you want to delete lead "${name}"?`)) {
      deleteLead(id);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.phone || !formData.assignedTo) return;

    if (editingId) {
      updateLead(editingId, formData);
    } else {
      addLead({
        id: Date.now().toString(),
        name: formData.name || '',
        phone: formData.phone || '',
        address: formData.address || '',
        status: (formData.status || 'New') as any,
        assignedTo: formData.assignedTo || '',
        createdAt: new Date().toISOString(),
        notes: formData.notes || ''
      });
    }
    setShowModal(false);
  };

  return (
    <div className="max-w-6xl mx-auto space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
           <h1 className="text-2xl font-bold text-slate-800">Lead Management</h1>
           <p className="text-slate-500 mt-1">Track potential scrap sources and assign to staff</p>
        </div>

        <div className="flex flex-wrap gap-3">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="Search leads..." 
              className="pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none w-full md:w-56 bg-white text-slate-900"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="relative">
             <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
             <select 
               value={statusFilter}
               onChange={(e) => setStatusFilter(e.target.value)}
               className="pl-9 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none appearance-none bg-white text-slate-900 text-sm"
             >
               <option value="All">All Status</option>
               <option value="New">New</option>
               <option value="In Progress">In Progress</option>
               <option value="Converted">Converted</option>
               <option value="Lost">Lost</option>
             </select>
          </div>
          <button 
            onClick={() => handleOpenModal()}
            className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg transition-colors font-medium shadow-sm whitespace-nowrap"
          >
            <Plus size={18} />
            <span>Add Lead</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200 text-slate-600 text-sm uppercase tracking-wider">
                <th className="p-4 font-semibold">Lead Details</th>
                <th className="p-4 font-semibold">Status</th>
                <th className="p-4 font-semibold">Assigned Staff</th>
                <th className="p-4 font-semibold">Notes</th>
                <th className="p-4 font-semibold text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredLeads.map((lead) => {
                const assignedStaff = staff.find(s => s.id === lead.assignedTo);
                return (
                  <tr key={lead.id} className="hover:bg-slate-50 transition-colors">
                    <td className="p-4">
                      <div className="font-bold text-slate-800">{lead.name}</div>
                      <div className="flex items-center text-slate-500 text-xs mt-1 space-x-2">
                        <span className="flex items-center"><Phone size={10} className="mr-1"/> {lead.phone}</span>
                        <span className="flex items-center"><MapPin size={10} className="mr-1"/> {lead.address}</span>
                      </div>
                    </td>
                    <td className="p-4">
                      <span className={`inline-flex items-center px-2.5 py-1 rounded-full text-xs font-medium ${getStatusColor(lead.status)}`}>
                         {getStatusIcon(lead.status)}
                         {lead.status}
                      </span>
                    </td>
                    <td className="p-4">
                       <div className="flex items-center text-slate-700 text-sm font-medium">
                         <div className="w-6 h-6 rounded-full bg-slate-200 flex items-center justify-center text-xs mr-2 text-slate-600">
                            {assignedStaff?.name.charAt(0) || '?'}
                         </div>
                         {assignedStaff?.name || 'Unassigned'}
                       </div>
                    </td>
                    <td className="p-4 text-sm text-slate-500 max-w-xs truncate">
                       {lead.notes || '-'}
                    </td>
                    <td className="p-4 text-center space-x-2">
                      <button 
                        onClick={() => handleOpenModal(lead)}
                        className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-full transition"
                      >
                        <Edit size={18} />
                      </button>
                      <button 
                        onClick={() => handleDelete(lead.id, lead.name)}
                        className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-full transition"
                      >
                        <Trash2 size={18} />
                      </button>
                    </td>
                  </tr>
                );
              })}
              {filteredLeads.length === 0 && (
                <tr>
                   <td colSpan={5} className="p-8 text-center text-slate-500">
                      No leads found.
                   </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add/Edit Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-lg max-w-lg w-full p-6">
            <h3 className="text-xl font-bold text-slate-800 mb-4">
              {editingId ? 'Edit Lead Details' : 'Create New Lead'}
            </h3>
            <form onSubmit={handleSubmit} className="space-y-4">
              {/* Quick Select Customer */}
              {!editingId && (
                  <div className="bg-slate-50 p-3 rounded-lg border border-slate-200 mb-4">
                      <label className="block text-xs font-bold text-slate-500 mb-1 uppercase tracking-wide">Select Existing Customer (Optional)</label>
                      <select 
                        className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                        onChange={handleCustomerSelect}
                        defaultValue=""
                      >
                          <option value="">-- Create Fresh Lead --</option>
                          {customers.map(c => (
                              <option key={c.id} value={c.id}>{c.name} - {c.phone}</option>
                          ))}
                      </select>
                  </div>
              )}

              <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Source Name</label>
                    <input 
                    type="text" 
                    required
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                    value={formData.name}
                    onChange={e => setFormData({...formData, name: e.target.value})}
                    placeholder="e.g. Hotel Plaza"
                    />
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Contact Phone</label>
                    <input 
                    type="tel" 
                    required
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                    value={formData.phone}
                    onChange={e => setFormData({...formData, phone: e.target.value})}
                    placeholder="98XXXXXXXX"
                    />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Address / Location</label>
                <input 
                  type="text" 
                  className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                  value={formData.address}
                  onChange={e => setFormData({...formData, address: e.target.value})}
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Assign To (Staff)</label>
                    <div className="relative">
                        <User className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                        <select 
                        required
                        className="w-full pl-9 p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900 appearance-none"
                        value={formData.assignedTo}
                        onChange={e => setFormData({...formData, assignedTo: e.target.value})}
                        >
                            <option value="">-- Select Staff --</option>
                            {activeStaff.map(s => (
                                <option key={s.id} value={s.id}>{s.name} ({s.role})</option>
                            ))}
                        </select>
                    </div>
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Status</label>
                    <select 
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                    value={formData.status}
                    onChange={e => setFormData({...formData, status: e.target.value as any})}
                    >
                        <option value="New">New</option>
                        <option value="In Progress">In Progress</option>
                        <option value="Converted">Converted</option>
                        <option value="Lost">Lost</option>
                    </select>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Notes / Instructions</label>
                <textarea 
                  className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900"
                  rows={3}
                  value={formData.notes}
                  onChange={e => setFormData({...formData, notes: e.target.value})}
